1	/**
2	 * app.js — Application entry point.
3	 * Initializes database, seeds data, sets up routing, and boots the app shell.
4	 */
5	
6	import { openDatabase } from './store/Database.js';
7	import { Router } from './router/Router.js';
8	import { AppShell } from './components/AppShell.js';
9	import authService from './services/AuthService.js';
10	import moderationService from './services/ModerationService.js';
11	import schedulerService from './services/SchedulerService.js';
12	import classRepository from './repositories/ClassRepository.js';
13	import { createClass } from './models/Class.js';
14	import { generateId } from './utils/helpers.js';
15	
16	import { LoginPage } from './pages/LoginPage.js';
17	import { DashboardPage } from './pages/DashboardPage.js';
18	import { RegistrationsPage } from './pages/RegistrationsPage.js';
19	import { QuizPage } from './pages/QuizPage.js';
20	import { ReviewsPage } from './pages/ReviewsPage.js';
21	import { ContractsPage } from './pages/ContractsPage.js';
22	import { AdminPage } from './pages/AdminPage.js';
23	
24	const appEl = document.getElementById('app');
25	
26	async function boot() {
27	  try {
28	    // 1. Open IndexedDB
29	    await openDatabase();
30	
31	    // 2. Seed default users if empty
32	    await authService.seedDefaultUsers();
33	
34	    // 2b. Seed default classes if empty
35	    const classCount = await classRepository.count();
36	    if (classCount === 0) {
37	      const defaultClasses = [
38	        { title: 'Introduction to Web Development', description: 'Learn HTML, CSS, and JavaScript basics.', capacity: 30, startDate: '2026-04-15', endDate: '2026-06-15' },
39	        { title: 'Advanced JavaScript', description: 'Deep dive into ES modules, async patterns, and frameworks.', capacity: 25, startDate: '2026-05-01', endDate: '2026-07-01' },
40	        { title: 'Database Fundamentals', description: 'SQL, NoSQL, and data modeling.', capacity: 20, startDate: '2026-04-20', endDate: '2026-06-20' },
41	      ];
42	      for (const c of defaultClasses) {
43	        await classRepository.add(createClass({ id: generateId(), ...c }));
44	      }
45	    }
46	
47	    // 3. Load config
48	    await moderationService.loadSensitiveWords();
49	
50	    // 4. Check existing session
51	    await authService.init();
52	
53	    // 5. Setup router
54	    const router = new Router();
55	    const appShell = new AppShell(router);
56	
57	    // Page instances (lazy-ish — created once)
58	    const loginPage = new LoginPage(router);
59	    const dashboardPage = new DashboardPage(appShell);
60	    const registrationsPage = new RegistrationsPage(appShell);
61	    const quizPage = new QuizPage(appShell);
62	    const reviewsPage = new ReviewsPage(appShell);
63	    const contractsPage = new ContractsPage(appShell);
64	    const adminPage = new AdminPage(appShell);
65	
66	    // Helper: ensure shell is rendered, then call page render
67	    const renderPage = async (page) => {
68	      if (!document.querySelector('.app-shell')) {
69	        appShell.render(appEl);
70	      }
71	      await page.render();
72	    };
73	
74	    // Route guard: redirect to login if not authenticated
75	    router.beforeEach((to) => {
76	      if (to.path !== '/login' && !authService.isAuthenticated()) {
77	        router.navigate('/login');
78	        return false;
79	      }
80	      if (to.path === '/login' && authService.isAuthenticated()) {
81	        router.navigate('/dashboard');
82	        return false;
83	      }
84	      return true;
85	    });
86	
87	    // Register routes
88	    router.route('/login', async () => {
89	      appEl.innerHTML = '';
90	      await loginPage.render(appEl);
91	    });
92	
93	    router.route('/dashboard', () => renderPage(dashboardPage));
94	    router.route('/registrations', () => renderPage(registrationsPage));
95	    router.route('/quiz', () => renderPage(quizPage));
96	    router.route('/reviews', () => renderPage(reviewsPage));
97	    router.route('/contracts', () => renderPage(contractsPage));
98	    router.route('/admin', () => renderPage(adminPage));
99	
100	    router.notFound(() => {
101	      if (authService.isAuthenticated()) {
102	        router.navigate('/dashboard');
103	      } else {
104	        router.navigate('/login');
105	      }
106	    });
107	
108	    // Highlight active nav link on navigation
109	    router.onNavigate(({ path }) => {
110	      document.querySelectorAll('.sidebar-nav a').forEach(a => {
111	        const href = a.getAttribute('href')?.replace('#', '');
112	        a.classList.toggle('active', href === path);
113	      });
114	    });
115	
116	    // 6. Start scheduler
117	    schedulerService.start();
118	
119	    // 7. Start router
120	    router.start();
121	  } catch (err) {
122	    console.error('Boot failed:', err);
123	    appEl.innerHTML = `<div class="loading-screen" style="color:var(--color-danger)">
124	      <div>
125	        <p>Failed to start application.</p>
126	        <p style="font-size:0.85rem;margin-top:8px">${err.message}</p>
127	      </div>
128	    </div>`;
129	  }
130	}
131	
132	boot();
133

1	/**
2	 * Router — Hash-based SPA router.
3	 */
4	
5	export class Router {
6	  constructor() {
7	    this._routes = {};
8	    this._currentRoute = null;
9	    this._beforeEach = null;
10	    this._notFound = null;
11	    this._onNavigate = null;
12	
13	    window.addEventListener('hashchange', () => this._resolve());
14	  }
15	
16	  /**
17	   * Register a route.
18	   * @param {string} path — hash path, e.g. '/dashboard'
19	   * @param {Function} handler — called with { params, query } when route matches
20	   */
21	  route(path, handler) {
22	    this._routes[path] = { path, handler };
23	    return this;
24	  }
25	
26	  /**
27	   * Set a guard that runs before each navigation.
28	   * @param {Function} guard — receives (to, from) → return false to block
29	   */
30	  beforeEach(guard) {
31	    this._beforeEach = guard;
32	    return this;
33	  }
34	
35	  /**
36	   * Set a 404 handler.
37	   */
38	  notFound(handler) {
39	    this._notFound = handler;
40	    return this;
41	  }
42	
43	  /**
44	   * Set a callback invoked on every successful navigation.
45	   */
46	  onNavigate(callback) {
47	    this._onNavigate = callback;
48	    return this;
49	  }
50	
51	  /**
52	   * Navigate to a hash path.
53	   */
54	  navigate(path) {
55	    window.location.hash = '#' + path;
56	  }
57	
58	  /**
59	   * Start the router — resolve the current hash.
60	   */
61	  start() {
62	    this._resolve();
63	  }
64	
65	  /**
66	   * Get current path from hash.
67	   */
68	  getCurrentPath() {
69	    const hash = window.location.hash.slice(1) || '/login';
70	    const [path] = hash.split('?');
71	    return path;
72	  }
73	
74	  /**
75	   * Parse query params from hash.
76	   */
77	  _parseQuery(hash) {
78	    const qIndex = hash.indexOf('?');
79	    if (qIndex === -1) return {};
80	    const qs = hash.slice(qIndex + 1);
81	    const params = {};
82	    for (const pair of qs.split('&')) {
83	      const [key, val] = pair.split('=');
84	      if (key) params[decodeURIComponent(key)] = decodeURIComponent(val || '');
85	    }
86	    return params;
87	  }
88	
89	  /**
90	   * Match a registered route pattern against a path.
91	   * Supports :param segments.
92	   * @returns {{ handler, params } | null}
93	   */
94	  _match(path) {
95	    for (const [pattern, routeDef] of Object.entries(this._routes)) {
96	      const patternParts = pattern.split('/');
97	      const pathParts = path.split('/');
98	      if (patternParts.length !== pathParts.length) continue;
99	
100	      const params = {};
101	      let match = true;
102	      for (let i = 0; i < patternParts.length; i++) {
103	        if (patternParts[i].startsWith(':')) {
104	          params[patternParts[i].slice(1)] = pathParts[i];
105	        } else if (patternParts[i] !== pathParts[i]) {
106	          match = false;
107	          break;
108	        }
109	      }
110	
111	      if (match) return { handler: routeDef.handler, params };
112	    }
113	    return null;
114	  }
115	
116	  /**
117	   * Internal: resolve the current hash to a route.
118	   */
119	  async _resolve() {
120	    const hash = window.location.hash.slice(1) || '/login';
121	    const [path] = hash.split('?');
122	    const query = this._parseQuery(hash);
123	    const from = this._currentRoute;
124	
125	    const matched = this._match(path);
126	
127	    if (this._beforeEach) {
128	      const allowed = await this._beforeEach({ path, query }, from);
129	      if (allowed === false) return;
130	    }
131	
132	    this._currentRoute = { path, query };
133	
134	    if (matched) {
135	      await matched.handler({ params: matched.params, query });
136	    } else if (this._notFound) {
137	      this._notFound({ path, query });
138	    }
139	
140	    if (this._onNavigate) {
141	      this._onNavigate({ path, query });
142	    }
143	  }
144	}
145	
146	export default Router;
