1	/**
2	 * AuthService — user authentication, session management, lockout logic.
3	 */
4	
5	import userRepository from '../repositories/UserRepository.js';
6	import sessionRepository from '../repositories/SessionRepository.js';
7	import cryptoService from './CryptoService.js';
8	import auditService from './AuditService.js';
9	import { createUser, USER_ROLES } from '../models/User.js';
10	import { generateId, now } from '../utils/helpers.js';
11	
12	const SESSION_KEY = 'trainingops_session';
13	const MAX_LOGIN_ATTEMPTS = 5;
14	const LOCKOUT_MINUTES = 15;
15	
16	export class AuthService {
17	  constructor() {
18	    this._currentUser = null;
19	    this._loginAttempts = {};  // username → count
20	  }
21	
22	  /**
23	   * Initialize auth — check for existing session.
24	   */
25	  async init() {
26	    const sessionId = localStorage.getItem(SESSION_KEY);
27	    if (!sessionId) return null;
28	
29	    const session = await sessionRepository.getById(sessionId);
30	    if (!session) {
31	      localStorage.removeItem(SESSION_KEY);
32	      return null;
33	    }
34	
35	    const user = await userRepository.getById(session.userId);
36	    if (!user) {
37	      localStorage.removeItem(SESSION_KEY);
38	      return null;
39	    }
40	
41	    this._currentUser = user;
42	    return user;
43	  }
44	
45	  /**
46	   * Login with username and password.
47	   */
48	  async login(username, password) {
49	    if (!username || String(username).trim() === '') {
50	      return { success: false, error: 'Username is required.' };
51	    }
52	    if (!password) {
53	      return { success: false, error: 'Password is required.' };
54	    }
55	
56	    const user = await userRepository.getByUsername(username);
57	    if (!user) {
58	      return { success: false, error: 'Invalid username or password.' };
59	    }
60	
61	    // Check lockout
62	    if (user.lockoutUntil && new Date(user.lockoutUntil) > new Date()) {
63	      const remaining = Math.ceil((new Date(user.lockoutUntil) - new Date()) / 60000);
64	      return { success: false, error: `Account locked. Try again in ${remaining} minutes.` };
65	    }
66	
67	    if (!user.passwordHash || !user.passwordHash.includes(':')) {
68	      return { success: false, error: 'Account configuration error. Contact administrator.' };
69	    }
70	
71	    const [hash, salt] = user.passwordHash.split(':');
72	    const valid = await cryptoService.verifyPassword(password, hash, salt);
73	
74	    if (!valid) {
75	      this._loginAttempts[username] = (this._loginAttempts[username] || 0) + 1;
76	      if (this._loginAttempts[username] >= MAX_LOGIN_ATTEMPTS) {
77	        user.lockoutUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60000).toISOString();
78	        await userRepository.put(user);
79	        this._loginAttempts[username] = 0;
80	        return { success: false, error: `Too many failed attempts. Account locked for ${LOCKOUT_MINUTES} minutes.` };
81	      }
82	      return { success: false, error: 'Invalid username or password.' };
83	    }
84	
85	    // Clear lockout and attempts on success
86	    this._loginAttempts[username] = 0;
87	    if (user.lockoutUntil) {
88	      user.lockoutUntil = null;
89	      await userRepository.put(user);
90	    }
91	
92	    // Create session
93	    const session = { id: generateId(), userId: user.id, createdAt: now() };
94	    await sessionRepository.add(session);
95	    localStorage.setItem(SESSION_KEY, session.id);
96	
97	    this._currentUser = user;
98	
99	    await auditService.log('user', user.id, 'login', 'User logged in', user.id);
100	
101	    return { success: true, user };
102	  }
103	
104	  /**
105	   * Logout current user.
106	   */
107	  async logout() {
108	    const sessionId = localStorage.getItem(SESSION_KEY);
109	    if (sessionId) {
110	      try { await sessionRepository.delete(sessionId); } catch (_) { /* ignore */ }
111	    }
112	    localStorage.removeItem(SESSION_KEY);
113	
114	    if (this._currentUser) {
115	      await auditService.log('user', this._currentUser.id, 'logout', 'User logged out', this._currentUser.id);
116	    }
117	
118	    this._currentUser = null;
119	  }
120	
121	  /**
122	   * Get the currently logged-in user.
123	   */
124	  getCurrentUser() {
125	    return this._currentUser;
126	  }
127	
128	  /**
129	   * Check if user is authenticated.
130	   */
131	  isAuthenticated() {
132	    return this._currentUser !== null;
133	  }
134	
135	  /**
136	   * Check if current user has one of the given roles.
137	   */
138	  hasRole(...roles) {
139	    return this._currentUser && roles.includes(this._currentUser.role);
140	  }
141	
142	  /**
143	   * Register a new user (admin action).
144	   */
145	  async registerUser(username, password, role, displayName = '') {
146	    if (!username || String(username).trim() === '') {
147	      return { success: false, error: 'Username is required.' };
148	    }
149	    if (!password || password.length < 4) {
150	      return { success: false, error: 'Password must be at least 4 characters.' };
151	    }
152	
153	    const existing = await userRepository.getByUsername(username);
154	    if (existing) {
155	      return { success: false, error: 'Username already exists.' };
156	    }
157	
158	    const validRoles = Object.values(USER_ROLES);
159	    if (!validRoles.includes(role)) {
160	      return { success: false, error: `Invalid role. Must be one of: ${validRoles.join(', ')}` };
161	    }
162	
163	    const { hash, salt } = await cryptoService.hashPassword(password);
164	    const user = createUser({
165	      id: generateId(),
166	      username,
167	      passwordHash: `${hash}:${salt}`,
168	      role,
169	      displayName: displayName || username,
170	    });
171	
172	    await userRepository.add(user);
173	    await auditService.log('user', user.id, 'created', `User ${username} created with role ${role}`, this._currentUser?.id || 'system');
174	
175	    return { success: true, user };
176	  }
177	
178	  /**
179	   * Seed default users if none exist.
180	   */
181	  async seedDefaultUsers() {
182	    const count = await userRepository.count();
183	    if (count > 0) return;
184	
185	    const defaults = [
186	      { username: 'admin', password: 'admin123', role: USER_ROLES.ADMINISTRATOR, displayName: 'System Admin' },
187	      { username: 'reviewer', password: 'reviewer123', role: USER_ROLES.STAFF_REVIEWER, displayName: 'Staff Reviewer' },
188	      { username: 'instructor', password: 'instructor123', role: USER_ROLES.INSTRUCTOR, displayName: 'Instructor One' },
189	      { username: 'learner', password: 'learner123', role: USER_ROLES.LEARNER, displayName: 'Learner One' },
190	    ];
191	
192	    for (const d of defaults) {
193	      const { hash, salt } = await cryptoService.hashPassword(d.password);
194	      const user = createUser({
195	        id: generateId(),
196	        username: d.username,
197	        passwordHash: `${hash}:${salt}`,
198	        role: d.role,
199	        displayName: d.displayName,
200	      });
201	      await userRepository.add(user);
202	    }
203	  }
204	}
205	
206	export default new AuthService();
207

1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	
16	// Transitions only reviewers/admins may perform
17	const REVIEWER_ONLY_TRANSITIONS = [
18	  REGISTRATION_STATUS.UNDER_REVIEW,
19	  REGISTRATION_STATUS.APPROVED,
20	  REGISTRATION_STATUS.REJECTED,
21	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
22	  REGISTRATION_STATUS.WAITLISTED,
23	];
24	
25	export class RegistrationService {
26	  constructor(deps = {}) {
27	    this._registrationRepo = deps.registrationRepository || registrationRepository;
28	    this._eventRepo = deps.registrationEventRepository || registrationEventRepository;
29	    this._classRepo = deps.classRepository || classRepository;
30	    this._userRepo = deps.userRepository || userRepository;
31	    this._auditService = deps.auditService || defaultAuditService;
32	  }
33	
34	  async create(userId, classId, notes = '') {
35	    if (!userId) throw new Error('userId is required to create a registration.');
36	
37	    const registration = createRegistration({
38	      id: generateId(),
39	      userId,
40	      classId,
41	      status: REGISTRATION_STATUS.DRAFT,
42	      notes,
43	    });
44	    await this._registrationRepo.add(registration);
45	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
46	    await this._auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
47	    eventBus.emit('registration:created', registration);
48	    return registration;
49	  }
50	
51	  async transition(registrationId, newStatus, comment, userId) {
52	    if (!registrationId) throw new Error('registrationId is required.');
53	    if (!newStatus) throw new Error('newStatus is required.');
54	    if (!userId) throw new Error('userId is required for transition.');
55	
56	    const reg = await this._registrationRepo.getById(registrationId);
57	    if (!reg) throw new Error('Registration not found.');
58	
59	    if (!canTransition(reg.status, newStatus)) {
60	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
61	    }
62	
63	    const actingUser = await this._userRepo.getById(userId);
64	    if (actingUser) {
65	      const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
66	      const isOwner = reg.userId === userId;
67	
68	      if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
69	        throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
70	      }
71	
72	      if (!isReviewerOrAdmin) {
73	        if (!isOwner) {
74	          throw new Error('You can only modify your own registrations.');
75	        }
76	        const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
77	        if (!selfAllowed.includes(newStatus)) {
78	          throw new Error(`You do not have permission to transition to ${newStatus}.`);
79	        }
80	      }
81	    }
82	
83	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
84	      if (!comment || comment.trim().length < 20) {
85	        throw new Error('Rejection comment must be at least 20 characters.');
86	      }
87	    }
88	
89	    const fromStatus = reg.status;
90	    reg.status = newStatus;
91	    reg.updatedAt = now();
92	    await this._registrationRepo.put(reg);
93	
94	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
95	    await this._auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
96	
97	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
98	
99	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
100	      await this._checkWaitlistPromotion(reg.classId, userId);
101	    }
102	
103	    return reg;
104	  }
105	
106	  async batchTransition(registrationIds, newStatus, comment, userId) {
107	    const results = [];
108	    for (const id of registrationIds) {
109	      try {
110	        const reg = await this.transition(id, newStatus, comment, userId);
111	        results.push({ id, success: true, registration: reg });
112	      } catch (err) {
113	        results.push({ id, success: false, error: err.message });
114	      }
115	    }
116	    return results;
117	  }
118	
119	  async getById(registrationId) {
120	    return this._registrationRepo.getById(registrationId);
121	  }
122	
123	  async getAll() {
124	    return this._registrationRepo.getAll();
125	  }
126	
127	  async getByUserId(userId) {
128	    return this._registrationRepo.getByUserId(userId);
129	  }
130	
131	  async getByStatus(status) {
132	    return this._registrationRepo.getByStatus(status);
133	  }
134	
135	  async getByClassId(classId) {
136	    return this._registrationRepo.getByClassId(classId);
137	  }
138	
139	  async getEvents(registrationId) {
140	    return this._eventRepo.getByRegistrationId(registrationId);
141	  }
142	
143	  async getClassFillRate(classId) {
144	    if (!classId) return 0;
145	    const cls = await this._classRepo.getById(classId);
146	    if (!cls || !cls.capacity) return 0;
147	
148	    const regs = await this._registrationRepo.getByClassId(classId);
149	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
150	    return approvedCount / cls.capacity;
151	  }
152	
153	  async _checkWaitlistPromotion(classId, userId) {
154	    if (!classId) return;
155	
156	    const fillRate = await this.getClassFillRate(classId);
157	    if (fillRate >= 0.95) return;
158	
159	    const waitlisted = await this._registrationRepo.filter(
160	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
161	    );
162	    if (waitlisted.length === 0) return;
163	
164	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
165	
166	    const next = waitlisted[0];
167	    const fromStatus = next.status;
168	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
169	    next.updatedAt = now();
