1	/**
2	 * QuizService — question bank CRUD, bulk import, paper generation, auto-grading, wrong-question tracking.
3	 */
4	
5	import questionRepository from '../repositories/QuestionRepository.js';
6	import quizRepository from '../repositories/QuizRepository.js';
7	import quizResultRepository from '../repositories/QuizResultRepository.js';
8	import wrongQuestionRepository from '../repositories/WrongQuestionRepository.js';
9	import defaultAuditService from './AuditService.js';
10	import { createQuestion, QUESTION_TYPES } from '../models/Question.js';
11	import { createQuiz, createQuizResult } from '../models/Quiz.js';
12	import { createWrongQuestion } from '../models/WrongQuestion.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import { validateQuestionRow } from '../utils/validators.js';
15	
16	export class QuizService {
17	  constructor(deps = {}) {
18	    this._questionRepo = deps.questionRepository || questionRepository;
19	    this._quizRepo = deps.quizRepository || quizRepository;
20	    this._quizResultRepo = deps.quizResultRepository || quizResultRepository;
21	    this._wrongQRepo = deps.wrongQuestionRepository || wrongQuestionRepository;
22	    this._auditService = deps.auditService || defaultAuditService;
23	  }
24	
25	  async createQuestion(data) {
26	    if (!data.questionText || String(data.questionText).trim() === '') throw new Error('questionText is required.');
27	    const validTypes = Object.values(QUESTION_TYPES);
28	    if (!validTypes.includes(data.type)) throw new Error(`type must be one of: ${validTypes.join(', ')}`);
29	    if (data.type !== QUESTION_TYPES.SUBJECTIVE && (!data.correctAnswer || String(data.correctAnswer).toString().trim() === '')) {
30	      throw new Error('correctAnswer is required for non-subjective questions.');
31	    }
32	    const diff = Number(data.difficulty);
33	    if (!Number.isInteger(diff) || diff < 1 || diff > 5) throw new Error('difficulty must be an integer between 1 and 5.');
34	
35	    const question = createQuestion({ id: generateId(), ...data });
36	    await this._questionRepo.add(question);
37	    await this._auditService.log('question', question.id, 'created', `Question created: ${question.type}`, data.createdBy || 'system');
38	    return question;
39	  }
40	
41	  async updateQuestion(id, updates) {
42	    const question = await this._questionRepo.getById(id);
43	    if (!question) throw new Error('Question not found.');
44	    Object.assign(question, updates, { updatedAt: now() });
45	    await this._questionRepo.put(question);
46	    return question;
47	  }
48	
49	  async deleteQuestion(id) { await this._questionRepo.delete(id); }
50	  async getQuestionById(id) { return this._questionRepo.getById(id); }
51	  async getAllQuestions() { return this._questionRepo.getAll(); }
52	  async getQuestionsByType(type) { return this._questionRepo.getByType(type); }
53	  async getQuestionsByDifficulty(difficulty) { return this._questionRepo.getByDifficulty(difficulty); }
54	
55	  async bulkImport(rows, createdBy = 'system') {
56	    if (!Array.isArray(rows) || rows.length === 0) {
57	      return { success: false, errors: ['Import data must be a non-empty array.'] };
58	    }
59	    const allErrors = [];
60	    for (let i = 0; i < rows.length; i++) {
61	      allErrors.push(...validateQuestionRow(rows[i], i + 1));
62	    }
63	    if (allErrors.length > 0) return { success: false, errors: allErrors };
64	
65	    const questions = rows.map(row => createQuestion({
66	      id: generateId(), questionText: row.questionText, type: row.type,
67	      options: row.options || [], correctAnswer: row.correctAnswer,
68	      difficulty: Number(row.difficulty), tags: row.tags,
69	      chapter: row.chapter || '', explanation: row.explanation || '',
70	    }));
71	
72	    await this._questionRepo.bulkAdd(questions);
73	    await this._auditService.log('question', 'bulk', 'bulk_import', `Imported ${questions.length} questions`, createdBy);
74	    return { success: true, count: questions.length };
75	  }
76	
77	  async generatePaper(title, classId, rules, createdBy) {
78	    if (!title || String(title).trim() === '') throw new Error('Paper title is required.');
79	    if (!rules || !rules.totalQuestions) throw new Error('Paper rules with totalQuestions are required.');
80	    const allQuestions = await this._questionRepo.getAll();
81	    if (allQuestions.length === 0) throw new Error('No questions available in the bank.');
82	
83	    const selected = this._selectQuestions(allQuestions, rules);
84	    const quiz = createQuiz({ id: generateId(), title, classId, questionIds: selected.map(q => q.id), rules, createdBy });
85	    await this._quizRepo.add(quiz);
86	    await this._auditService.log('quiz', quiz.id, 'created', `Paper generated: ${title}`, createdBy);
87	    return quiz;
88	  }
89	
90	  _selectQuestions(allQuestions, rules) {
91	    const total = rules.totalQuestions || 30;
92	    const distribution = rules.difficultyDistribution || {};
93	    const chapterMin = rules.chapterConstraints || {};
94	    const difficultyCounts = {};
95	    let allocated = 0;
96	    const difficulties = Object.keys(distribution).map(Number).sort();
97	    for (const d of difficulties) { difficultyCounts[d] = Math.floor(total * distribution[d]); allocated += difficultyCounts[d]; }
98	    if (allocated < total && difficulties.length > 0) difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
99	    const byDifficulty = {};
100	    for (const q of allQuestions) { if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = []; byDifficulty[q.difficulty].push(q); }
101	    for (const d of Object.keys(byDifficulty)) byDifficulty[d] = this._shuffle(byDifficulty[d]);
102	    const selected = [];
103	    const usedIds = new Set();
104	    for (const [chapter, minCount] of Object.entries(chapterMin)) {
105	      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
106	      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) { selected.push(chapterQs[i]); usedIds.add(chapterQs[i].id); }
107	    }
108	    for (const [d, count] of Object.entries(difficultyCounts)) {
109	      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
110	      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
111	      for (let i = 0; i < Math.min(needed, pool.length); i++) { selected.push(pool[i]); usedIds.add(pool[i].id); }
112	    }
113	    return selected.slice(0, total);
114	  }
115	
116	  _shuffle(arr) { const a = [...arr]; for (let i = a.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [a[i], a[j]] = [a[j], a[i]]; } return a; }
117	
118	  async submitAnswers(quizId, userId, answers) {
119	    if (!quizId) throw new Error('quizId is required.');
120	    if (!userId) throw new Error('userId is required.');
121	    if (!Array.isArray(answers)) throw new Error('answers must be an array.');
122	    const quiz = await this._quizRepo.getById(quizId);
123	    if (!quiz) throw new Error('Quiz not found.');
124	    if (!quiz.questionIds || quiz.questionIds.length === 0) throw new Error('Quiz has no questions.');
125	
126	    const gradedAnswers = [];
127	    let objectiveCorrect = 0, objectiveTotal = 0;
128	    for (const ans of answers) {
129	      const question = await this._questionRepo.getById(ans.questionId);
130	      if (!question) continue;
131	      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
132	      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
133	        graded.autoGraded = false;
134	      } else {
135	        graded.autoGraded = true;
136	        objectiveTotal++;
137	        if (question.type === QUESTION_TYPES.MULTIPLE) {
138	          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
139	          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
140	          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
141	        } else {
142	          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
143	        }
144	        if (graded.isCorrect) objectiveCorrect++;
145	        if (!graded.isCorrect) await this._addWrongQuestion(userId, question, ans.answer, quizId);
146	      }
147	      gradedAnswers.push(graded);
148	    }
149	
150	    const result = createQuizResult({ id: generateId(), quizId, userId, answers: gradedAnswers, objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null });
151	    await this._quizResultRepo.add(result);
152	    return result;
153	  }
154	
155	  async getResultsByUserId(userId) { return this._quizResultRepo.getByUserId(userId); }
156	  async getResultsByQuizId(quizId) { return this._quizResultRepo.getByQuizId(quizId); }
157	  async getAllQuizzes() { return this._quizRepo.getAll(); }
158	  async getQuizById(quizId) { return this._quizRepo.getById(quizId); }
159	  async getAllQuizResults() { return this._quizResultRepo.getAll(); }
160	  async getWrongQuestions(userId) { return this._wrongQRepo.getByUserId(userId); }
161	
162	  async _addWrongQuestion(userId, question, userAnswer, quizId) {
163	    const entry = createWrongQuestion({ id: generateId(), userId, questionId: question.id, userAnswer: JSON.stringify(userAnswer), correctAnswer: JSON.stringify(question.correctAnswer), explanation: question.explanation, quizId });
164	    await this._wrongQRepo.add(entry);
165	  }
166	}
167	
168	export default new QuizService();
