2	 * ModerationService — sensitive-word filtering, abuse reports, resolution tracking.
3	 */
4	
5	import reportRepository from '../repositories/ReportRepository.js';
6	import defaultAuditService from './AuditService.js';
7	import { createReport, REPORT_STATUS, REPORT_OUTCOMES } from '../models/Report.js';
8	import { generateId, now } from '../utils/helpers.js';
9	
10	const RESOLUTION_DEADLINE_DAYS = 7;
11	
12	const FALLBACK_WORDS = ['spam', 'scam', 'fake', 'fraud', 'abuse', 'harassment', 'threat', 'exploit', 'illegal', 'offensive'];
13	
14	let sensitiveWords = [];
15	
16	export class ModerationService {
17	  constructor(deps = {}) {
18	    this._reportRepo = deps.reportRepository || reportRepository;
19	    this._auditService = deps.auditService || defaultAuditService;
20	    if (deps.sensitiveWords) {
21	      sensitiveWords = deps.sensitiveWords;
22	    }
23	  }
24	
25	  async loadSensitiveWords() {
26	    try {
27	      const response = await fetch('../src/config/sensitiveWords.json');
28	      const data = await response.json();
29	      sensitiveWords = (data.words || []).map(w => w.toLowerCase());
30	    } catch (e) {
31	      console.warn('Could not load sensitive words config, using fallback list.');
32	      sensitiveWords = FALLBACK_WORDS;
33	    }
34	  }
35	
36	  checkContent(text) {
37	    if (!text) return { flagged: false, words: [] };
38	    const lower = text.toLowerCase();
39	    const found = sensitiveWords.filter(w => lower.includes(w));
40	    return { flagged: found.length > 0, words: found };
41	  }
42	
43	  async submitReport(reporterId, targetId, targetType, reason) {
44	    if (!reporterId) throw new Error('reporterId is required.');
45	    if (!targetId) throw new Error('targetId is required.');
46	    if (!targetType) throw new Error('targetType is required.');
47	    const report = createReport({ id: generateId(), reporterId, targetId, targetType, reason });
48	    await this._reportRepo.add(report);
49	    await this._auditService.log('report', report.id, 'created', `Abuse report filed against ${targetType}:${targetId}`, reporterId);
50	    return report;
51	  }
52	
53	  async resolveReport(reportId, outcome, resolvedBy) {
54	    if (!reportId) throw new Error('reportId is required.');
55	    if (!resolvedBy) throw new Error('resolvedBy is required.');
56	    const report = await this._reportRepo.getById(reportId);
57	    if (!report) throw new Error('Report not found.');
58	    if (report.status === REPORT_STATUS.RESOLVED) throw new Error('Report has already been resolved.');
59	    const validOutcomes = Object.values(REPORT_OUTCOMES);
60	    if (!validOutcomes.includes(outcome)) throw new Error(`Outcome must be one of: ${validOutcomes.join(', ')}`);
61	    report.status = REPORT_STATUS.RESOLVED;
62	    report.resolution = outcome;
63	    report.resolvedBy = resolvedBy;
64	    report.resolvedAt = now();
65	    await this._reportRepo.put(report);
66	    await this._auditService.log('report', report.id, 'resolved', `Report resolved: ${outcome}`, resolvedBy);
67	    return report;
68	  }
69	
70	  async getOpenReports() {
71	    const open = await this._reportRepo.getByStatus(REPORT_STATUS.OPEN);
72	    const underReview = await this._reportRepo.getByStatus(REPORT_STATUS.UNDER_REVIEW);
73	    return [...open, ...underReview];
74	  }
75	
76	  async getOverdueReports() {
77	    const open = await this.getOpenReports();
78	    const cutoff = Date.now() - RESOLUTION_DEADLINE_DAYS * 24 * 60 * 60 * 1000;
79	    return open.filter(r => new Date(r.createdAt).getTime() < cutoff);
80	  }
81	
82	  async getAllReports() { return this._reportRepo.getAll(); }
83	  async getReportById(reportId) { return this._reportRepo.getById(reportId); }
84	}
