1	/**
2	 * ContractService — template management, placeholder substitution, versioning,
3	 * signature handling, signing workflow states, PDF-like print export.
4	 */
5	
6	import contractRepository from '../repositories/ContractRepository.js';
7	import templateRepository from '../repositories/TemplateRepository.js';
8	import defaultAuditService from './AuditService.js';
9	import defaultCryptoService from './CryptoService.js';
10	import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
11	import { generateId, now, downloadBlob } from '../utils/helpers.js';
12	
13	export class ContractService {
14	  constructor(deps = {}) {
15	    this._contractRepo = deps.contractRepository || contractRepository;
16	    this._templateRepo = deps.templateRepository || templateRepository;
17	    this._auditService = deps.auditService || defaultAuditService;
18	    this._cryptoService = deps.cryptoService || defaultCryptoService;
19	  }
20	
21	  async createTemplate(data) {
22	    // Extract placeholders from content
23	    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
24	
25	    const template = createTemplate({
26	      id: generateId(),
27	      name: data.name,
28	      content: data.content,
29	      placeholders,
30	      active: true,
31	      version: 1,
32	      effectiveDate: data.effectiveDate || now(),
33	    });
34	
35	    await this._templateRepo.add(template);
36	    await this._auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
37	    return template;
38	  }
39	
40	  async updateTemplate(templateId, updates, updatedBy) {
41	    const existing = await this._templateRepo.getById(templateId);
42	    if (!existing) throw new Error('Template not found.');
43	
44	    // Deactivate old version
45	    existing.active = false;
46	    existing.updatedAt = now();
47	    await this._templateRepo.put(existing);
48	
49	    // Create new version
50	    const newVersion = createTemplate({
51	      id: generateId(),
52	      name: updates.name || existing.name,
53	      content: updates.content || existing.content,
54	      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
55	      active: true,
56	      version: existing.version + 1,
57	      effectiveDate: updates.effectiveDate || now(),
58	    });
59	
60	    await this._templateRepo.add(newVersion);
61	    await this._auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
62	    return newVersion;
63	  }
64	
65	  async getActiveTemplates() {
66	    return this._templateRepo.getActive();
67	  }
68	
69	  async getTemplateById(templateId) {
70	    return this._templateRepo.getById(templateId);
71	  }
72	
73	  async getAllTemplates() {
74	    return this._templateRepo.getAll();
75	  }
76	
77	  // --- Contract Generation ---
78	
79	  /**
80	   * Generate a contract from a template with variable substitution.
81	   */
82	  async generateContract(templateId, variables, createdBy) {
83	    const template = await this._templateRepo.getById(templateId);
84	    if (!template) throw new Error('Template not found.');
85	
86	    let content = template.content;
87	    for (const [key, value] of Object.entries(variables)) {
88	      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
89	    }
90	
91	    const contract = createContract({
92	      id: generateId(),
93	      templateId,
94	      templateVersion: template.version,
95	      content,
96	      status: CONTRACT_STATUS.INITIATED,
97	      createdBy,
98	    });
99	
100	    await this._contractRepo.add(contract);
101	    await this._auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
102	    return contract;
103	  }
104	
105	  // --- Signing Workflow ---
106	
107	  /**
108	   * Transition a contract's signing status.
109	   */
110	  async transitionStatus(contractId, newStatus, userId) {
111	    const contract = await this._contractRepo.getById(contractId);
112	    if (!contract) throw new Error('Contract not found.');
113	
114	    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
115	    if (!allowed.includes(newStatus)) {
116	      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
117	    }
118	
119	    const fromStatus = contract.status;
120	    contract.status = newStatus;
121	    contract.updatedAt = now();
122	    await this._contractRepo.put(contract);
123	
124	    await this._auditService.log('contract', contractId, 'status_change', `${fromStatus} → ${newStatus}`, userId);
125	    return contract;
126	  }
127	
128	  /**
129	   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
130	   */
131	  async signContract(contractId, signatureData, signerName, userId) {
132	    const contract = await this._contractRepo.getById(contractId);
133	    if (!contract) throw new Error('Contract not found.');
134	
135	    if (contract.status !== CONTRACT_STATUS.INITIATED) {
136	      throw new Error('Contract can only be signed when in initiated status.');
137	    }
138	
139	    if (!signatureData || String(signatureData).trim() === '') {
140	      throw new Error('Signature is required before signing.');
141	    }
142	
143	    if (!signerName || String(signerName).trim() === '') {
144	      throw new Error('Signer name is required.');
145	    }
146	
147	    const timestamp = now();
148	    const hash = await this._cryptoService.generateSignatureHash(contract.content, signerName, timestamp);
149	
150	    contract.signatureData = signatureData; // base64 canvas or typed name
151	    contract.signatureHash = hash;
152	    contract.signedBy = userId;
153	    contract.signedAt = timestamp;
154	    contract.status = CONTRACT_STATUS.SIGNED;
155	    contract.updatedAt = timestamp;
156	
157	    await this._contractRepo.put(contract);
158	    await this._auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
159	    return contract;
160	  }
161	
162	  /**
163	   * Withdraw a contract.
164	   */
165	  async withdrawContract(contractId, userId) {
166	    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
167	  }
168	
169	  /**
170	   * Void a contract.
171	   */
172	  async voidContract(contractId, userId) {
173	    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
174	  }
175	
176	  // --- Export ---
177	
178	  /**
179	   * Export contract to a printable HTML blob for PDF-like output.
180	   */
181	  exportToPrintableHTML(contract) {
182	    const html = `<!DOCTYPE html>
183	<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
184	<style>
185	  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
186	  h1 { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; }
187	  .sig-block { margin-top: 40px; border-top: 1px solid #999; padding-top: 10px; }
188	  .hash { font-size: 0.7em; color: #666; word-break: break-all; }
189	  @media print { body { margin: 0; } }
190	</style></head><body>
191	<h1>Training Contract</h1>
192	<div class="content">${contract.content.replace(/\n/g, '<br>')}</div>
193	${contract.signedBy ? `
194	<div class="sig-block">
195	  <p><strong>Signed by:</strong> ${contract.signedBy}</p>
196	  <p><strong>Date:</strong> ${contract.signedAt}</p>
197	  <p class="hash"><strong>Integrity Hash:</strong> ${contract.signatureHash}</p>
198	</div>` : ''}
199	</body></html>`;
200	    return new Blob([html], { type: 'text/html' });
201	  }
202	
203	  /**
204	   * Trigger download of a printable contract.
205	   */
206	  downloadContract(contract) {
207	    const blob = this.exportToPrintableHTML(contract);
208	    downloadBlob(blob, `contract-${contract.id}.html`);
209	  }
210	
211	  async getContractById(contractId) {
212	    return this._contractRepo.getById(contractId);
213	  }
214	
215	  async getAllContracts() {
216	    return this._contractRepo.getAll();
217	  }
218	
219	  async getContractsByStatus(status) {
220	    return this._contractRepo.getByStatus(status);
221	  }
222	}
223	
224	export default new ContractService();
