11	
12	const MAX_IMAGES = 6;
13	const MAX_IMAGE_SIZE_MB = 2;
14	const MAX_TEXT_LENGTH = 2000;
15	const FOLLOW_UP_WINDOW_DAYS = 14;
16	
17	export class ReviewService {
18	  constructor(deps = {}) {
19	    this._reviewRepo = deps.reviewRepository || reviewRepository;
20	    this._auditService = deps.auditService || defaultAuditService;
21	    this._moderationService = deps.moderationService || defaultModerationService;
