23	
24	  async submitReview({ userId, targetUserId, targetClassId, direction, rating, text, images, tags }) {
25	    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
26	      throw new Error('Rating must be between 1 and 5.');
27	    }
28	    if (text && text.length > MAX_TEXT_LENGTH) {
29	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
30	    }
31	    if (text) {
32	      const modCheck = this._moderationService.checkContent(text);
33	      if (modCheck.flagged) {
34	        throw new Error(`Review contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
35	      }
36	    }
37	    if (images && images.length > MAX_IMAGES) {
38	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
39	    }
40	    if (images) {
41	      for (const img of images) {
42	        if (img.size > MAX_IMAGE_SIZE_MB * 1024 * 1024) {
43	          throw new Error(`Each image must be under ${MAX_IMAGE_SIZE_MB}MB.`);
44	        }
45	      }
46	    }
47	
48	    const review = createReview({
49	      id: generateId(),
50	      userId,
51	      targetUserId,
52	      targetClassId,
53	      direction,
54	      rating,
55	      text: text || '',
56	      images: images || [],
57	      tags: tags || [],
58	    });
59	
60	    await this._reviewRepo.add(review);
61	    await this._auditService.log('review', review.id, 'created', `Review submitted: ${rating} stars`, userId);
62	    return review;
63	  }
64	
65	  async submitFollowUp(originalReviewId, { text, rating, images, tags }, userId) {
66	    const original = await this._reviewRepo.getById(originalReviewId);
67	    if (!original) throw new Error('Original review not found.');
68	    if (original.userId !== userId) throw new Error('Only the original reviewer can follow up.');
69	
70	    const allReviews = await this._reviewRepo.getByUserId(userId);
71	    const existingFollowUp = allReviews.find(r => r.followUpOf === originalReviewId);
72	    if (existingFollowUp) {
73	      throw new Error('A follow-up review has already been submitted.');
74	    }
75	
76	    const daysSince = (Date.now() - new Date(original.createdAt).getTime()) / (1000 * 60 * 60 * 24);
77	    if (daysSince > FOLLOW_UP_WINDOW_DAYS) {
78	      throw new Error(`Follow-up reviews must be submitted within ${FOLLOW_UP_WINDOW_DAYS} days.`);
79	    }
80	
81	    if (rating !== undefined && rating !== null) {
82	      if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
83	        throw new Error('Rating must be between 1 and 5.');
84	      }
85	    }
86	    if (text && text.length > MAX_TEXT_LENGTH) {
87	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
88	    }
89	    if (text) {
90	      const modCheck = this._moderationService.checkContent(text);
91	      if (modCheck.flagged) {
92	        throw new Error(`Follow-up contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
93	      }
94	    }
95	    if (images && images.length > MAX_IMAGES) {
96	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
97	    }
98	
99	    const followUp = createReview({
100	      id: generateId(),
101	      userId,
102	      targetUserId: original.targetUserId,
103	      targetClassId: original.targetClassId,
104	      direction: original.direction,
105	      rating: rating || original.rating,
106	      text: text || '',
107	      images: images || [],
108	      tags: tags || [],
109	      followUpOf: originalReviewId,
110	    });
111	
112	    await this._reviewRepo.add(followUp);
113	    await this._auditService.log('review', followUp.id, 'follow_up', `Follow-up to review ${originalReviewId}`, userId);
114	    return followUp;
115	  }
116	
117	  async getById(reviewId) { return this._reviewRepo.getById(reviewId); }
118	  async getAll() { return this._reviewRepo.getAll(); }
119	  async getByUserId(userId) { return this._reviewRepo.getByUserId(userId); }
120	  async getByTargetUserId(targetUserId) { return this._reviewRepo.getByTargetUserId(targetUserId); }
121	  async getByDirection(direction) { return this._reviewRepo.getByDirection(direction); }
122	}
