1	/**
2	 * ImportExportService — full dataset export/import with optional AES encryption.
3	 */
4	
5	import { getDatabase, openDatabase, STORES } from '../store/Database.js';
6	import cryptoService from './CryptoService.js';
7	import { downloadBlob } from '../utils/helpers.js';
8	
9	export class ImportExportService {
10	  /**
11	   * Export the entire dataset as JSON.
12	   * @param {string} [passphrase] — if provided, encrypt the export with AES-GCM
13	   */
14	  async exportAll(passphrase = null) {
15	    const db = getDatabase();
16	    if (!db) throw new Error('Database not initialized.');
17	
18	    const data = {};
19	    for (const storeDef of STORES) {
20	      data[storeDef.name] = await this._readStore(db, storeDef.name);
21	    }
22	
23	    // Also capture LocalStorage settings
24	    data._localStorage = {};
25	    for (let i = 0; i < localStorage.length; i++) {
26	      const key = localStorage.key(i);
27	      data._localStorage[key] = localStorage.getItem(key);
28	    }
29	
30	    let jsonStr = JSON.stringify(data, null, 2);
31	
32	    if (passphrase) {
33	      const encrypted = await cryptoService.encrypt(jsonStr, passphrase);
34	      jsonStr = JSON.stringify({ encrypted: true, ...encrypted });
35	    }
36	
37	    const blob = new Blob([jsonStr], { type: 'application/json' });
38	    const filename = `trainingops-backup-${new Date().toISOString().slice(0, 10)}.json`;
39	    downloadBlob(blob, filename);
40	
41	    return { success: true, filename };
42	  }
43	
44	  /**
45	   * Import a dataset from a JSON file.
46	   * @param {File} file
47	   * @param {string} [passphrase] — for decryption
48	   * @returns {{ success: boolean, preview?: object, error?: string }}
49	   */
50	  async parseImportFile(file, passphrase = null) {
51	    const text = await file.text();
52	    let parsed;
53	
54	    try {
55	      parsed = JSON.parse(text);
56	    } catch {
57	      return { success: false, error: 'Invalid JSON file.' };
58	    }
59	
60	    // Decrypt if needed
61	    if (parsed.encrypted) {
62	      if (!passphrase) {
63	        return { success: false, error: 'File is encrypted. A passphrase is required.' };
64	      }
65	      try {
66	        const decrypted = await cryptoService.decrypt(parsed, passphrase);
67	        parsed = JSON.parse(decrypted);
68	      } catch {
69	        return { success: false, error: 'Decryption failed. Wrong passphrase.' };
70	      }
71	    }
72	
73	    // Build preview: count of records per store
74	    const preview = {};
75	    for (const storeDef of STORES) {
76	      if (parsed[storeDef.name]) {
77	        preview[storeDef.name] = parsed[storeDef.name].length;
78	      }
79	    }
80	
81	    return { success: true, preview, data: parsed };
82	  }
83	
84	  /**
85	   * Apply imported data (overwrites existing). Must call parseImportFile first.
86	   */
87	  async applyImport(data) {
88	    if (!data || typeof data !== 'object') {
89	      throw new Error('Invalid import data format.');
90	    }
91	
92	    const db = getDatabase();
93	    if (!db) throw new Error('Database not initialized.');
94	
95	    for (const storeDef of STORES) {
96	      if (!data[storeDef.name]) continue;
97	
98	      await new Promise((resolve, reject) => {
99	        const tx = db.transaction(storeDef.name, 'readwrite');
100	        const store = tx.objectStore(storeDef.name);
101	        store.clear();
102	        for (const record of data[storeDef.name]) {
103	          store.put(record);
104	        }
105	        tx.oncomplete = () => resolve();
106	        tx.onerror = () => reject(tx.error);
107	      });
108	    }
109	
110	    // Restore LocalStorage entries
111	    if (data._localStorage) {
112	      for (const [key, value] of Object.entries(data._localStorage)) {
113	        localStorage.setItem(key, value);
114	      }
115	    }
116	
117	    return { success: true };
118	  }
119	
120	  _readStore(db, storeName) {
121	    return new Promise((resolve, reject) => {
122	      const tx = db.transaction(storeName, 'readonly');
123	      const store = tx.objectStore(storeName);
124	      const req = store.getAll();
125	      req.onsuccess = () => resolve(req.result);
126	      req.onerror = () => reject(req.error);
127	    });
128	  }
129	}
130	
131	export default new ImportExportService();
