350	  async _takeQuiz(quizId) {
351	    const quiz = await quizService.getQuizById(quizId);
352	    if (!quiz) { Toast.error('Quiz not found.'); return; }
353	
354	    const questions = [];
355	    for (const qId of quiz.questionIds) {
356	      const q = await quizService.getQuestionById(qId);
357	      if (q) questions.push(q);
358	    }
359	
360	    if (questions.length === 0) { Toast.error('This quiz has no questions.'); return; }
361	
362	    // Build quiz form
363	    const questionsHTML = questions.map((q, idx) => {
364	      let inputHTML = '';
365	      if (q.type === QUESTION_TYPES.SINGLE) {
366	        inputHTML = (q.options || []).map(o =>
367	          `<label style="display:block;margin:4px 0"><input type="radio" name="ans-${q.id}" value="${escapeHtml(o.value)}"> ${escapeHtml(o.value)}: ${escapeHtml(o.label)}</label>`
368	        ).join('');
369	      } else if (q.type === QUESTION_TYPES.MULTIPLE) {
370	        inputHTML = (q.options || []).map(o =>
371	          `<label style="display:block;margin:4px 0"><input type="checkbox" name="ans-${q.id}" value="${escapeHtml(o.value)}"> ${escapeHtml(o.value)}: ${escapeHtml(o.label)}</label>`
372	        ).join('');
373	      } else if (q.type === QUESTION_TYPES.FILL_IN) {
374	        inputHTML = `<input type="text" class="form-control" id="ans-${q.id}" placeholder="Your answer">`;
375	      } else {
376	        inputHTML = `<textarea class="form-control" id="ans-${q.id}" rows="3" placeholder="Your answer (subjective)"></textarea>`;
377	      }
378	      return `
379	        <div style="margin-bottom:20px;padding:12px;border:1px solid var(--color-border);border-radius:var(--radius)">
380	          <p style="font-weight:600;margin-bottom:8px">${idx + 1}. ${escapeHtml(q.questionText)}</p>
381	          <small style="color:var(--color-text-muted)">Type: ${q.type} | Difficulty: ${q.difficulty}</small>
382	          <div style="margin-top:8px" data-qid="${q.id}" data-qtype="${q.type}">${inputHTML}</div>
383	        </div>
384	      `;
385	    }).join('');
386	
387	    Drawer.open(`Take Quiz: ${quiz.title}`, `
388	      <form id="quiz-submit-form">
389	        ${questionsHTML}
390	        <div id="quiz-submit-error" class="form-error"></div>
391	        <button type="submit" class="btn btn-primary" style="width:100%">Submit Answers</button>
392	      </form>
393	    `, (drawerEl) => {
394	      drawerEl.querySelector('#quiz-submit-form').addEventListener('submit', async (e) => {
395	        e.preventDefault();
396	        const user = authService.getCurrentUser();
397	        const answers = [];
398	
399	        for (const q of questions) {
400	          let answer;
401	          if (q.type === QUESTION_TYPES.SINGLE) {
402	            const checked = drawerEl.querySelector(`input[name="ans-${q.id}"]:checked`);
403	            answer = checked ? checked.value : '';
404	          } else if (q.type === QUESTION_TYPES.MULTIPLE) {
405	            const checked = drawerEl.querySelectorAll(`input[name="ans-${q.id}"]:checked`);
406	            answer = Array.from(checked).map(c => c.value);
407	          } else {
408	            const el = drawerEl.querySelector(`#ans-${q.id}`);
409	            answer = el ? el.value : '';
410	          }
411	          answers.push({ questionId: q.id, answer });
412	        }
413	
414	        try {
415	          const result = await quizService.submitAnswers(quiz.id, user.id, answers);
416	          Drawer.closeAll();
417	          Toast.success(`Quiz submitted! Objective score: ${result.objectiveScore !== null ? result.objectiveScore + '%' : 'N/A (subjective only)'}`);
418	          this.activeTab = 'my-results';
419	          this.render();
420	        } catch (err) {
421	          drawerEl.querySelector('#quiz-submit-error').textContent = err.message;
422	        }
423	      });
424	    });
425	  }
