628	            return;
629	          }
630	        }
631	
632	        if (graded > 0) {
633	          Toast.success(`Graded ${graded} answer(s).`);
634	        }
635	        Drawer.closeAll();
636	        this.render();
637	      });
638	    });
639	  }
