205	          <select id="sig-method" class="form-control">
206	            <option value="typed">Typed Name</option>
207	            <option value="drawn">Draw Signature</option>
208	          </select>
209	        </div>
210	        <div id="sig-typed" class="form-group">
211	          <label for="sig-name">Full Name</label>
212	          <input id="sig-name" class="form-control" type="text">
213	        </div>
214	        <div id="sig-drawn" class="form-group hidden">
215	          <label>Draw your signature</label>
216	          <canvas id="sig-canvas" width="400" height="150" style="border:1px solid var(--color-border);border-radius:var(--radius);cursor:crosshair;display:block"></canvas>
217	          <button type="button" class="btn btn-sm btn-secondary mt-4" id="sig-clear">Clear</button>
218	        </div>
219	        <div id="sig-error" class="form-error"></div>
220	        <button type="submit" class="btn btn-primary mt-4">Sign</button>
221	      </form>
222	    `, (modalEl, close) => {
223	      const methodSelect = modalEl.querySelector('#sig-method');
224	      const typedDiv = modalEl.querySelector('#sig-typed');
225	      const drawnDiv = modalEl.querySelector('#sig-drawn');
226	      const canvas = modalEl.querySelector('#sig-canvas');
227	      const ctx = canvas.getContext('2d');
228	      let drawing = false;
229	
230	      methodSelect.addEventListener('change', () => {
231	        if (methodSelect.value === 'typed') {
232	          typedDiv.classList.remove('hidden');
233	          drawnDiv.classList.add('hidden');
234	        } else {
235	          typedDiv.classList.add('hidden');
236	          drawnDiv.classList.remove('hidden');
237	        }
238	      });
239	
240	      // Canvas drawing
241	      canvas.addEventListener('mousedown', (e) => { drawing = true; ctx.beginPath(); ctx.moveTo(e.offsetX, e.offsetY); });
242	      canvas.addEventListener('mousemove', (e) => { if (drawing) { ctx.lineTo(e.offsetX, e.offsetY); ctx.stroke(); } });
243	      canvas.addEventListener('mouseup', () => { drawing = false; });
244	      canvas.addEventListener('mouseleave', () => { drawing = false; });
245	
246	      // Touch support
247	      canvas.addEventListener('touchstart', (e) => { e.preventDefault(); drawing = true; const t = e.touches[0]; const r = canvas.getBoundingClientRect(); ctx.beginPath(); ctx.moveTo(t.clientX - r.left, t.clientY - r.top); });
248	      canvas.addEventListener('touchmove', (e) => { e.preventDefault(); if (drawing) { const t = e.touches[0]; const r = canvas.getBoundingClientRect(); ctx.lineTo(t.clientX - r.left, t.clientY - r.top); ctx.stroke(); } });
249	      canvas.addEventListener('touchend', () => { drawing = false; });
250	
251	      modalEl.querySelector('#sig-clear')?.addEventListener('click', () => {
252	        ctx.clearRect(0, 0, canvas.width, canvas.height);
253	      });
254	
255	      modalEl.querySelector('#sign-form').addEventListener('submit', async (e) => {
256	        e.preventDefault();
257	        const user = authService.getCurrentUser();
258	        let signatureData, signerName;
259	
260	        if (methodSelect.value === 'typed') {
