266	          signatureData = signerName;
267	        } else {
268	          signerName = user.displayName || user.username;
269	          signatureData = canvas.toDataURL('image/png');
270	        }
271	
272	        try {
273	          await contractService.signContract(contract.id, signatureData, signerName, user.id);
274	          Toast.success('Contract signed successfully.');
275	          close();
276	          this.render();
277	        } catch (err) {
278	          modalEl.querySelector('#sig-error').textContent = err.message;
279	        }
280	      });
281	    });
282	  }
