1	/**
2	 * ReputationService — score calculation, threshold enforcement, rating aggregation.
3	 */
4	
5	import reputationScoreRepository from '../repositories/ReputationScoreRepository.js';
6	import auditService from './AuditService.js';
7	import { createReputationScore, REPUTATION_THRESHOLD } from '../models/ReputationScore.js';
8	import { generateId, now } from '../utils/helpers.js';
9	
10	// Default weights — can be overridden from appConfig
11	const DEFAULT_WEIGHTS = {
12	  fulfillmentRate: 0.5,
13	  lateRate: 0.3,
14	  complaintRate: 0.2,
15	};
16	
17	export class ReputationService {
18	  /**
19	   * Compute and store reputation score for a user.
20	   * @param {string} userId
21	   * @param {object} metrics — { fulfillmentRate: 0–1, lateRate: 0–1, complaintRate: 0–1 }
22	   * @param {object} [weights] — optional custom weights
23	   */
24	  async computeScore(userId, metrics, weights = DEFAULT_WEIGHTS) {
25	    if (!userId) throw new Error('userId is required.');
26	    if (!metrics) throw new Error('metrics object is required.');
27	
28	    const validate01 = (v, name) => {
29	      const n = Number(v);
30	      if (isNaN(n) || n < 0 || n > 1) throw new Error(`${name} must be between 0 and 1.`);
31	      return n;
32	    };
33	    metrics.fulfillmentRate = validate01(metrics.fulfillmentRate, 'fulfillmentRate');
34	    metrics.lateRate = validate01(metrics.lateRate, 'lateRate');
35	    metrics.complaintRate = validate01(metrics.complaintRate, 'complaintRate');
36	
37	    const score = Math.round(
38	      (metrics.fulfillmentRate * weights.fulfillmentRate +
39	        (1 - metrics.lateRate) * weights.lateRate +
40	        (1 - metrics.complaintRate) * weights.complaintRate) * 100
41	    );
42	
43	    const clampedScore = Math.max(0, Math.min(100, score));
44	
45	    const existing = await reputationScoreRepository.getByUserId(userId);
46	
47	    const record = createReputationScore({
48	      id: existing ? existing.id : generateId(),
49	      userId,
50	      score: clampedScore,
51	      fulfillmentRate: metrics.fulfillmentRate,
52	      lateRate: metrics.lateRate,
53	      complaintRate: metrics.complaintRate,
54	    });
55	
56	    await reputationScoreRepository.put(record);
57	    await auditService.log('reputation', userId, 'computed', `Score: ${clampedScore}`, 'system');
58	
59	    return record;
60	  }
61	
62	  /**
63	   * Get the current reputation score for a user.
64	   */
65	  async getScore(userId) {
66	    return reputationScoreRepository.getByUserId(userId);
67	  }
68	
69	  /**
70	   * Check if user is below threshold and should be restricted.
71	   */
72	  async isRestricted(userId) {
73	    const record = await this.getScore(userId);
74	    if (!record) return false; // no score computed yet, not restricted
75	    return record.score < REPUTATION_THRESHOLD;
76	  }
77	
78	  /**
79	   * Get all reputation scores.
80	   */
81	  async getAllScores() {
82	    return reputationScoreRepository.getAll();
83	  }
84	}
85	
86	export default new ReputationService();
