1	/**
2	 * RatingService — two-way ratings with tag-based feedback and appeal flow.
3	 */
4	
5	import ratingRepository from '../repositories/RatingRepository.js';
6	import appealRepository from '../repositories/AppealRepository.js';
7	import defaultAuditService from './AuditService.js';
8	import { createRating, createAppeal, APPEAL_STATUS } from '../models/Rating.js';
9	import { generateId, now } from '../utils/helpers.js';
10	
11	export class RatingService {
12	  constructor(deps = {}) {
13	    this._ratingRepo = deps.ratingRepository || ratingRepository;
14	    this._appealRepo = deps.appealRepository || appealRepository;
15	    this._auditService = deps.auditService || defaultAuditService;
16	  }
17	
18	  async submitRating({ fromUserId, toUserId, classId, score, tags, comment }) {
19	    if (!fromUserId) throw new Error('fromUserId is required.');
20	    if (!toUserId) throw new Error('toUserId is required.');
21	    if (fromUserId === toUserId) throw new Error('Cannot rate yourself.');
22	    if (!Number.isInteger(score) || score < 1 || score > 5) {
23	      throw new Error('Score must be between 1 and 5.');
24	    }
25	
26	    const rating = createRating({
27	      id: generateId(),
28	      fromUserId,
29	      toUserId,
30	      classId,
31	      score,
32	      tags: tags || [],
33	      comment: comment || '',
34	    });
35	
36	    await this._ratingRepo.add(rating);
37	    await this._auditService.log('rating', rating.id, 'created', `Rating ${score}/5 from ${fromUserId} to ${toUserId}`, fromUserId);
38	    return rating;
39	  }
40	
41	  /**
42	   * File an appeal on a rating.
43	   */
44	  async fileAppeal(ratingId, appealerId, reason) {
45	    if (!ratingId) throw new Error('ratingId is required.');
46	    if (!appealerId) throw new Error('appealerId is required.');
47	    if (!reason || String(reason).trim() === '') throw new Error('Appeal reason is required.');
48	
49	    const rating = await this._ratingRepo.getById(ratingId);
50	    if (!rating) throw new Error('Rating not found.');
51	
52	    const existingAppeals = await this._appealRepo.getByRatingId(ratingId);
53	    const pending = existingAppeals.find(a => a.status === APPEAL_STATUS.PENDING);
54	    if (pending) throw new Error('An appeal is already pending for this rating.');
55	
56	    const appeal = createAppeal({
57	      id: generateId(),
58	      ratingId,
59	      appealerId,
60	      reason,
61	    });
62	
63	    await this._appealRepo.add(appeal);
64	    await this._auditService.log('appeal', appeal.id, 'filed', `Appeal filed for rating ${ratingId}`, appealerId);
65	    return appeal;
66	  }
67	
68	  /**
69	   * Resolve an appeal (reviewer decision: uphold, adjust, void).
70	   */
71	  async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore = null) {
72	    if (!appealId) throw new Error('appealId is required.');
73	    if (!reviewerId) throw new Error('reviewerId is required.');
74	
75	    const appeal = await this._appealRepo.getById(appealId);
76	    if (!appeal) throw new Error('Appeal not found.');
77	
78	    if (appeal.status !== APPEAL_STATUS.PENDING) {
79	      throw new Error('Appeal has already been resolved.');
80	    }
81	
82	    if (!rationale || rationale.trim().length === 0) {
83	      throw new Error('Written rationale is required.');
84	    }
85	
86	    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
87	    if (!validDecisions.includes(decision)) {
88	      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
89	    }
90	
91	    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
92	      throw new Error('Adjusted score must be between 1 and 5.');
93	    }
94	
95	    appeal.status = decision;
96	    appeal.decision = decision;
97	    appeal.rationale = rationale;
98	    appeal.reviewerId = reviewerId;
99	    appeal.adjustedScore = adjustedScore;
100	    appeal.resolvedAt = now();
101	
102	    await this._appealRepo.put(appeal);
103	
104	    // If adjusted, update the original rating
105	    if (decision === APPEAL_STATUS.ADJUSTED) {
106	      const rating = await this._ratingRepo.getById(appeal.ratingId);
107	      if (rating) {
108	        rating.score = adjustedScore;
109	        await this._ratingRepo.put(rating);
110	      }
111	    }
112	
113	    // If voided, we could mark the rating as void — for now just log it
114	    await this._auditService.log('appeal', appealId, 'resolved', `Decision: ${decision}, rationale: ${rationale}`, reviewerId);
115	    return appeal;
116	  }
117	
118	  async getRatingById(ratingId) {
119	    return this._ratingRepo.getById(ratingId);
120	  }
121	
122	  async getRatingsForUser(toUserId) {
123	    return this._ratingRepo.getByToUserId(toUserId);
124	  }
125	
126	  async getRatingsByUser(fromUserId) {
127	    return this._ratingRepo.getByFromUserId(fromUserId);
128	  }
129	
130	  async getAllRatings() {
131	    return this._ratingRepo.getAll();
132	  }
133	
134	  async getPendingAppeals() {
135	    return this._appealRepo.getByStatus(APPEAL_STATUS.PENDING);
136	  }
137	
138	  async getAppealsByRatingId(ratingId) {
139	    return this._appealRepo.getByRatingId(ratingId);
140	  }
141	
142	  async getAllAppeals() {
143	    return this._appealRepo.getAll();
144	  }
145	}
146	
147	export default new RatingService();
