1	/**
2	 * Validation utilities for forms and business rules.
3	 */
4	
5	export function required(value, fieldName = 'Field') {
6	  if (value === null || value === undefined || String(value).trim() === '') {
7	    return `${fieldName} is required.`;
8	  }
9	  return null;
10	}
11	
12	export function minLength(value, min, fieldName = 'Field') {
13	  if (String(value).trim().length < min) {
14	    return `${fieldName} must be at least ${min} characters.`;
15	  }
16	  return null;
17	}
18	
19	export function maxLength(value, max, fieldName = 'Field') {
20	  if (String(value).trim().length > max) {
21	    return `${fieldName} must be at most ${max} characters.`;
22	  }
23	  return null;
24	}
25	
26	export function inRange(value, min, max, fieldName = 'Field') {
27	  const num = Number(value);
28	  if (isNaN(num) || num < min || num > max) {
29	    return `${fieldName} must be between ${min} and ${max}.`;
30	  }
31	  return null;
32	}
33	
34	export function isInteger(value, fieldName = 'Field') {
35	  if (!Number.isInteger(Number(value))) {
36	    return `${fieldName} must be an integer.`;
37	  }
38	  return null;
39	}
40	
41	export function isOneOf(value, allowed, fieldName = 'Field') {
42	  if (!allowed.includes(value)) {
43	    return `${fieldName} must be one of: ${allowed.join(', ')}.`;
44	  }
45	  return null;
46	}
47	
48	/**
49	 * Validate an array of rules. Returns first error or null.
50	 */
51	export function validateField(value, rules) {
52	  for (const rule of rules) {
53	    const error = rule(value);
54	    if (error) return error;
55	  }
56	  return null;
57	}
58	
59	/**
60	 * Validate an object against a schema of field → rules[].
61	 * @returns {{ valid: boolean, errors: Record<string, string> }}
62	 */
63	export function validateObject(obj, schema) {
64	  const errors = {};
65	  for (const [field, rules] of Object.entries(schema)) {
66	    const error = validateField(obj[field], rules);
67	    if (error) errors[field] = error;
68	  }
69	  return { valid: Object.keys(errors).length === 0, errors };
70	}
71	
72	/**
73	 * Validate question import row (for bulk import).
74	 */
75	export function validateQuestionRow(row, index) {
76	  const errors = [];
77	  if (!row.questionText || String(row.questionText).trim() === '') {
78	    errors.push(`Row ${index}: questionText is required`);
79	  }
80	  const validTypes = ['single', 'multiple', 'fill-in', 'subjective'];
81	  if (!validTypes.includes(row.type)) {
82	    errors.push(`Row ${index}: type must be one of ${validTypes.join(', ')}`);
83	  }
84	  if (row.type !== 'subjective' && (!row.correctAnswer || String(row.correctAnswer).trim() === '')) {
85	    errors.push(`Row ${index}: correctAnswer is required for ${row.type} type`);
86	  }
87	  const diff = Number(row.difficulty);
88	  if (!Number.isInteger(diff) || diff < 1 || diff > 5) {
89	    errors.push(`Row ${index}: difficulty must be 1–5`);
90	  }
91	  if (!row.tags || String(row.tags).trim() === '') {
92	    errors.push(`Row ${index}: tags is required`);
93	  }
94	  return errors;
95	}
