1	/**
2	 * General utility helpers used across the application.
3	 */
4	
5	/**
6	 * Generate a UUID v4 string.
7	 */
8	export function generateId() {
9	  return crypto.randomUUID
10	    ? crypto.randomUUID()
11	    : 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
12	        const r = (Math.random() * 16) | 0;
13	        return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
14	      });
15	}
16	
17	/**
18	 * Current ISO timestamp.
19	 */
20	export function now() {
21	  return new Date().toISOString();
22	}
23	
24	/**
25	 * Deep clone a plain object via structuredClone (or JSON fallback).
26	 */
27	export function deepClone(obj) {
28	  if (typeof structuredClone === 'function') return structuredClone(obj);
29	  return JSON.parse(JSON.stringify(obj));
30	}
31	
32	/**
33	 * Mask a string, showing only the last N characters.
34	 * @param {string} value
35	 * @param {number} visibleCount
36	 */
37	export function maskString(value, visibleCount = 4) {
38	  if (!value || value.length <= visibleCount) return value;
39	  return '*'.repeat(value.length - visibleCount) + value.slice(-visibleCount);
40	}
41	
42	/**
43	 * Format a date string for display.
44	 */
45	export function formatDate(isoString) {
46	  if (!isoString) return '';
47	  const d = new Date(isoString);
48	  return d.toLocaleDateString('en-US', {
49	    year: 'numeric', month: 'short', day: 'numeric',
50	    hour: '2-digit', minute: '2-digit',
51	  });
52	}
53	
54	/**
55	 * Debounce a function.
56	 */
57	export function debounce(fn, ms = 300) {
58	  let timer;
59	  return (...args) => {
60	    clearTimeout(timer);
61	    timer = setTimeout(() => fn(...args), ms);
62	  };
63	}
64	
65	/**
66	 * Sanitize HTML to prevent XSS.
67	 */
68	export function escapeHtml(str) {
69	  const div = document.createElement('div');
70	  div.textContent = str;
71	  return div.innerHTML;
72	}
73	
74	/**
75	 * Validate file is JPG or PNG and within size limit.
76	 */
77	export function validateImageFile(file, maxSizeMB = 2) {
78	  const validTypes = ['image/jpeg', 'image/png'];
79	  if (!validTypes.includes(file.type)) {
80	    return { valid: false, error: 'Only JPG and PNG files are allowed.' };
81	  }
82	  if (file.size > maxSizeMB * 1024 * 1024) {
83	    return { valid: false, error: `File must be under ${maxSizeMB}MB.` };
84	  }
85	  return { valid: true, error: null };
86	}
87	
88	/**
89	 * Read a file as ArrayBuffer.
90	 */
91	export function readFileAsArrayBuffer(file) {
92	  return new Promise((resolve, reject) => {
93	    const reader = new FileReader();
94	    reader.onload = () => resolve(reader.result);
95	    reader.onerror = () => reject(reader.error);
96	    reader.readAsArrayBuffer(file);
97	  });
98	}
99	
100	/**
101	 * Read a file as text.
102	 */
103	export function readFileAsText(file) {
104	  return new Promise((resolve, reject) => {
105	    const reader = new FileReader();
106	    reader.onload = () => resolve(reader.result);
107	    reader.onerror = () => reject(reader.error);
108	    reader.readAsText(file);
109	  });
110	}
111	
112	/**
113	 * Read a file as data URL (base64).
114	 */
115	export function readFileAsDataURL(file) {
116	  return new Promise((resolve, reject) => {
117	    const reader = new FileReader();
118	    reader.onload = () => resolve(reader.result);
119	    reader.onerror = () => reject(reader.error);
120	    reader.readAsDataURL(file);
121	  });
122	}
123	
124	/**
125	 * Trigger a browser download for a Blob.
126	 */
127	export function downloadBlob(blob, filename) {
128	  const url = URL.createObjectURL(blob);
129	  const a = document.createElement('a');
130	  a.href = url;
131	  a.download = filename;
132	  document.body.appendChild(a);
133	  a.click();
134	  document.body.removeChild(a);
135	  URL.revokeObjectURL(url);
136	}
