1	/**
2	 * GradingService — subjective grading with 0–10 rubric and notes.
3	 */
4	
5	import quizResultRepository from '../repositories/QuizResultRepository.js';
6	import auditService from './AuditService.js';
7	import { now } from '../utils/helpers.js';
8	
9	export class GradingService {
10	  /**
11	   * Grade a subjective answer within a quiz result.
12	   * @param {string} resultId — quiz result ID
13	   * @param {string} questionId — which question to grade
14	   * @param {number} score — integer 0–10
15	   * @param {string} notes — optional rubric notes
16	   * @param {string} gradedBy — instructor user ID
17	   */
18	  async gradeSubjective(resultId, questionId, score, notes, gradedBy) {
19	    if (!Number.isInteger(score) || score < 0 || score > 10) {
20	      throw new Error('Score must be an integer between 0 and 10.');
21	    }
22	
23	    const result = await quizResultRepository.getById(resultId);
24	    if (!result) throw new Error('Quiz result not found.');
25	
26	    if (!result.subjectiveScores) result.subjectiveScores = {};
27	
28	    result.subjectiveScores[questionId] = {
29	      score,
30	      notes: notes || '',
31	      gradedBy,
32	      gradedAt: now(),
33	    };
34	
35	    // Recalculate total score
36	    result.totalScore = this._computeTotalScore(result);
37	    result.gradedBy = gradedBy;
38	    result.gradedAt = now();
39	
40	    await quizResultRepository.put(result);
41	    await auditService.log('quizResult', resultId, 'graded', `Question ${questionId} scored ${score}/10`, gradedBy);
42	
43	    return result;
44	  }
45	
46	  /**
47	   * Get a quiz result by ID.
48	   */
49	  async getResultById(resultId) {
50	    return quizResultRepository.getById(resultId);
51	  }
52	
53	  /**
54	   * Check if all subjective items in a result have been graded.
55	   */
56	  async isFullyGraded(resultId) {
57	    const result = await quizResultRepository.getById(resultId);
58	    if (!result) return false;
59	
60	    const subjectiveAnswers = result.answers.filter(a => !a.autoGraded);
61	    return subjectiveAnswers.every(a => result.subjectiveScores && result.subjectiveScores[a.questionId]);
62	  }
63	
64	  _computeTotalScore(result) {
65	    let totalPoints = 0;
66	    let totalPossible = 0;
67	
68	    // Objective portion
69	    const objectiveAnswers = result.answers.filter(a => a.autoGraded);
70	    if (objectiveAnswers.length > 0) {
71	      const correct = objectiveAnswers.filter(a => a.isCorrect).length;
72	      totalPoints += correct;
73	      totalPossible += objectiveAnswers.length;
74	    }
75	
76	    // Subjective portion (normalized to 0–1 scale per question)
77	    if (result.subjectiveScores) {
78	      for (const [, entry] of Object.entries(result.subjectiveScores)) {
79	        totalPoints += entry.score / 10;
80	        totalPossible += 1;
81	      }
82	    }
83	
84	    return totalPossible > 0 ? Math.round((totalPoints / totalPossible) * 100) : null;
85	  }
86	}
87	
88	export default new GradingService();
