86	
87	    if (appeal.status !== APPEAL_STATUS.PENDING) {
88	      throw new Error('Appeal has already been resolved.');
89	    }
90	
91	    if (!rationale || rationale.trim().length === 0) {
92	      throw new Error('Written rationale is required.');
93	    }
94	
95	    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
96	    if (!validDecisions.includes(decision)) {
97	      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
98	    }
99	
100	    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
101	      throw new Error('Adjusted score must be between 1 and 5.');
102	    }
103	
104	    appeal.status = decision;
