100	    if (!rules || !rules.totalQuestions) throw new Error('Paper rules with totalQuestions are required.');
101	    const allQuestions = await this._questionRepo.getAll();
102	    if (allQuestions.length === 0) throw new Error('No questions available in the bank.');
103	
104	    const selected = this._selectQuestions(allQuestions, rules);
105	    const quiz = createQuiz({ id: generateId(), title, classId, questionIds: selected.map(q => q.id), rules, createdBy });
