111	  _selectQuestions(allQuestions, rules) {
112	    const total = rules.totalQuestions || 30;
113	    const distribution = rules.difficultyDistribution || {};
114	    const chapterMin = rules.chapterConstraints || {};
115	    const difficultyCounts = {};
116	    let allocated = 0;
117	    const difficulties = Object.keys(distribution).map(Number).sort();
118	    for (const d of difficulties) { difficultyCounts[d] = Math.floor(total * distribution[d]); allocated += difficultyCounts[d]; }
119	    if (allocated < total && difficulties.length > 0) difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
120	    const byDifficulty = {};
121	    for (const q of allQuestions) { if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = []; byDifficulty[q.difficulty].push(q); }
122	    for (const d of Object.keys(byDifficulty)) byDifficulty[d] = this._shuffle(byDifficulty[d]);
123	    const selected = [];
124	    const usedIds = new Set();
125	    for (const [chapter, minCount] of Object.entries(chapterMin)) {
126	      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
127	      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) { selected.push(chapterQs[i]); usedIds.add(chapterQs[i].id); }
128	    }
129	    for (const [d, count] of Object.entries(difficultyCounts)) {
130	      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
131	      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
132	      for (let i = 0; i < Math.min(needed, pool.length); i++) { selected.push(pool[i]); usedIds.add(pool[i].id); }
133	    }
134	    return selected.slice(0, total);
135	  }
