142	    if (!Array.isArray(answers)) throw new Error('answers must be an array.');
143	    const quiz = await this._quizRepo.getById(quizId);
144	    if (!quiz) throw new Error('Quiz not found.');
145	    if (!quiz.questionIds || quiz.questionIds.length === 0) throw new Error('Quiz has no questions.');
146	
147	    const gradedAnswers = [];
148	    let objectiveCorrect = 0, objectiveTotal = 0;
149	    for (const ans of answers) {
150	      const question = await this._questionRepo.getById(ans.questionId);
151	      if (!question) continue;
152	      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
153	      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
154	        graded.autoGraded = false;
155	      } else {
156	        graded.autoGraded = true;
157	        objectiveTotal++;
158	        if (question.type === QUESTION_TYPES.MULTIPLE) {
159	          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
160	          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
161	          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
162	        } else {
163	          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
164	        }
165	        if (graded.isCorrect) objectiveCorrect++;
166	        if (!graded.isCorrect) await this._addWrongQuestion(userId, question, ans.answer, quizId);
167	      }
168	      gradedAnswers.push(graded);
169	    }
170	
171	    const result = createQuizResult({ id: generateId(), quizId, userId, answers: gradedAnswers, objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null });
172	    await this._quizResultRepo.add(result);
173	    return result;
174	  }
