1	/**
2	 * AuthService — user authentication, session management, lockout logic.
3	 */
4	
5	import userRepository from '../repositories/UserRepository.js';
6	import sessionRepository from '../repositories/SessionRepository.js';
7	import cryptoService from './CryptoService.js';
8	import auditService from './AuditService.js';
9	import { createUser, USER_ROLES } from '../models/User.js';
10	import { generateId, now } from '../utils/helpers.js';
11	
12	const SESSION_KEY = 'trainingops_session';
13	const MAX_LOGIN_ATTEMPTS = 5;
14	const LOCKOUT_MINUTES = 15;
15	
16	export class AuthService {
17	  constructor() {
18	    this._currentUser = null;
19	    this._loginAttempts = {};  // username → count
20	    this.onSessionChange = null; // callback for state isolation
21	  }
22	
23	  /**
24	   * Initialize auth — check for existing session.
25	   */
26	  async init() {
27	    const sessionId = localStorage.getItem(SESSION_KEY);
28	    if (!sessionId) return null;
29	
30	    const session = await sessionRepository.getById(sessionId);
31	    if (!session) {
32	      localStorage.removeItem(SESSION_KEY);
33	      return null;
34	    }
35	
36	    const user = await userRepository.getById(session.userId);
37	    if (!user) {
38	      localStorage.removeItem(SESSION_KEY);
39	      return null;
40	    }
41	
42	    this._currentUser = user;
43	    return user;
44	  }
45	
46	  /**
47	   * Login with username and password.
48	   */
49	  async login(username, password) {
50	    if (!username || String(username).trim() === '') {
51	      return { success: false, error: 'Username is required.' };
52	    }
53	    if (!password) {
54	      return { success: false, error: 'Password is required.' };
55	    }
56	
57	    const user = await userRepository.getByUsername(username);
58	    if (!user) {
59	      return { success: false, error: 'Invalid username or password.' };
60	    }
61	
62	    // Check lockout
63	    if (user.lockoutUntil && new Date(user.lockoutUntil) > new Date()) {
64	      const remaining = Math.ceil((new Date(user.lockoutUntil) - new Date()) / 60000);
65	      return { success: false, error: `Account locked. Try again in ${remaining} minutes.` };
66	    }
67	
68	    if (!user.passwordHash || !user.passwordHash.includes(':')) {
69	      return { success: false, error: 'Account configuration error. Contact administrator.' };
70	    }
71	
72	    const [hash, salt] = user.passwordHash.split(':');
73	    const valid = await cryptoService.verifyPassword(password, hash, salt);
74	
75	    if (!valid) {
76	      this._loginAttempts[username] = (this._loginAttempts[username] || 0) + 1;
77	      if (this._loginAttempts[username] >= MAX_LOGIN_ATTEMPTS) {
78	        user.lockoutUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60000).toISOString();
79	        await userRepository.put(user);
80	        this._loginAttempts[username] = 0;
81	        return { success: false, error: `Too many failed attempts. Account locked for ${LOCKOUT_MINUTES} minutes.` };
82	      }
83	      return { success: false, error: 'Invalid username or password.' };
84	    }
85	
86	    // Clear lockout and attempts on success
87	    this._loginAttempts[username] = 0;
88	    if (user.lockoutUntil) {
89	      user.lockoutUntil = null;
90	      await userRepository.put(user);
91	    }
92	
93	    // Create session
94	    const session = { id: generateId(), userId: user.id, createdAt: now() };
95	    await sessionRepository.add(session);
96	    localStorage.setItem(SESSION_KEY, session.id);
97	
98	    this._currentUser = user;
99	
100	    // Notify listeners for state isolation (reset page instances)
101	    if (this.onSessionChange) this.onSessionChange();
102	
103	    await auditService.log('user', user.id, 'login', 'User logged in', user.id);
104	
105	    return { success: true, user };
106	  }
107	
108	  /**
109	   * Logout current user.
110	   */
111	  async logout() {
112	    const sessionId = localStorage.getItem(SESSION_KEY);
113	    if (sessionId) {
114	      try { await sessionRepository.delete(sessionId); } catch (_) { /* ignore */ }
115	    }
116	    localStorage.removeItem(SESSION_KEY);
117	
118	    if (this._currentUser) {
119	      await auditService.log('user', this._currentUser.id, 'logout', 'User logged out', this._currentUser.id);
120	    }
121	
122	    this._currentUser = null;
123	
124	    // Notify listeners for state isolation (reset page instances)
125	    if (this.onSessionChange) this.onSessionChange();
126	  }
127	
128	  /**
129	   * Get the currently logged-in user.
130	   */
131	  getCurrentUser() {
132	    return this._currentUser;
133	  }
134	
135	  /**
136	   * Check if user is authenticated.
137	   */
138	  isAuthenticated() {
139	    return this._currentUser !== null;
140	  }
141	
142	  /**
143	   * Check if current user has one of the given roles.
144	   */
145	  hasRole(...roles) {
146	    return this._currentUser && roles.includes(this._currentUser.role);
147	  }
148	
149	  /**
150	   * Register a new user (admin action).
151	   * Only Administrators can register new users.
152	   */
153	  async registerUser(username, password, role, displayName = '') {
154	    if (this._currentUser && this._currentUser.role !== USER_ROLES.ADMINISTRATOR) {
155	      return { success: false, error: 'Only administrators can register new users.' };
156	    }
157	    if (!username || String(username).trim() === '') {
158	      return { success: false, error: 'Username is required.' };
159	    }
160	    if (!password || password.length < 4) {
161	      return { success: false, error: 'Password must be at least 4 characters.' };
162	    }
163	
164	    const existing = await userRepository.getByUsername(username);
165	    if (existing) {
166	      return { success: false, error: 'Username already exists.' };
167	    }
168	
169	    const validRoles = Object.values(USER_ROLES);
170	    if (!validRoles.includes(role)) {
171	      return { success: false, error: `Invalid role. Must be one of: ${validRoles.join(', ')}` };
172	    }
173	
174	    const { hash, salt } = await cryptoService.hashPassword(password);
175	    const user = createUser({
176	      id: generateId(),
177	      username,
178	      passwordHash: `${hash}:${salt}`,
179	      role,
180	      displayName: displayName || username,
181	    });
182	
183	    await userRepository.add(user);
184	    await auditService.log('user', user.id, 'created', `User ${username} created with role ${role}`, this._currentUser?.id || 'system');
185	
186	    return { success: true, user };
187	  }
188	
189	  /**
190	   * Seed default users if none exist.
191	   */
192	  async seedDefaultUsers() {
193	    const count = await userRepository.count();
194	    if (count > 0) return;
195	
196	    const defaults = [
197	      { username: 'admin', password: 'admin123', role: USER_ROLES.ADMINISTRATOR, displayName: 'System Admin' },
198	      { username: 'reviewer', password: 'reviewer123', role: USER_ROLES.STAFF_REVIEWER, displayName: 'Staff Reviewer' },
199	      { username: 'instructor', password: 'instructor123', role: USER_ROLES.INSTRUCTOR, displayName: 'Instructor One' },
200	      { username: 'learner', password: 'learner123', role: USER_ROLES.LEARNER, displayName: 'Learner One' },
201	    ];
202	
203	    for (const d of defaults) {
204	      const { hash, salt } = await cryptoService.hashPassword(d.password);
205	      const user = createUser({
206	        id: generateId(),
207	        username: d.username,
208	        passwordHash: `${hash}:${salt}`,
209	        role: d.role,
210	        displayName: d.displayName,
211	      });
212	      await userRepository.add(user);
213	    }
214	  }
215	}
216	
217	export default new AuthService();
