1	/**
2	 * ContractService — template management, placeholder substitution, versioning,
3	 * signature handling, signing workflow states, PDF-like print export.
4	 */
5	
6	import contractRepository from '../repositories/ContractRepository.js';
7	import templateRepository from '../repositories/TemplateRepository.js';
8	import userRepository from '../repositories/UserRepository.js';
9	import defaultAuditService from './AuditService.js';
10	import defaultCryptoService from './CryptoService.js';
11	import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now, downloadBlob } from '../utils/helpers.js';
14	
15	export class ContractService {
16	  constructor(deps = {}) {
17	    this._contractRepo = deps.contractRepository || contractRepository;
18	    this._templateRepo = deps.templateRepository || templateRepository;
19	    this._userRepo = deps.userRepository || userRepository;
20	    this._auditService = deps.auditService || defaultAuditService;
21	    this._cryptoService = deps.cryptoService || defaultCryptoService;
22	  }
23	
24	  async createTemplate(data) {
25	    // Extract placeholders from content
26	    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
27	
28	    const template = createTemplate({
29	      id: generateId(),
30	      name: data.name,
31	      content: data.content,
32	      placeholders,
33	      active: true,
34	      version: 1,
35	      effectiveDate: data.effectiveDate || now(),
36	    });
37	
38	    await this._templateRepo.add(template);
39	    await this._auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
40	    return template;
41	  }
42	
43	  async updateTemplate(templateId, updates, updatedBy) {
44	    const existing = await this._templateRepo.getById(templateId);
45	    if (!existing) throw new Error('Template not found.');
46	
47	    // Deactivate old version
48	    existing.active = false;
49	    existing.updatedAt = now();
50	    await this._templateRepo.put(existing);
51	
52	    // Create new version
53	    const newVersion = createTemplate({
54	      id: generateId(),
55	      name: updates.name || existing.name,
56	      content: updates.content || existing.content,
57	      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
58	      active: true,
59	      version: existing.version + 1,
60	      effectiveDate: updates.effectiveDate || now(),
61	    });
62	
63	    await this._templateRepo.add(newVersion);
64	    await this._auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
65	    return newVersion;
66	  }
67	
68	  async getActiveTemplates() {
69	    return this._templateRepo.getActive();
70	  }
71	
72	  async getTemplateById(templateId) {
73	    return this._templateRepo.getById(templateId);
74	  }
75	
76	  async getAllTemplates() {
77	    return this._templateRepo.getAll();
78	  }
79	
80	  // --- Contract Generation ---
81	
82	  /**
83	   * Generate a contract from a template with variable substitution.
84	   */
85	  async generateContract(templateId, variables, createdBy) {
86	    const template = await this._templateRepo.getById(templateId);
87	    if (!template) throw new Error('Template not found.');
88	
89	    let content = template.content;
90	    for (const [key, value] of Object.entries(variables)) {
91	      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
92	    }
93	
94	    const contract = createContract({
95	      id: generateId(),
96	      templateId,
97	      templateVersion: template.version,
98	      content,
99	      status: CONTRACT_STATUS.INITIATED,
100	      createdBy,
101	    });
102	
103	    await this._contractRepo.add(contract);
104	    await this._auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
105	    return contract;
106	  }
107	
108	  // --- Signing Workflow ---
109	
110	  /**
111	   * Transition a contract's signing status.
112	   */
113	  async transitionStatus(contractId, newStatus, userId) {
114	    const contract = await this._contractRepo.getById(contractId);
115	    if (!contract) throw new Error('Contract not found.');
116	
117	    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
118	    if (!allowed.includes(newStatus)) {
119	      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
120	    }
121	
122	    const fromStatus = contract.status;
123	    contract.status = newStatus;
124	    contract.updatedAt = now();
125	    await this._contractRepo.put(contract);
126	
127	    await this._auditService.log('contract', contractId, 'status_change', `${fromStatus} → ${newStatus}`, userId);
128	    return contract;
129	  }
130	
131	  /**
132	   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
133	   */
134	  async signContract(contractId, signatureData, signerName, userId) {
135	    const contract = await this._contractRepo.getById(contractId);
136	    if (!contract) throw new Error('Contract not found.');
137	
138	    if (contract.status !== CONTRACT_STATUS.INITIATED) {
139	      throw new Error('Contract can only be signed when in initiated status.');
140	    }
141	
142	    if (!signatureData || String(signatureData).trim() === '') {
143	      throw new Error('Signature is required before signing.');
144	    }
145	
146	    if (!signerName || String(signerName).trim() === '') {
147	      throw new Error('Signer name is required.');
148	    }
149	
150	    const timestamp = now();
151	    const hash = await this._cryptoService.generateSignatureHash(contract.content, signerName, timestamp);
152	
153	    contract.signatureData = signatureData; // base64 canvas or typed name
154	    contract.signatureHash = hash;
155	    contract.signedBy = userId;
156	    contract.signedAt = timestamp;
157	    contract.status = CONTRACT_STATUS.SIGNED;
158	    contract.updatedAt = timestamp;
159	
160	    await this._contractRepo.put(contract);
161	    await this._auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
162	    return contract;
163	  }
164	
165	  /**
166	   * Withdraw a contract.
167	   */
168	  async withdrawContract(contractId, userId) {
169	    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
170	  }
171	
172	  /**
173	   * Void a contract.
174	   */
175	  async voidContract(contractId, userId) {
176	    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
177	  }
178	
179	  // --- Export ---
180	
181	  /**
182	   * Export contract to a printable HTML blob for PDF-like output.
183	   */
184	  exportToPrintableHTML(contract) {
185	    const html = `<!DOCTYPE html>
186	<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
187	<style>
188	  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
189	  h1 { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; }
190	  .sig-block { margin-top: 40px; border-top: 1px solid #999; padding-top: 10px; }
191	  .hash { font-size: 0.7em; color: #666; word-break: break-all; }
192	  @media print { body { margin: 0; } }
193	</style></head><body>
194	<h1>Training Contract</h1>
195	<div class="content">${contract.content.replace(/\n/g, '<br>')}</div>
196	${contract.signedBy ? `
197	<div class="sig-block">
198	  <p><strong>Signed by:</strong> ${contract.signedBy}</p>
199	  <p><strong>Date:</strong> ${contract.signedAt}</p>
200	  <p class="hash"><strong>Integrity Hash:</strong> ${contract.signatureHash}</p>
201	</div>` : ''}
202	</body></html>`;
203	    return new Blob([html], { type: 'text/html' });
204	  }
205	
206	  /**
207	   * Trigger download of a printable contract.
208	   */
209	  downloadContract(contract) {
210	    const blob = this.exportToPrintableHTML(contract);
211	    downloadBlob(blob, `contract-${contract.id}.html`);
212	  }
213	
214	  async getContractById(contractId) {
215	    return this._contractRepo.getById(contractId);
216	  }
217	
218	  async getAllContracts() {
219	    return this._contractRepo.getAll();
220	  }
221	
222	  async getContractsByStatus(status) {
223	    return this._contractRepo.getByStatus(status);
224	  }
225	}
226	
227	export default new ContractService();
