1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	import { getConfig } from '../config/appConfig.js';
16	
17	// Transitions only reviewers/admins may perform
18	const REVIEWER_ONLY_TRANSITIONS = [
19	  REGISTRATION_STATUS.UNDER_REVIEW,
20	  REGISTRATION_STATUS.APPROVED,
21	  REGISTRATION_STATUS.REJECTED,
22	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
23	  REGISTRATION_STATUS.WAITLISTED,
24	];
25	
26	export class RegistrationService {
27	  constructor(deps = {}) {
28	    this._registrationRepo = deps.registrationRepository || registrationRepository;
29	    this._eventRepo = deps.registrationEventRepository || registrationEventRepository;
30	    this._classRepo = deps.classRepository || classRepository;
31	    this._userRepo = deps.userRepository || userRepository;
32	    this._auditService = deps.auditService || defaultAuditService;
33	  }
34	
35	  async create(userId, classId, notes = '') {
36	    if (!userId) throw new Error('userId is required to create a registration.');
37	
38	    const registration = createRegistration({
39	      id: generateId(),
40	      userId,
41	      classId,
42	      status: REGISTRATION_STATUS.DRAFT,
43	      notes,
44	    });
45	    await this._registrationRepo.add(registration);
46	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
47	    await this._auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
48	    eventBus.emit('registration:created', registration);
49	    return registration;
50	  }
51	
52	  async transition(registrationId, newStatus, comment, userId) {
53	    if (!registrationId) throw new Error('registrationId is required.');
54	    if (!newStatus) throw new Error('newStatus is required.');
55	    if (!userId) throw new Error('userId is required for transition.');
56	
57	    const reg = await this._registrationRepo.getById(registrationId);
58	    if (!reg) throw new Error('Registration not found.');
59	
60	    if (!canTransition(reg.status, newStatus)) {
61	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
62	    }
63	
64	    const actingUser = await this._userRepo.getById(userId);
65	    if (actingUser) {
66	      const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
67	      const isOwner = reg.userId === userId;
68	
69	      if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
70	        throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
71	      }
72	
73	      if (!isReviewerOrAdmin) {
74	        if (!isOwner) {
75	          throw new Error('You can only modify your own registrations.');
76	        }
77	        const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
78	        if (!selfAllowed.includes(newStatus)) {
79	          throw new Error(`You do not have permission to transition to ${newStatus}.`);
80	        }
81	      }
82	    }
83	
84	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
85	      if (!comment || comment.trim().length < 20) {
86	        throw new Error('Rejection comment must be at least 20 characters.');
87	      }
88	    }
89	
90	    const fromStatus = reg.status;
91	    reg.status = newStatus;
92	    reg.updatedAt = now();
93	    await this._registrationRepo.put(reg);
94	
95	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
96	    await this._auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
97	
98	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
99	
100	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
101	      await this._checkWaitlistPromotion(reg.classId, userId);
102	    }
103	
104	    return reg;
105	  }
106	
107	  async batchTransition(registrationIds, newStatus, comment, userId) {
108	    const results = [];
109	    for (const id of registrationIds) {
110	      try {
111	        const reg = await this.transition(id, newStatus, comment, userId);
112	        results.push({ id, success: true, registration: reg });
113	      } catch (err) {
114	        results.push({ id, success: false, error: err.message });
115	      }
116	    }
117	    return results;
118	  }
119	
120	  async getById(registrationId) {
121	    return this._registrationRepo.getById(registrationId);
122	  }
123	
124	  async getAll() {
125	    return this._registrationRepo.getAll();
126	  }
127	
128	  async getByUserId(userId) {
129	    return this._registrationRepo.getByUserId(userId);
130	  }
131	
132	  async getByStatus(status) {
133	    return this._registrationRepo.getByStatus(status);
134	  }
135	
136	  async getByClassId(classId) {
137	    return this._registrationRepo.getByClassId(classId);
138	  }
139	
140	  async getEvents(registrationId) {
141	    return this._eventRepo.getByRegistrationId(registrationId);
142	  }
143	
144	  async getClassFillRate(classId) {
145	    if (!classId) return 0;
146	    const cls = await this._classRepo.getById(classId);
147	    if (!cls || !cls.capacity) return 0;
148	
149	    const regs = await this._registrationRepo.getByClassId(classId);
150	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
151	    return approvedCount / cls.capacity;
152	  }
153	
154	  async _checkWaitlistPromotion(classId, userId) {
155	    if (!classId) return;
156	
157	    const fillRate = await this.getClassFillRate(classId);
158	    const config = getConfig();
159	    const threshold = (config.registration && config.registration.waitlistPromotionFillRate) || 0.95;
160	    if (fillRate >= threshold) return;
161	
162	    const waitlisted = await this._registrationRepo.filter(
163	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
164	    );
165	    if (waitlisted.length === 0) return;
166	
167	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
168	
169	    const next = waitlisted[0];
170	    const fromStatus = next.status;
171	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
172	    next.updatedAt = now();
173	    await this._registrationRepo.put(next);
174	
175	    await this._logEvent(next.id, fromStatus, REGISTRATION_STATUS.UNDER_REVIEW, 'Auto-promoted from waitlist (seat available, fill rate < 95%)', userId);
176	    await this._auditService.log('registration', next.id, 'status_change', `${fromStatus} → ${REGISTRATION_STATUS.UNDER_REVIEW}: Waitlist promotion`, userId);
177	
178	    eventBus.emit('registration:transition', { registration: next, fromStatus, toStatus: REGISTRATION_STATUS.UNDER_REVIEW });
179	  }
180	
181	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
182	    const event = createRegistrationEvent({
183	      id: generateId(),
184	      registrationId,
185	      fromStatus,
186	      toStatus,
187	      comment,
188	      userId,
189	      timestamp: now(),
190	    });
191	    await this._eventRepo.add(event);
192	    return event;
193	  }
194	}
195	
196	export default new RegistrationService();
