12	
13	// Fallback defaults; overridden by appConfig at runtime
14	const DEFAULT_MAX_IMAGES = 6;
15	const DEFAULT_MAX_IMAGE_SIZE_MB = 2;
16	const DEFAULT_MAX_TEXT_LENGTH = 2000;
17	const DEFAULT_FOLLOW_UP_WINDOW_DAYS = 14;
18	
19	export class ReviewService {
20	  constructor(deps = {}) {
21	    this._reviewRepo = deps.reviewRepository || reviewRepository;
22	    this._auditService = deps.auditService || defaultAuditService;
23	    this._moderationService = deps.moderationService || defaultModerationService;
24	  }
25	
26	  async submitReview({ userId, targetUserId, targetClassId, direction, rating, text, images, tags }) {
27	    const config = getConfig();
28	    const MAX_TEXT_LENGTH = (config.review && config.review.maxTextLength) || DEFAULT_MAX_TEXT_LENGTH;
29	    const MAX_IMAGES = (config.review && config.review.maxImages) || DEFAULT_MAX_IMAGES;
30	    const MAX_IMAGE_SIZE_MB = (config.review && config.review.maxImageSizeMB) || DEFAULT_MAX_IMAGE_SIZE_MB;
31	
32	    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
33	      throw new Error('Rating must be between 1 and 5.');
34	    }
35	    if (text && text.length > MAX_TEXT_LENGTH) {
36	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
37	    }
38	    if (text) {
39	      const modCheck = this._moderationService.checkContent(text);
40	      if (modCheck.flagged) {
41	        throw new Error(`Review contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
42	      }
43	    }
44	    if (images && images.length > MAX_IMAGES) {
45	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
46	    }
47	    if (images) {
48	      for (const img of images) {
49	        if (img.size > MAX_IMAGE_SIZE_MB * 1024 * 1024) {
50	          throw new Error(`Each image must be under ${MAX_IMAGE_SIZE_MB}MB.`);
51	        }
52	      }
53	    }
54	
55	    const review = createReview({
56	      id: generateId(),
57	      userId,
58	      targetUserId,
59	      targetClassId,
60	      direction,
61	      rating,
62	      text: text || '',
63	      images: images || [],
64	      tags: tags || [],
65	    });
66	
67	    await this._reviewRepo.add(review);
68	    await this._auditService.log('review', review.id, 'created', `Review submitted: ${rating} stars`, userId);
69	    return review;
70	  }
71	
72	  async submitFollowUp(originalReviewId, { text, rating, images, tags }, userId) {
73	    const config = getConfig();
74	    const MAX_TEXT_LENGTH = (config.review && config.review.maxTextLength) || DEFAULT_MAX_TEXT_LENGTH;
75	    const MAX_IMAGES = (config.review && config.review.maxImages) || DEFAULT_MAX_IMAGES;
76	    const FOLLOW_UP_WINDOW_DAYS = (config.review && config.review.followUpWindowDays) || DEFAULT_FOLLOW_UP_WINDOW_DAYS;
77	
78	    const original = await this._reviewRepo.getById(originalReviewId);
79	    if (!original) throw new Error('Original review not found.');
80	    if (original.userId !== userId) throw new Error('Only the original reviewer can follow up.');
81	
82	    const allReviews = await this._reviewRepo.getByUserId(userId);
83	    const existingFollowUp = allReviews.find(r => r.followUpOf === originalReviewId);
84	    if (existingFollowUp) {
85	      throw new Error('A follow-up review has already been submitted.');
86	    }
87	
88	    const daysSince = (Date.now() - new Date(original.createdAt).getTime()) / (1000 * 60 * 60 * 24);
89	    if (daysSince > FOLLOW_UP_WINDOW_DAYS) {
90	      throw new Error(`Follow-up reviews must be submitted within ${FOLLOW_UP_WINDOW_DAYS} days.`);
91	    }
92	
93	    if (rating !== undefined && rating !== null) {
94	      if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
95	        throw new Error('Rating must be between 1 and 5.');
96	      }
97	    }
98	    if (text && text.length > MAX_TEXT_LENGTH) {
99	      throw new Error(`Review text must be at most ${MAX_TEXT_LENGTH} characters.`);
100	    }
101	    if (text) {
102	      const modCheck = this._moderationService.checkContent(text);
103	      if (modCheck.flagged) {
104	        throw new Error(`Follow-up contains prohibited content: ${modCheck.words.join(', ')}. Please revise.`);
105	      }
106	    }
107	    if (images && images.length > MAX_IMAGES) {
108	      throw new Error(`Maximum ${MAX_IMAGES} images allowed.`);
109	    }
110	
111	    const followUp = createReview({
112	      id: generateId(),
113	      userId,
114	      targetUserId: original.targetUserId,
115	      targetClassId: original.targetClassId,
116	      direction: original.direction,
117	      rating: rating || original.rating,
118	      text: text || '',
119	      images: images || [],
120	      tags: tags || [],
121	      followUpOf: originalReviewId,
122	    });
123	
124	    await this._reviewRepo.add(followUp);
125	    await this._auditService.log('review', followUp.id, 'follow_up', `Follow-up to review ${originalReviewId}`, userId);
126	    return followUp;
127	  }
128	
129	  async getById(reviewId) { return this._reviewRepo.getById(reviewId); }
130	  async getAll() { return this._reviewRepo.getAll(); }
131	  async getByUserId(userId) { return this._reviewRepo.getByUserId(userId); }
132	  async getByTargetUserId(targetUserId) { return this._reviewRepo.getByTargetUserId(targetUserId); }
133	  async getByDirection(direction) { return this._reviewRepo.getByDirection(direction); }
134	}
