5	import { describe, it, assert, assertEqual, assertThrowsAsync, buildTestServices } from '../test-helpers.js';
6	import { validateQuestionRow } from '../src/utils/validators.js';
7	
8	export async function runQuizTests() {
9	  await describe('QuizService.createQuestion() — Validation (real service)', async () => {
10	    await it('should create a valid single-choice question', async () => {
11	      const { quizService } = buildTestServices();
12	      const q = await quizService.createQuestion({ questionText: 'What is 2+2?', type: 'single', correctAnswer: 'B', difficulty: 3, tags: ['math'] });
13	      assertEqual(q.type, 'single');
14	    });
15	
16	    await it('should persist question', async () => {
17	      const { quizService, repos } = buildTestServices();
18	      const q = await quizService.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 1, tags: ['t'] });
19	      const fetched = await repos.questionRepository.getById(q.id);
20	      assert(fetched !== null);
21	    });
22	
23	    await it('should reject empty questionText', async () => {
24	      const { quizService } = buildTestServices();
25	      await assertThrowsAsync(() => quizService.createQuestion({ questionText: '', type: 'single', correctAnswer: 'A', difficulty: 3 }), 'questionText is required');
26	    });
27	
28	    await it('should reject invalid type', async () => {
29	      const { quizService } = buildTestServices();
30	      await assertThrowsAsync(() => quizService.createQuestion({ questionText: 'Q', type: 'essay', correctAnswer: 'A', difficulty: 3 }), 'type must be one of');
31	    });
32	
33	    await it('should reject missing correctAnswer for non-subjective', async () => {
34	      const { quizService } = buildTestServices();
35	      await assertThrowsAsync(() => quizService.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: '', difficulty: 3 }), 'correctAnswer is required');
36	    });
37	
38	    await it('should allow missing correctAnswer for subjective', async () => {
39	      const { quizService } = buildTestServices();
40	      const q = await quizService.createQuestion({ questionText: 'Explain X', type: 'subjective', difficulty: 2, tags: ['t'] });
41	      assertEqual(q.type, 'subjective');
42	    });
43	
44	    await it('should reject difficulty outside 1-5', async () => {
45	      const { quizService } = buildTestServices();
46	      await assertThrowsAsync(() => quizService.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 0 }), 'difficulty must be');
47	      await assertThrowsAsync(() => quizService.createQuestion({ questionText: 'Q', type: 'single', correctAnswer: 'A', difficulty: 6 }), 'difficulty must be');
48	    });
49	  });
50	
51	  await describe('QuizService.bulkImport() — Validation (real service)', async () => {
52	    await it('should import valid rows', async () => {
