1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	import { getConfig } from '../config/appConfig.js';
16	
17	// Transitions only reviewers/admins may perform
18	const REVIEWER_ONLY_TRANSITIONS = [
19	  REGISTRATION_STATUS.UNDER_REVIEW,
20	  REGISTRATION_STATUS.APPROVED,
21	  REGISTRATION_STATUS.REJECTED,
22	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
23	  REGISTRATION_STATUS.WAITLISTED,
24	];
25	
26	export class RegistrationService {
27	  constructor(deps = {}) {
28	    this._registrationRepo = deps.registrationRepository || registrationRepository;
29	    this._eventRepo = deps.registrationEventRepository || registrationEventRepository;
30	    this._classRepo = deps.classRepository || classRepository;
31	    this._userRepo = deps.userRepository || userRepository;
32	    this._auditService = deps.auditService || defaultAuditService;
33	  }
34	
35	  async create(userId, classId, notes = '') {
36	    if (!userId) throw new Error('userId is required to create a registration.');
37	
38	    const registration = createRegistration({
39	      id: generateId(),
40	      userId,
41	      classId,
42	      status: REGISTRATION_STATUS.DRAFT,
43	      notes,
44	    });
45	    await this._registrationRepo.add(registration);
46	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
47	    await this._auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
48	    eventBus.emit('registration:created', registration);
49	    return registration;
50	  }
51	
52	  async transition(registrationId, newStatus, comment, userId) {
53	    if (!registrationId) throw new Error('registrationId is required.');
54	    if (!newStatus) throw new Error('newStatus is required.');
55	    if (!userId) throw new Error('userId is required for transition.');
56	
57	    const reg = await this._registrationRepo.getById(registrationId);
58	    if (!reg) throw new Error('Registration not found.');
59	
60	    if (!canTransition(reg.status, newStatus)) {
61	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
62	    }
63	
64	    const actingUser = await this._userRepo.getById(userId);
65	    if (!actingUser) {
66	      throw new Error('Acting user not found. Cannot perform transition.');
67	    }
68	
69	    const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
70	    const isOwner = reg.userId === userId;
71	
72	    if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
73	      throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
74	    }
75	
76	    if (!isReviewerOrAdmin) {
77	      if (!isOwner) {
78	        throw new Error('You can only modify your own registrations.');
79	      }
80	      const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
81	      if (!selfAllowed.includes(newStatus)) {
82	        throw new Error(`You do not have permission to transition to ${newStatus}.`);
83	      }
84	    }
85	
86	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
87	      if (!comment || comment.trim().length < 20) {
88	        throw new Error('Rejection comment must be at least 20 characters.');
89	      }
90	    }
91	
92	    const fromStatus = reg.status;
93	    reg.status = newStatus;
94	    reg.updatedAt = now();
95	    await this._registrationRepo.put(reg);
96	
97	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
98	    await this._auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
99	
100	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
101	
102	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
103	      await this._checkWaitlistPromotion(reg.classId, userId);
104	    }
105	
106	    return reg;
107	  }
108	
109	  async batchTransition(registrationIds, newStatus, comment, userId) {
110	    const results = [];
111	    for (const id of registrationIds) {
112	      try {
113	        const reg = await this.transition(id, newStatus, comment, userId);
114	        results.push({ id, success: true, registration: reg });
115	      } catch (err) {
116	        results.push({ id, success: false, error: err.message });
117	      }
118	    }
119	    return results;
120	  }
121	
122	  async getById(registrationId) {
123	    return this._registrationRepo.getById(registrationId);
124	  }
125	
126	  async getAll() {
127	    return this._registrationRepo.getAll();
128	  }
129	
130	  async getByUserId(userId) {
131	    return this._registrationRepo.getByUserId(userId);
132	  }
133	
134	  async getByStatus(status) {
135	    return this._registrationRepo.getByStatus(status);
136	  }
137	
138	  async getByClassId(classId) {
139	    return this._registrationRepo.getByClassId(classId);
140	  }
141	
142	  async getEvents(registrationId) {
143	    return this._eventRepo.getByRegistrationId(registrationId);
144	  }
145	
146	  async getClassFillRate(classId) {
147	    if (!classId) return 0;
148	    const cls = await this._classRepo.getById(classId);
149	    if (!cls || !cls.capacity) return 0;
150	
151	    const regs = await this._registrationRepo.getByClassId(classId);
152	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
153	    return approvedCount / cls.capacity;
154	  }
155	
156	  async _checkWaitlistPromotion(classId, userId) {
157	    if (!classId) return;
158	
159	    const fillRate = await this.getClassFillRate(classId);
160	    const config = getConfig();
161	    const threshold = (config.registration && config.registration.waitlistPromotionFillRate) || 0.95;
162	    if (fillRate >= threshold) return;
163	
164	    const waitlisted = await this._registrationRepo.filter(
165	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
166	    );
167	    if (waitlisted.length === 0) return;
168	
169	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
170	
171	    const next = waitlisted[0];
172	    const fromStatus = next.status;
173	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
174	    next.updatedAt = now();
175	    await this._registrationRepo.put(next);
176	
177	    await this._logEvent(next.id, fromStatus, REGISTRATION_STATUS.UNDER_REVIEW, 'Auto-promoted from waitlist (seat available, fill rate < 95%)', userId);
178	    await this._auditService.log('registration', next.id, 'status_change', `${fromStatus} → ${REGISTRATION_STATUS.UNDER_REVIEW}: Waitlist promotion`, userId);
179	
180	    eventBus.emit('registration:transition', { registration: next, fromStatus, toStatus: REGISTRATION_STATUS.UNDER_REVIEW });
181	  }
182	
183	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
184	    const event = createRegistrationEvent({
185	      id: generateId(),
186	      registrationId,
187	      fromStatus,
188	      toStatus,
189	      comment,
190	      userId,
191	      timestamp: now(),
192	    });
193	    await this._eventRepo.add(event);
194	    return event;
195	  }
196	}
197	
198	export default new RegistrationService();
199

1	/**
2	 * ContractService — template management, placeholder substitution, versioning,
3	 * signature handling, signing workflow states, PDF-like print export.
4	 */
5	
6	import contractRepository from '../repositories/ContractRepository.js';
7	import templateRepository from '../repositories/TemplateRepository.js';
8	import userRepository from '../repositories/UserRepository.js';
9	import defaultAuditService from './AuditService.js';
10	import defaultCryptoService from './CryptoService.js';
11	import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now, downloadBlob } from '../utils/helpers.js';
14	
15	export class ContractService {
16	  constructor(deps = {}) {
17	    this._contractRepo = deps.contractRepository || contractRepository;
18	    this._templateRepo = deps.templateRepository || templateRepository;
19	    this._userRepo = deps.userRepository || userRepository;
20	    this._auditService = deps.auditService || defaultAuditService;
21	    this._cryptoService = deps.cryptoService || defaultCryptoService;
22	  }
23	
24	  async _requireAdmin(userId) {
25	    if (!userId) throw new Error('userId is required for this operation.');
26	    const user = await this._userRepo.getById(userId);
27	    if (!user) {
28	      throw new Error('Acting user not found. Cannot perform this operation.');
29	    }
30	    if (user.role !== USER_ROLES.ADMINISTRATOR) {
31	      throw new Error('Only administrators can manage templates.');
32	    }
33	  }
34	
35	  async createTemplate(data) {
36	    if (data.createdBy) await this._requireAdmin(data.createdBy);
37	    // Extract placeholders from content
38	    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
39	
40	    const template = createTemplate({
41	      id: generateId(),
42	      name: data.name,
43	      content: data.content,
44	      placeholders,
45	      active: true,
46	      version: 1,
47	      effectiveDate: data.effectiveDate || now(),
48	    });
49	
50	    await this._templateRepo.add(template);
51	    await this._auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
52	    return template;
53	  }
54	
55	  async updateTemplate(templateId, updates, updatedBy) {
56	    if (updatedBy) await this._requireAdmin(updatedBy);
57	    const existing = await this._templateRepo.getById(templateId);
58	    if (!existing) throw new Error('Template not found.');
59	
60	    // Deactivate old version
61	    existing.active = false;
62	    existing.updatedAt = now();
63	    await this._templateRepo.put(existing);
64	
65	    // Create new version
66	    const newVersion = createTemplate({
67	      id: generateId(),
68	      name: updates.name || existing.name,
69	      content: updates.content || existing.content,
70	      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
71	      active: true,
72	      version: existing.version + 1,
73	      effectiveDate: updates.effectiveDate || now(),
74	    });
75	
76	    await this._templateRepo.add(newVersion);
77	    await this._auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
78	    return newVersion;
79	  }
80	
81	  async getActiveTemplates() {
82	    return this._templateRepo.getActive();
83	  }
84	
85	  async getTemplateById(templateId) {
86	    return this._templateRepo.getById(templateId);
87	  }
88	
89	  async getAllTemplates() {
90	    return this._templateRepo.getAll();
91	  }
92	
93	  // --- Contract Generation ---
94	
95	  /**
96	   * Generate a contract from a template with variable substitution.
97	   */
98	  async generateContract(templateId, variables, createdBy) {
99	    const template = await this._templateRepo.getById(templateId);
100	    if (!template) throw new Error('Template not found.');
101	
102	    let content = template.content;
103	    for (const [key, value] of Object.entries(variables)) {
104	      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
105	    }
106	
107	    const contract = createContract({
108	      id: generateId(),
109	      templateId,
110	      templateVersion: template.version,
111	      content,
112	      status: CONTRACT_STATUS.INITIATED,
113	      createdBy,
114	    });
115	
116	    await this._contractRepo.add(contract);
117	    await this._auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
118	    return contract;
119	  }
120	
121	  // --- Signing Workflow ---
122	
123	  /**
124	   * Transition a contract's signing status.
125	   */
126	  async transitionStatus(contractId, newStatus, userId) {
127	    const contract = await this._contractRepo.getById(contractId);
128	    if (!contract) throw new Error('Contract not found.');
129	
130	    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
131	    if (!allowed.includes(newStatus)) {
132	      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
133	    }
134	
135	    const fromStatus = contract.status;
136	    contract.status = newStatus;
137	    contract.updatedAt = now();
138	    await this._contractRepo.put(contract);
139	
140	    await this._auditService.log('contract', contractId, 'status_change', `${fromStatus} → ${newStatus}`, userId);
141	    return contract;
142	  }
143	
144	  /**
145	   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
146	   */
147	  async signContract(contractId, signatureData, signerName, userId) {
148	    const contract = await this._contractRepo.getById(contractId);
149	    if (!contract) throw new Error('Contract not found.');
150	
151	    if (contract.status !== CONTRACT_STATUS.INITIATED) {
152	      throw new Error('Contract can only be signed when in initiated status.');
153	    }
154	
155	    if (!signatureData || String(signatureData).trim() === '') {
156	      throw new Error('Signature is required before signing.');
157	    }
158	
159	    if (!signerName || String(signerName).trim() === '') {
160	      throw new Error('Signer name is required.');
161	    }
162	
163	    const timestamp = now();
164	    const hash = await this._cryptoService.generateSignatureHash(contract.content, signerName, timestamp);
165	
166	    contract.signatureData = signatureData; // base64 canvas or typed name
167	    contract.signatureHash = hash;
168	    contract.signedBy = userId;
169	    contract.signedAt = timestamp;
170	    contract.status = CONTRACT_STATUS.SIGNED;
171	    contract.updatedAt = timestamp;
172	
173	    await this._contractRepo.put(contract);
174	    await this._auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
175	    return contract;
176	  }
177	
178	  /**
179	   * Withdraw a contract.
180	   */
181	  async withdrawContract(contractId, userId) {
182	    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
183	  }
184	
185	  /**
186	   * Void a contract.
187	   */
188	  async voidContract(contractId, userId) {
189	    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
190	  }
191	
192	  // --- Export ---
193	
194	  /**
195	   * Export contract to a printable HTML blob for PDF-like output.
196	   */
197	  exportToPrintableHTML(contract) {
198	    const html = `<!DOCTYPE html>
199	<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
200	<style>
201	  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
202	  h1 { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; }
203	  .sig-block { margin-top: 40px; border-top: 1px solid #999; padding-top: 10px; }
204	  .hash { font-size: 0.7em; color: #666; word-break: break-all; }
205	  @media print { body { margin: 0; } }
206	</style></head><body>
207	<h1>Training Contract</h1>
208	<div class="content">${contract.content.replace(/\n/g, '<br>')}</div>
209	${contract.signedBy ? `
210	<div class="sig-block">
211	  <p><strong>Signed by:</strong> ${contract.signedBy}</p>
212	  <p><strong>Date:</strong> ${contract.signedAt}</p>
213	  <p class="hash"><strong>Integrity Hash:</strong> ${contract.signatureHash}</p>
214	</div>` : ''}
215	</body></html>`;
216	    return new Blob([html], { type: 'text/html' });
217	  }
218	
219	  /**
220	   * Trigger download of a printable contract.
221	   */
222	  downloadContract(contract) {
223	    const blob = this.exportToPrintableHTML(contract);
224	    downloadBlob(blob, `contract-${contract.id}.html`);
225	  }
226	
227	  async getContractById(contractId) {
228	    return this._contractRepo.getById(contractId);
229	  }
230	
231	  async getAllContracts() {
232	    return this._contractRepo.getAll();
233	  }
234	
235	  async getContractsByStatus(status) {
236	    return this._contractRepo.getByStatus(status);
237	  }
238	}
239	
240	export default new ContractService();
241

1	/**
2	 * QuizService — question bank CRUD, bulk import, paper generation, auto-grading, wrong-question tracking.
3	 */
4	
5	import questionRepository from '../repositories/QuestionRepository.js';
6	import quizRepository from '../repositories/QuizRepository.js';
7	import quizResultRepository from '../repositories/QuizResultRepository.js';
8	import wrongQuestionRepository from '../repositories/WrongQuestionRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createQuestion, QUESTION_TYPES } from '../models/Question.js';
12	import { createQuiz, createQuizResult } from '../models/Quiz.js';
13	import { createWrongQuestion } from '../models/WrongQuestion.js';
14	import { USER_ROLES } from '../models/User.js';
15	import { generateId, now } from '../utils/helpers.js';
16	import { validateQuestionRow } from '../utils/validators.js';
17	
18	export class QuizService {
19	  constructor(deps = {}) {
20	    this._questionRepo = deps.questionRepository || questionRepository;
21	    this._quizRepo = deps.quizRepository || quizRepository;
22	    this._quizResultRepo = deps.quizResultRepository || quizResultRepository;
23	    this._wrongQRepo = deps.wrongQuestionRepository || wrongQuestionRepository;
24	    this._userRepo = deps.userRepository || userRepository;
25	    this._auditService = deps.auditService || defaultAuditService;
26	  }
27	
28	  /**
29	   * Validate that the acting user is an Instructor or Administrator (fail-closed).
30	   * Rejects if user is not found, null, or has wrong role.
31	   */
32	  async _requireInstructorOrAdmin(userId) {
33	    if (!userId) throw new Error('userId is required for this operation.');
34	    const user = await this._userRepo.getById(userId);
35	    if (!user) {
36	      throw new Error('Acting user not found. Cannot perform this operation.');
37	    }
38	    if (![USER_ROLES.ADMINISTRATOR, USER_ROLES.INSTRUCTOR].includes(user.role)) {
39	      throw new Error('Only instructors or administrators can manage questions.');
40	    }
41	  }
42	
43	  async createQuestion(data) {
44	    await this._requireInstructorOrAdmin(data.createdBy);
45	    if (!data.questionText || String(data.questionText).trim() === '') throw new Error('questionText is required.');
46	    const validTypes = Object.values(QUESTION_TYPES);
47	    if (!validTypes.includes(data.type)) throw new Error(`type must be one of: ${validTypes.join(', ')}`);
48	    if (data.type !== QUESTION_TYPES.SUBJECTIVE && (!data.correctAnswer || String(data.correctAnswer).toString().trim() === '')) {
49	      throw new Error('correctAnswer is required for non-subjective questions.');
50	    }
51	    const diff = Number(data.difficulty);
52	    if (!Number.isInteger(diff) || diff < 1 || diff > 5) throw new Error('difficulty must be an integer between 1 and 5.');
53	
54	    const question = createQuestion({ id: generateId(), ...data });
55	    await this._questionRepo.add(question);
56	    await this._auditService.log('question', question.id, 'created', `Question created: ${question.type}`, data.createdBy || 'system');
57	    return question;
58	  }
59	
60	  async updateQuestion(id, updates, userId) {
61	    await this._requireInstructorOrAdmin(userId);
62	    const question = await this._questionRepo.getById(id);
63	    if (!question) throw new Error('Question not found.');
64	    Object.assign(question, updates, { updatedAt: now() });
65	    await this._questionRepo.put(question);
66	    await this._auditService.log('question', id, 'updated', `Question updated`, userId || 'system');
67	    return question;
68	  }
69	
70	  async deleteQuestion(id, userId) {
71	    await this._requireInstructorOrAdmin(userId);
72	    await this._questionRepo.delete(id);
73	    await this._auditService.log('question', id, 'deleted', `Question deleted`, userId || 'system');
74	  }
75	  async getQuestionById(id) { return this._questionRepo.getById(id); }
76	  async getAllQuestions() { return this._questionRepo.getAll(); }
77	  async getQuestionsByType(type) { return this._questionRepo.getByType(type); }
78	  async getQuestionsByDifficulty(difficulty) { return this._questionRepo.getByDifficulty(difficulty); }
79	
80	  async bulkImport(rows, createdBy = 'system') {
81	    await this._requireInstructorOrAdmin(createdBy);
82	    if (!Array.isArray(rows) || rows.length === 0) {
83	      return { success: false, errors: ['Import data must be a non-empty array.'] };
84	    }
85	    const allErrors = [];
86	    for (let i = 0; i < rows.length; i++) {
87	      allErrors.push(...validateQuestionRow(rows[i], i + 1));
88	    }
89	    if (allErrors.length > 0) return { success: false, errors: allErrors };
90	
91	    const questions = rows.map(row => createQuestion({
92	      id: generateId(), questionText: row.questionText, type: row.type,
93	      options: row.options || [], correctAnswer: row.correctAnswer,
94	      difficulty: Number(row.difficulty), tags: row.tags,
95	      chapter: row.chapter || '', explanation: row.explanation || '',
96	    }));
97	
98	    await this._questionRepo.bulkAdd(questions);
99	    await this._auditService.log('question', 'bulk', 'bulk_import', `Imported ${questions.length} questions`, createdBy);
100	    return { success: true, count: questions.length };
101	  }
102	
103	  async generatePaper(title, classId, rules, createdBy) {
104	    await this._requireInstructorOrAdmin(createdBy);
105	    if (!title || String(title).trim() === '') throw new Error('Paper title is required.');
106	    if (!rules || !rules.totalQuestions) throw new Error('Paper rules with totalQuestions are required.');
107	    const allQuestions = await this._questionRepo.getAll();
108	    if (allQuestions.length === 0) throw new Error('No questions available in the bank.');
109	
110	    const selected = this._selectQuestions(allQuestions, rules);
111	    const quiz = createQuiz({ id: generateId(), title, classId, questionIds: selected.map(q => q.id), rules, createdBy });
112	    await this._quizRepo.add(quiz);
113	    await this._auditService.log('quiz', quiz.id, 'created', `Paper generated: ${title}`, createdBy);
114	    return quiz;
115	  }
116	
117	  _selectQuestions(allQuestions, rules) {
118	    const total = rules.totalQuestions || 30;
119	    const distribution = rules.difficultyDistribution || {};
120	    const chapterMin = rules.chapterConstraints || {};
121	    const difficultyCounts = {};
122	    let allocated = 0;
123	    const difficulties = Object.keys(distribution).map(Number).sort();
124	    for (const d of difficulties) { difficultyCounts[d] = Math.floor(total * distribution[d]); allocated += difficultyCounts[d]; }
125	    if (allocated < total && difficulties.length > 0) difficultyCounts[difficulties[difficulties.length - 1]] += total - allocated;
126	    const byDifficulty = {};
127	    for (const q of allQuestions) { if (!byDifficulty[q.difficulty]) byDifficulty[q.difficulty] = []; byDifficulty[q.difficulty].push(q); }
128	    for (const d of Object.keys(byDifficulty)) byDifficulty[d] = this._shuffle(byDifficulty[d]);
129	    const selected = [];
130	    const usedIds = new Set();
131	    for (const [chapter, minCount] of Object.entries(chapterMin)) {
132	      const chapterQs = allQuestions.filter(q => q.chapter === chapter && !usedIds.has(q.id));
133	      for (let i = 0; i < Math.min(minCount, chapterQs.length); i++) { selected.push(chapterQs[i]); usedIds.add(chapterQs[i].id); }
134	    }
135	    for (const [d, count] of Object.entries(difficultyCounts)) {
136	      const pool = (byDifficulty[d] || []).filter(q => !usedIds.has(q.id));
137	      const needed = count - selected.filter(q => q.difficulty === Number(d)).length;
138	      for (let i = 0; i < Math.min(needed, pool.length); i++) { selected.push(pool[i]); usedIds.add(pool[i].id); }
139	    }
140	    return selected.slice(0, total);
141	  }
142	
143	  _shuffle(arr) { const a = [...arr]; for (let i = a.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [a[i], a[j]] = [a[j], a[i]]; } return a; }
144	
145	  async submitAnswers(quizId, userId, answers) {
146	    if (!quizId) throw new Error('quizId is required.');
147	    if (!userId) throw new Error('userId is required.');
148	    if (!Array.isArray(answers)) throw new Error('answers must be an array.');
149	    const quiz = await this._quizRepo.getById(quizId);
150	    if (!quiz) throw new Error('Quiz not found.');
151	    if (!quiz.questionIds || quiz.questionIds.length === 0) throw new Error('Quiz has no questions.');
152	
153	    const gradedAnswers = [];
154	    let objectiveCorrect = 0, objectiveTotal = 0;
155	    for (const ans of answers) {
156	      const question = await this._questionRepo.getById(ans.questionId);
157	      if (!question) continue;
158	      const graded = { questionId: ans.questionId, answer: ans.answer, autoGraded: false, isCorrect: null };
159	      if (question.type === QUESTION_TYPES.SUBJECTIVE) {
160	        graded.autoGraded = false;
161	      } else {
162	        graded.autoGraded = true;
163	        objectiveTotal++;
164	        if (question.type === QUESTION_TYPES.MULTIPLE) {
165	          const correct = Array.isArray(question.correctAnswer) ? question.correctAnswer.sort() : [];
166	          const given = Array.isArray(ans.answer) ? ans.answer.sort() : [];
167	          graded.isCorrect = JSON.stringify(correct) === JSON.stringify(given);
168	        } else {
169	          graded.isCorrect = String(ans.answer).trim().toLowerCase() === String(question.correctAnswer).trim().toLowerCase();
170	        }
171	        if (graded.isCorrect) objectiveCorrect++;
172	        if (!graded.isCorrect) await this._addWrongQuestion(userId, question, ans.answer, quizId);
173	      }
174	      gradedAnswers.push(graded);
175	    }
176	
177	    const result = createQuizResult({ id: generateId(), quizId, userId, answers: gradedAnswers, objectiveScore: objectiveTotal > 0 ? Math.round((objectiveCorrect / objectiveTotal) * 100) : null });
178	    await this._quizResultRepo.add(result);
179	    return result;
180	  }
181	
182	  async getResultsByUserId(userId) { return this._quizResultRepo.getByUserId(userId); }
183	  async getResultsByQuizId(quizId) { return this._quizResultRepo.getByQuizId(quizId); }
184	  async getAllQuizzes() { return this._quizRepo.getAll(); }
185	  async getQuizById(quizId) { return this._quizRepo.getById(quizId); }
186	  async getAllQuizResults() { return this._quizResultRepo.getAll(); }
187	  async getWrongQuestions(userId) { return this._wrongQRepo.getByUserId(userId); }
188	
189	  async _addWrongQuestion(userId, question, userAnswer, quizId) {
190	    const entry = createWrongQuestion({ id: generateId(), userId, questionId: question.id, userAnswer: JSON.stringify(userAnswer), correctAnswer: JSON.stringify(question.correctAnswer), explanation: question.explanation, quizId });
191	    await this._wrongQRepo.add(entry);
192	  }
193	}
194	
195	export default new QuizService();
