1	/**
2	 * ReputationService — score calculation, threshold enforcement, rating aggregation.
3	 */
4	
5	import reputationScoreRepository from '../repositories/ReputationScoreRepository.js';
6	import auditService from './AuditService.js';
7	import { createReputationScore, REPUTATION_THRESHOLD } from '../models/ReputationScore.js';
8	import { generateId, now } from '../utils/helpers.js';
9	import { getConfig } from '../config/appConfig.js';
10	
11	// Default weights — overridden by appConfig when available
12	const DEFAULT_WEIGHTS = {
13	  fulfillmentRate: 0.5,
14	  lateRate: 0.3,
15	  complaintRate: 0.2,
16	};
17	
18	export class ReputationService {
19	  /**
20	   * Compute and store reputation score for a user.
21	   * @param {string} userId
22	   * @param {object} metrics — { fulfillmentRate: 0–1, lateRate: 0–1, complaintRate: 0–1 }
23	   * @param {object} [weights] — optional custom weights
24	   */
25	  async computeScore(userId, metrics, weights) {
26	    // Load weights from config if not explicitly provided
27	    if (!weights) {
28	      const config = getConfig();
29	      weights = (config.reputation && config.reputation.weights) || DEFAULT_WEIGHTS;
30	    }
31	    if (!userId) throw new Error('userId is required.');
32	    if (!metrics) throw new Error('metrics object is required.');
33	
34	    const validate01 = (v, name) => {
35	      const n = Number(v);
36	      if (isNaN(n) || n < 0 || n > 1) throw new Error(`${name} must be between 0 and 1.`);
37	      return n;
38	    };
39	    metrics.fulfillmentRate = validate01(metrics.fulfillmentRate, 'fulfillmentRate');
40	    metrics.lateRate = validate01(metrics.lateRate, 'lateRate');
41	    metrics.complaintRate = validate01(metrics.complaintRate, 'complaintRate');
42	
43	    const score = Math.round(
44	      (metrics.fulfillmentRate * weights.fulfillmentRate +
45	        (1 - metrics.lateRate) * weights.lateRate +
46	        (1 - metrics.complaintRate) * weights.complaintRate) * 100
47	    );
48	
49	    const clampedScore = Math.max(0, Math.min(100, score));
50	
51	    const existing = await reputationScoreRepository.getByUserId(userId);
52	
53	    const record = createReputationScore({
54	      id: existing ? existing.id : generateId(),
55	      userId,
56	      score: clampedScore,
57	      fulfillmentRate: metrics.fulfillmentRate,
58	      lateRate: metrics.lateRate,
59	      complaintRate: metrics.complaintRate,
60	    });
61	
62	    await reputationScoreRepository.put(record);
63	    await auditService.log('reputation', userId, 'computed', `Score: ${clampedScore}`, 'system');
64	
65	    return record;
66	  }
67	
68	  /**
69	   * Get the current reputation score for a user.
70	   */
71	  async getScore(userId) {
72	    return reputationScoreRepository.getByUserId(userId);
73	  }
74	
75	  /**
76	   * Check if user is below threshold and should be restricted.
77	   */
78	  async isRestricted(userId) {
79	    const record = await this.getScore(userId);
80	    if (!record) return false; // no score computed yet, not restricted
81	    const config = getConfig();
82	    const threshold = (config.reputation && config.reputation.threshold) || REPUTATION_THRESHOLD;
83	    return record.score < threshold;
84	  }
85	
86	  /**
87	   * Get all reputation scores.
88	   */
89	  async getAllScores() {
90	    return reputationScoreRepository.getAll();
91	  }
92	}
93	
94	export default new ReputationService();
