1	/**
2	 * app.js — Application entry point.
3	 * Initializes database, seeds data, sets up routing, and boots the app shell.
4	 */
5	
6	import { openDatabase } from './store/Database.js';
7	import { Router } from './router/Router.js';
8	import { AppShell } from './components/AppShell.js';
9	import authService from './services/AuthService.js';
10	import moderationService from './services/ModerationService.js';
11	import schedulerService from './services/SchedulerService.js';
12	import classRepository from './repositories/ClassRepository.js';
13	import { createClass } from './models/Class.js';
14	import { generateId } from './utils/helpers.js';
15	import { loadAppConfig } from './config/appConfig.js';
16	import { USER_ROLES } from './models/User.js';
17	
18	import { LoginPage } from './pages/LoginPage.js';
19	import { DashboardPage } from './pages/DashboardPage.js';
20	import { RegistrationsPage } from './pages/RegistrationsPage.js';
21	import { QuizPage } from './pages/QuizPage.js';
22	import { ReviewsPage } from './pages/ReviewsPage.js';
23	import { ContractsPage } from './pages/ContractsPage.js';
24	import { AdminPage } from './pages/AdminPage.js';
25	
26	const appEl = document.getElementById('app');
27	
28	// Route-level RBAC configuration
29	const ROUTE_ROLES = {
30	  '/admin': [USER_ROLES.ADMINISTRATOR],
31	};
32	
33	async function boot() {
34	  try {
35	    // 1. Open IndexedDB
36	    await openDatabase();
37	
38	    // 2. Seed default users if empty
39	    await authService.seedDefaultUsers();
40	
41	    // 2b. Seed default classes if empty
42	    const classCount = await classRepository.count();
43	    if (classCount === 0) {
44	      const defaultClasses = [
45	        { title: 'Introduction to Web Development', description: 'Learn HTML, CSS, and JavaScript basics.', capacity: 30, startDate: '2026-04-15', endDate: '2026-06-15' },
46	        { title: 'Advanced JavaScript', description: 'Deep dive into ES modules, async patterns, and frameworks.', capacity: 25, startDate: '2026-05-01', endDate: '2026-07-01' },
47	        { title: 'Database Fundamentals', description: 'SQL, NoSQL, and data modeling.', capacity: 20, startDate: '2026-04-20', endDate: '2026-06-20' },
48	      ];
49	      for (const c of defaultClasses) {
50	        await classRepository.add(createClass({ id: generateId(), ...c }));
51	      }
52	    }
53	
54	    // 3. Load config
55	    await loadAppConfig();
56	    await moderationService.loadSensitiveWords();
57	
58	    // 4. Check existing session
59	    await authService.init();
60	
61	    // 5. Setup router
62	    const router = new Router();
63	    const appShell = new AppShell(router);
64	
65	    // Page factory — creates fresh instances per session to ensure state isolation
66	    let pages = createPages(router, appShell);
67	
68	    function createPages(router, appShell) {
69	      return {
70	        loginPage: new LoginPage(router),
71	        dashboardPage: new DashboardPage(appShell),
72	        registrationsPage: new RegistrationsPage(appShell),
73	        quizPage: new QuizPage(appShell),
74	        reviewsPage: new ReviewsPage(appShell),
75	        contractsPage: new ContractsPage(appShell),
76	        adminPage: new AdminPage(appShell),
77	      };
78	    }
79	
80	    // Reset all page instances on login/logout for state isolation
81	    authService.onSessionChange = () => {
82	      pages = createPages(router, appShell);
83	    };
84	
85	    // Helper: ensure shell is rendered, then call page render
86	    const renderPage = async (page) => {
87	      if (!document.querySelector('.app-shell')) {
88	        appShell.render(appEl);
89	      }
90	      await page.render();
91	    };
92	
93	    // Route guard: authentication + RBAC
94	    router.beforeEach((to) => {
95	      if (to.path !== '/login' && !authService.isAuthenticated()) {
96	        router.navigate('/login');
97	        return false;
98	      }
99	      if (to.path === '/login' && authService.isAuthenticated()) {
100	        router.navigate('/dashboard');
101	        return false;
102	      }
103	
104	      // RBAC: check route-level role restrictions
105	      if (authService.isAuthenticated() && ROUTE_ROLES[to.path]) {
106	        const allowedRoles = ROUTE_ROLES[to.path];
107	        if (!authService.hasRole(...allowedRoles)) {
108	          router.navigate('/dashboard');
109	          return false;
110	        }
111	      }
112	
113	      return true;
114	    });
115	
116	    // Register routes
117	    router.route('/login', async () => {
118	      appEl.innerHTML = '';
119	      await pages.loginPage.render(appEl);
120	    });
121	
122	    router.route('/dashboard', () => renderPage(pages.dashboardPage));
123	    router.route('/registrations', () => renderPage(pages.registrationsPage));
124	    router.route('/quiz', () => renderPage(pages.quizPage));
125	    router.route('/reviews', () => renderPage(pages.reviewsPage));
126	    router.route('/contracts', () => renderPage(pages.contractsPage));
127	    router.route('/admin', () => renderPage(pages.adminPage));
128	
129	    router.notFound(() => {
130	      if (authService.isAuthenticated()) {
131	        router.navigate('/dashboard');
132	      } else {
133	        router.navigate('/login');
134	      }
135	    });
136	
137	    // Highlight active nav link on navigation
138	    router.onNavigate(({ path }) => {
139	      document.querySelectorAll('.sidebar-nav a').forEach(a => {
140	        const href = a.getAttribute('href')?.replace('#', '');
141	        a.classList.toggle('active', href === path);
142	      });
143	    });
144	
145	    // 6. Start scheduler
146	    schedulerService.start();
147	
148	    // 7. Start router
149	    router.start();
150	  } catch (err) {
151	    console.error('Boot failed:', err);
152	    appEl.innerHTML = `<div class="loading-screen" style="color:var(--color-danger)">
153	      <div>
154	        <p>Failed to start application.</p>
155	        <p style="font-size:0.85rem;margin-top:8px">${err.message}</p>
156	      </div>
157	    </div>`;
158	  }
159	}
160	
161	boot();
