6	// ============================================================
7	// InMemoryStore — drop-in replacement for any repository
8	// ============================================================
9	
10	export class InMemoryStore {
11	  constructor() {
12	    this._data = new Map();
13	  }
14	
15	  async getById(id) {
16	    const v = this._data.get(id);
17	    return v ? JSON.parse(JSON.stringify(v)) : null;
18	  }
19	
20	  async getAll() {
21	    return [...this._data.values()].map(v => JSON.parse(JSON.stringify(v)));
22	  }
23	
24	  async getByIndex(indexName, value) {
25	    return [...this._data.values()].filter(r => r[indexName] === value).map(v => JSON.parse(JSON.stringify(v)));
26	  }
27	
28	  async add(record) {
29	    const key = record.id || record.key;
30	    if (this._data.has(key)) throw new Error(`Duplicate key: ${key}`);
31	    this._data.set(key, JSON.parse(JSON.stringify(record)));
32	    return key;
33	  }
34	
35	  async put(record) {
36	    const key = record.id || record.key;
37	    this._data.set(key, JSON.parse(JSON.stringify(record)));
38	    return key;
39	  }
40	
41	  async delete(id) { this._data.delete(id); }
42	  async clear() { this._data.clear(); }
43	  async count() { return this._data.size; }
44	
45	  async filter(predicate) {
46	    return [...this._data.values()].filter(predicate).map(v => JSON.parse(JSON.stringify(v)));
47	  }
48	
49	  async bulkAdd(records) { for (const r of records) await this.add(r); }
50	  async bulkPut(records) { for (const r of records) await this.put(r); }
51	
52	  // Additional index-like methods used by specific repos
53	  async getByEntityId(entityId) { return this.getByIndex('entityId', entityId); }
54	  async getByEntityType(entityType) { return this.getByIndex('entityType', entityType); }
55	  async getByRegistrationId(registrationId) {
56	    const results = await this.getByIndex('registrationId', registrationId);
57	    return results.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));
58	  }
59	  async getByUserId(userId) { return this.getByIndex('userId', userId); }
60	  async getByUsername(username) { const r = await this.getByIndex('username', username); return r[0] || null; }
