68	  async getByDirection(direction) { return this.getByIndex('direction', direction); }
69	  async getByTargetId(targetId) { return this.getByIndex('targetId', targetId); }
70	  async getByTemplateId(templateId) { return this.getByIndex('templateId', templateId); }
71	  async getByRatingId(ratingId) { return this.getByIndex('ratingId', ratingId); }
72	  async getByFromUserId(fromUserId) { return this.getByIndex('fromUserId', fromUserId); }
73	  async getByToUserId(toUserId) { return this.getByIndex('toUserId', toUserId); }
74	  async getByThreadId(threadId) {
75	    const results = await this.getByIndex('threadId', threadId);
76	    return results.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
