87	let _passCount = 0;
88	let _failCount = 0;
89	let _currentSuite = '';
90	const _failures = [];
91	
92	export async function describe(name, fn) {
93	  _currentSuite = name;
94	  console.log(`\n  ${name}`);
95	  await fn();
96	}
97	
98	export async function it(name, fn) {
99	  try {
100	    await fn();
101	    _passCount++;
102	    console.log(`    ✓ ${name}`);
103	  } catch (err) {
104	    _failCount++;
105	    _failures.push({ suite: _currentSuite, test: name, error: err.message });
106	    console.log(`    ✗ ${name}`);
107	    console.log(`      Error: ${err.message}`);
108	  }
109	}
110	
111	export function assert(condition, message = 'Assertion failed') {
112	  if (!condition) throw new Error(message);
113	}
114	
115	export function assertEqual(actual, expected, message) {
116	  if (actual !== expected) throw new Error(message || `Expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
117	}
118	
119	export async function assertThrowsAsync(fn, expectedMessage) {
120	  let threw = false, error = null;
121	  try { await fn(); } catch (e) { threw = true; error = e; }
122	  if (!threw) throw new Error(`Expected function to throw${expectedMessage ? ` "${expectedMessage}"` : ''}`);
123	  if (expectedMessage && !error.message.includes(expectedMessage)) {
124	    throw new Error(`Expected error containing "${expectedMessage}", got "${error.message}"`);
125	  }
126	}
127	
128	export function printSummary() {
129	  console.log(`\n${'='.repeat(50)}`);
130	  console.log(`  ${_passCount} passing, ${_failCount} failing`);
131	  if (_failures.length > 0) {
132	    console.log('\n  Failures:');
133	    _failures.forEach((f, i) => console.log(`    ${i + 1}) ${f.suite} > ${f.test}\n       ${f.error}`));
134	  }
135	  console.log(`${'='.repeat(50)}\n`);
136	  return { passed: _passCount, failed: _failCount, failures: _failures };
137	}
