1	/**
2	 * ReputationService — score calculation, threshold enforcement, rating aggregation.
3	 */
4	
5	import reputationScoreRepository from '../repositories/ReputationScoreRepository.js';
6	import auditService from './AuditService.js';
7	import { createReputationScore, REPUTATION_THRESHOLD } from '../models/ReputationScore.js';
8	import { generateId, now } from '../utils/helpers.js';
9	import { getConfig } from '../config/appConfig.js';
10	
11	// Default weights — overridden by appConfig when available
12	const DEFAULT_WEIGHTS = {
13	  fulfillmentRate: 0.5,
14	  lateRate: 0.3,
15	  complaintRate: 0.2,
16	};
17	
18	export class ReputationService {
19	  constructor(deps = {}) {
20	    this._reputationScoreRepo = deps.reputationScoreRepository || reputationScoreRepository;
21	    this._auditService = deps.auditService || auditService;
22	  }
23	
24	  /**
25	   * Compute and store reputation score for a user.
26	   * @param {string} userId
27	   * @param {object} metrics — { fulfillmentRate: 0–1, lateRate: 0–1, complaintRate: 0–1 }
28	   * @param {object} [weights] — optional custom weights
29	   */
30	  async computeScore(userId, metrics, weights) {
31	    // Load weights from config if not explicitly provided
32	    if (!weights) {
33	      const config = getConfig();
34	      weights = (config.reputation && config.reputation.weights) || DEFAULT_WEIGHTS;
35	    }
36	    if (!userId) throw new Error('userId is required.');
37	    if (!metrics) throw new Error('metrics object is required.');
38	
39	    const validate01 = (v, name) => {
40	      const n = Number(v);
41	      if (isNaN(n) || n < 0 || n > 1) throw new Error(`${name} must be between 0 and 1.`);
42	      return n;
43	    };
44	    metrics.fulfillmentRate = validate01(metrics.fulfillmentRate, 'fulfillmentRate');
45	    metrics.lateRate = validate01(metrics.lateRate, 'lateRate');
46	    metrics.complaintRate = validate01(metrics.complaintRate, 'complaintRate');
47	
48	    const score = Math.round(
49	      (metrics.fulfillmentRate * weights.fulfillmentRate +
50	        (1 - metrics.lateRate) * weights.lateRate +
51	        (1 - metrics.complaintRate) * weights.complaintRate) * 100
52	    );
53	
54	    const clampedScore = Math.max(0, Math.min(100, score));
55	
56	    const existing = await this._reputationScoreRepo.getByUserId(userId);
57	
58	    const record = createReputationScore({
59	      id: existing ? existing.id : generateId(),
60	      userId,
61	      score: clampedScore,
62	      fulfillmentRate: metrics.fulfillmentRate,
63	      lateRate: metrics.lateRate,
64	      complaintRate: metrics.complaintRate,
65	    });
66	
67	    await this._reputationScoreRepo.put(record);
68	    await this._auditService.log('reputation', userId, 'computed', `Score: ${clampedScore}`, 'system');
69	
70	    return record;
71	  }
72	
73	  /**
74	   * Get the current reputation score for a user.
75	   */
76	  async getScore(userId) {
77	    return this._reputationScoreRepo.getByUserId(userId);
78	  }
79	
80	  /**
81	   * Check if user is below threshold and should be restricted.
82	   */
83	  async isRestricted(userId) {
84	    const record = await this.getScore(userId);
85	    if (!record) return false; // no score computed yet, not restricted
86	    const config = getConfig();
87	    const threshold = (config.reputation && config.reputation.threshold) || REPUTATION_THRESHOLD;
88	    return record.score < threshold;
89	  }
90	
91	  /**
92	   * Get all reputation scores.
93	   */
94	  async getAllScores() {
95	    return this._reputationScoreRepo.getAll();
96	  }
97	}
98	
99	export default new ReputationService();
100

