    return this._reputationScoreRepo.getByUserId(userId);
  }", "new_string": "  async getScore(userId) {
    const results = await this._reputationScoreRepo.getByUserId(userId);
    if (Array.isArray(results)) return results[0] || null;
    return results;
  }"}

