1	/**
2	 * RegistrationService — registration CRUD, state machine, waitlist, audit logging.
3	 * All business rules enforced at service level.
4	 */
5	
6	import registrationRepository from '../repositories/RegistrationRepository.js';
7	import registrationEventRepository from '../repositories/RegistrationEventRepository.js';
8	import classRepository from '../repositories/ClassRepository.js';
9	import userRepository from '../repositories/UserRepository.js';
10	import defaultAuditService from './AuditService.js';
11	import { createRegistration, createRegistrationEvent, REGISTRATION_STATUS, REGISTRATION_TRANSITIONS, canTransition, TERMINAL_STATES } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	import eventBus from '../utils/EventBus.js';
15	import { getConfig } from '../config/appConfig.js';
16	import defaultReputationService from './ReputationService.js';
17	
18	// Transitions only reviewers/admins may perform
19	const REVIEWER_ONLY_TRANSITIONS = [
20	  REGISTRATION_STATUS.UNDER_REVIEW,
21	  REGISTRATION_STATUS.APPROVED,
22	  REGISTRATION_STATUS.REJECTED,
23	  REGISTRATION_STATUS.NEEDS_MORE_INFO,
24	  REGISTRATION_STATUS.WAITLISTED,
25	];
26	
27	export class RegistrationService {
28	  constructor(deps = {}) {
29	    this._registrationRepo = deps.registrationRepository || registrationRepository;
30	    this._eventRepo = deps.registrationEventRepository || registrationEventRepository;
31	    this._classRepo = deps.classRepository || classRepository;
32	    this._userRepo = deps.userRepository || userRepository;
33	    this._auditService = deps.auditService || defaultAuditService;
34	    this._reputationService = deps.reputationService || defaultReputationService;
35	  }
36	
37	  async create(userId, classId, notes = '') {
38	    if (!userId) throw new Error('userId is required to create a registration.');
39	
40	    // Reputation enforcement at service level
41	    const restricted = await this._reputationService.isRestricted(userId);
42	    if (restricted) {
43	      throw new Error('Your reputation score is below the threshold. You cannot create new registrations.');
44	    }
45	
46	    const registration = createRegistration({
47	      id: generateId(),
48	      userId,
49	      classId,
50	      status: REGISTRATION_STATUS.DRAFT,
51	      notes,
52	    });
53	    await this._registrationRepo.add(registration);
54	    await this._logEvent(registration.id, null, REGISTRATION_STATUS.DRAFT, 'Registration created', userId);
55	    await this._auditService.log('registration', registration.id, 'created', 'Registration created in Draft', userId);
56	    eventBus.emit('registration:created', registration);
57	    return registration;
58	  }
59	
60	  async transition(registrationId, newStatus, comment, userId) {
61	    if (!registrationId) throw new Error('registrationId is required.');
62	    if (!newStatus) throw new Error('newStatus is required.');
63	    if (!userId) throw new Error('userId is required for transition.');
64	
65	    const reg = await this._registrationRepo.getById(registrationId);
66	    if (!reg) throw new Error('Registration not found.');
67	
68	    if (!canTransition(reg.status, newStatus)) {
69	      throw new Error(`Cannot transition from ${reg.status} to ${newStatus}.`);
70	    }
71	
72	    const actingUser = await this._userRepo.getById(userId);
73	    if (!actingUser) {
74	      throw new Error('Acting user not found. Cannot perform transition.');
75	    }
76	
77	    const isReviewerOrAdmin = [USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role);
78	    const isOwner = reg.userId === userId;
79	
80	    if (REVIEWER_ONLY_TRANSITIONS.includes(newStatus) && !isReviewerOrAdmin) {
81	      throw new Error(`Only administrators or staff reviewers can transition to ${newStatus}.`);
82	    }
83	
84	    if (!isReviewerOrAdmin) {
85	      if (!isOwner) {
86	        throw new Error('You can only modify your own registrations.');
87	      }
88	      const selfAllowed = [REGISTRATION_STATUS.SUBMITTED, REGISTRATION_STATUS.CANCELLED];
89	      if (!selfAllowed.includes(newStatus)) {
90	        throw new Error(`You do not have permission to transition to ${newStatus}.`);
91	      }
92	    }
93	
94	    if (newStatus === REGISTRATION_STATUS.REJECTED) {
95	      if (!comment || comment.trim().length < 20) {
96	        throw new Error('Rejection comment must be at least 20 characters.');
97	      }
98	    }
99	
100	    const fromStatus = reg.status;
101	    reg.status = newStatus;
102	    reg.updatedAt = now();
103	    await this._registrationRepo.put(reg);
104	
105	    await this._logEvent(reg.id, fromStatus, newStatus, comment || '', userId);
106	    await this._auditService.log('registration', reg.id, 'status_change', `${fromStatus} → ${newStatus}${comment ? ': ' + comment : ''}`, userId);
107	
108	    eventBus.emit('registration:transition', { registration: reg, fromStatus, toStatus: newStatus });
109	
110	    if (fromStatus === REGISTRATION_STATUS.APPROVED && newStatus === REGISTRATION_STATUS.CANCELLED) {
111	      await this._checkWaitlistPromotion(reg.classId, userId);
112	    }
113	
114	    return reg;
115	  }
116	
117	  async batchTransition(registrationIds, newStatus, comment, userId) {
118	    const results = [];
119	    for (const id of registrationIds) {
120	      try {
121	        const reg = await this.transition(id, newStatus, comment, userId);
122	        results.push({ id, success: true, registration: reg });
123	      } catch (err) {
124	        results.push({ id, success: false, error: err.message });
125	      }
126	    }
127	    return results;
128	  }
129	
130	  async getById(registrationId) {
131	    return this._registrationRepo.getById(registrationId);
132	  }
133	
134	  async getAll() {
135	    return this._registrationRepo.getAll();
136	  }
137	
138	  /**
139	   * Get registrations scoped by the acting user's role.
140	   * Learner: own records only. Reviewer/Admin: all records.
141	   */
142	  async getAllScoped(actingUserId) {
143	    if (!actingUserId) return [];
144	    const user = await this._userRepo.getById(actingUserId);
145	    if (!user) return [];
146	    if ([USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(user.role)) {
147	      return this._registrationRepo.getAll();
148	    }
149	    return this._registrationRepo.getByUserId(actingUserId);
150	  }
151	
152	  async getByUserId(userId) {
153	    return this._registrationRepo.getByUserId(userId);
154	  }
155	
156	  async getByStatus(status) {
157	    return this._registrationRepo.getByStatus(status);
158	  }
159	
160	  async getByClassId(classId) {
161	    return this._registrationRepo.getByClassId(classId);
162	  }
163	
164	  async getEvents(registrationId) {
165	    return this._eventRepo.getByRegistrationId(registrationId);
166	  }
167	
168	  async getClassFillRate(classId) {
169	    if (!classId) return 0;
170	    const cls = await this._classRepo.getById(classId);
171	    if (!cls || !cls.capacity) return 0;
172	
173	    const regs = await this._registrationRepo.getByClassId(classId);
174	    const approvedCount = regs.filter(r => r.status === REGISTRATION_STATUS.APPROVED).length;
175	    return approvedCount / cls.capacity;
176	  }
177	
178	  async _checkWaitlistPromotion(classId, userId) {
179	    if (!classId) return;
180	
181	    const fillRate = await this.getClassFillRate(classId);
182	    const config = getConfig();
183	    const threshold = (config.registration && config.registration.waitlistPromotionFillRate) || 0.95;
184	    if (fillRate >= threshold) return;
185	
186	    const waitlisted = await this._registrationRepo.filter(
187	      r => r.classId === classId && r.status === REGISTRATION_STATUS.WAITLISTED
188	    );
189	    if (waitlisted.length === 0) return;
190	
191	    waitlisted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
192	
193	    const next = waitlisted[0];
194	    const fromStatus = next.status;
195	    next.status = REGISTRATION_STATUS.UNDER_REVIEW;
196	    next.updatedAt = now();
197	    await this._registrationRepo.put(next);
198	
199	    await this._logEvent(next.id, fromStatus, REGISTRATION_STATUS.UNDER_REVIEW, 'Auto-promoted from waitlist (seat available, fill rate < 95%)', userId);
200	    await this._auditService.log('registration', next.id, 'status_change', `${fromStatus} → ${REGISTRATION_STATUS.UNDER_REVIEW}: Waitlist promotion`, userId);
201	
202	    eventBus.emit('registration:transition', { registration: next, fromStatus, toStatus: REGISTRATION_STATUS.UNDER_REVIEW });
203	  }
204	
205	  async _logEvent(registrationId, fromStatus, toStatus, comment, userId) {
206	    const event = createRegistrationEvent({
207	      id: generateId(),
208	      registrationId,
209	      fromStatus,
210	      toStatus,
211	      comment,
212	      userId,
213	      timestamp: now(),
214	    });
215	    await this._eventRepo.add(event);
216	    return event;
217	  }
218	}
219	
220	export default new RegistrationService();
