2	 * ContractService — template management, placeholder substitution, versioning,
3	 * signature handling, signing workflow states, PDF-like print export.
4	 */
5	
6	import contractRepository from '../repositories/ContractRepository.js';
7	import templateRepository from '../repositories/TemplateRepository.js';
8	import userRepository from '../repositories/UserRepository.js';
9	import defaultAuditService from './AuditService.js';
10	import defaultCryptoService from './CryptoService.js';
11	import { createContract, createTemplate, CONTRACT_STATUS, CONTRACT_TRANSITIONS } from '../models/Contract.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now, downloadBlob } from '../utils/helpers.js';
14	
15	export class ContractService {
16	  constructor(deps = {}) {
17	    this._contractRepo = deps.contractRepository || contractRepository;
18	    this._templateRepo = deps.templateRepository || templateRepository;
19	    this._userRepo = deps.userRepository || userRepository;
20	    this._auditService = deps.auditService || defaultAuditService;
21	    this._cryptoService = deps.cryptoService || defaultCryptoService;
22	  }
23	
24	  async _requireAdmin(userId) {
25	    if (!userId) throw new Error('userId is required for this operation.');
26	    const user = await this._userRepo.getById(userId);
27	    if (!user) {
28	      throw new Error('Acting user not found. Cannot perform this operation.');
29	    }
30	    if (user.role !== USER_ROLES.ADMINISTRATOR) {
31	      throw new Error('Only administrators can manage templates.');
32	    }
33	  }
34	
35	  async createTemplate(data) {
36	    if (data.createdBy) await this._requireAdmin(data.createdBy);
37	    // Extract placeholders from content
38	    const placeholders = (data.content.match(/\{[^}]+\}/g) || []);
39	
40	    const template = createTemplate({
41	      id: generateId(),
42	      name: data.name,
43	      content: data.content,
44	      placeholders,
45	      active: true,
46	      version: 1,
47	      effectiveDate: data.effectiveDate || now(),
48	    });
49	
50	    await this._templateRepo.add(template);
51	    await this._auditService.log('template', template.id, 'created', `Template "${data.name}" v1 created`, data.createdBy || 'system');
52	    return template;
53	  }
54	
55	  async updateTemplate(templateId, updates, updatedBy) {
56	    if (updatedBy) await this._requireAdmin(updatedBy);
57	    const existing = await this._templateRepo.getById(templateId);
58	    if (!existing) throw new Error('Template not found.');
59	
60	    // Deactivate old version
61	    existing.active = false;
62	    existing.updatedAt = now();
63	    await this._templateRepo.put(existing);
64	
65	    // Create new version
66	    const newVersion = createTemplate({
67	      id: generateId(),
68	      name: updates.name || existing.name,
69	      content: updates.content || existing.content,
70	      placeholders: (updates.content || existing.content).match(/\{[^}]+\}/g) || [],
71	      active: true,
72	      version: existing.version + 1,
73	      effectiveDate: updates.effectiveDate || now(),
74	    });
75	
76	    await this._templateRepo.add(newVersion);
77	    await this._auditService.log('template', newVersion.id, 'versioned', `Template "${newVersion.name}" v${newVersion.version}`, updatedBy);
78	    return newVersion;
79	  }
80	
81	  async getActiveTemplates() {
82	    return this._templateRepo.getActive();
83	  }
84	
85	  async getTemplateById(templateId) {
86	    return this._templateRepo.getById(templateId);
87	  }
88	
89	  async getAllTemplates() {
90	    return this._templateRepo.getAll();
91	  }
92	
93	  // --- Contract Generation ---
94	
95	  /**
96	   * Generate a contract from a template with variable substitution.
97	   */
98	  async generateContract(templateId, variables, createdBy) {
99	    const template = await this._templateRepo.getById(templateId);
100	    if (!template) throw new Error('Template not found.');
101	
102	    let content = template.content;
103	    for (const [key, value] of Object.entries(variables)) {
104	      content = content.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
105	    }
106	
107	    const contract = createContract({
108	      id: generateId(),
109	      templateId,
110	      templateVersion: template.version,
111	      content,
112	      status: CONTRACT_STATUS.INITIATED,
113	      createdBy,
114	    });
115	
116	    await this._contractRepo.add(contract);
117	    await this._auditService.log('contract', contract.id, 'created', 'Contract generated from template', createdBy);
118	    return contract;
119	  }
120	
121	  // --- Signing Workflow ---
122	
123	  /**
124	   * Verify the acting user has access to the contract (owner or admin).
125	   */
126	  async _requireContractAccess(contract, userId) {
127	    if (!userId) throw new Error('userId is required for contract operations.');
128	    const user = await this._userRepo.getById(userId);
129	    if (!user) throw new Error('Acting user not found. Cannot perform contract operation.');
130	    if (user.role === USER_ROLES.ADMINISTRATOR) return user;
131	    if (contract.createdBy !== userId && contract.signedBy !== userId) {
132	      throw new Error('You do not have access to this contract.');
133	    }
134	    return user;
135	  }
136	
137	  /**
138	   * Transition a contract's signing status.
139	   */
140	  async transitionStatus(contractId, newStatus, userId) {
141	    const contract = await this._contractRepo.getById(contractId);
142	    if (!contract) throw new Error('Contract not found.');
143	
144	    await this._requireContractAccess(contract, userId);
145	
146	    const allowed = CONTRACT_TRANSITIONS[contract.status] || [];
147	    if (!allowed.includes(newStatus)) {
148	      throw new Error(`Cannot transition contract from ${contract.status} to ${newStatus}.`);
149	    }
150	
151	    const fromStatus = contract.status;
152	    contract.status = newStatus;
153	    contract.updatedAt = now();
154	    await this._contractRepo.put(contract);
155	
156	    await this._auditService.log('contract', contractId, 'status_change', `${fromStatus} → ${newStatus}`, userId);
157	    return contract;
158	  }
159	
160	  /**
161	   * Sign a contract — attach typed name or canvas signature + SHA-256 hash.
162	   */
163	  async signContract(contractId, signatureData, signerName, userId) {
164	    const contract = await this._contractRepo.getById(contractId);
165	    if (!contract) throw new Error('Contract not found.');
166	
167	    await this._requireContractAccess(contract, userId);
168	
169	    if (contract.status !== CONTRACT_STATUS.INITIATED) {
170	      throw new Error('Contract can only be signed when in initiated status.');
171	    }
172	
173	    if (!signatureData || String(signatureData).trim() === '') {
174	      throw new Error('Signature is required before signing.');
175	    }
176	
177	    if (!signerName || String(signerName).trim() === '') {
178	      throw new Error('Signer name is required.');
179	    }
180	
181	    const timestamp = now();
182	    const hash = await this._cryptoService.generateSignatureHash(contract.content, signerName, timestamp);
183	
184	    contract.signatureData = signatureData; // base64 canvas or typed name
185	    contract.signatureHash = hash;
186	    contract.signedBy = userId;
187	    contract.signedAt = timestamp;
188	    contract.status = CONTRACT_STATUS.SIGNED;
189	    contract.updatedAt = timestamp;
190	
191	    await this._contractRepo.put(contract);
192	    await this._auditService.log('contract', contractId, 'signed', `Signed by ${signerName}, hash: ${hash.substring(0, 16)}...`, userId);
193	    return contract;
194	  }
195	
196	  /**
197	   * Withdraw a contract.
198	   */
199	  async withdrawContract(contractId, userId) {
200	    return this.transitionStatus(contractId, CONTRACT_STATUS.WITHDRAWN, userId);
201	  }
202	
203	  /**
204	   * Void a contract.
205	   */
206	  async voidContract(contractId, userId) {
207	    return this.transitionStatus(contractId, CONTRACT_STATUS.VOIDED, userId);
208	  }
209	
210	  // --- Export ---
211	
212	  /**
213	   * Export contract to a printable HTML blob for PDF-like output.
214	   */
215	  exportToPrintableHTML(contract) {
216	    const html = `<!DOCTYPE html>
217	<html><head><meta charset="UTF-8"><title>Contract ${contract.id}</title>
218	<style>
219	  body { font-family: serif; max-width: 800px; margin: 40px auto; padding: 20px; line-height: 1.6; }
