123	        </div>
124	        <div class="form-group" id="q-options-group">
125	          <label for="q-options">Options (one per line, prefix correct with *)</label>
126	          <textarea id="q-options" class="form-control" rows="4" placeholder="*Option A (correct)&#10;Option B&#10;Option C&#10;Option D"></textarea>
127	          <small style="color:var(--color-text-muted)">For single/multiple choice. Prefix correct answers with *</small>
128	        </div>
129	        <div class="form-group">
130	          <label for="q-answer">Correct Answer (for fill-in type)</label>
131	          <input id="q-answer" class="form-control" type="text">
132	        </div>
133	        <div class="form-group">
134	          <label for="q-difficulty">Difficulty (1–5)</label>
135	          <input id="q-difficulty" class="form-control" type="number" min="1" max="5" required>
136	        </div>
137	        <div class="form-group">
138	          <label for="q-tags">Tags (comma-separated)</label>
139	          <input id="q-tags" class="form-control" type="text" required>
140	        </div>
141	        <div class="form-group">
142	          <label for="q-chapter">Chapter</label>
143	          <input id="q-chapter" class="form-control" type="text">
144	        </div>
145	        <div class="form-group">
146	          <label for="q-explanation">Explanation</label>
147	          <textarea id="q-explanation" class="form-control" rows="2"></textarea>
148	        </div>
149	        <div id="q-error" class="form-error"></div>
150	        <button type="submit" class="btn btn-primary mt-4">Save</button>
