2	 * RatingService — two-way ratings with tag-based feedback and appeal flow.
3	 */
4	
5	import ratingRepository from '../repositories/RatingRepository.js';
6	import appealRepository from '../repositories/AppealRepository.js';
7	import userRepository from '../repositories/UserRepository.js';
8	import defaultAuditService from './AuditService.js';
9	import { createRating, createAppeal, APPEAL_STATUS } from '../models/Rating.js';
10	import { USER_ROLES } from '../models/User.js';
