13	export class RatingService {
14	  constructor(deps = {}) {
15	    this._ratingRepo = deps.ratingRepository || ratingRepository;
16	    this._appealRepo = deps.appealRepository || appealRepository;
17	    this._userRepo = deps.userRepository || userRepository;
18	    this._auditService = deps.auditService || defaultAuditService;
19	  }
20	
21	  async submitRating({ fromUserId, toUserId, classId, score, tags, comment }) {
22	    if (!fromUserId) throw new Error('fromUserId is required.');
23	    if (!toUserId) throw new Error('toUserId is required.');
24	    if (fromUserId === toUserId) throw new Error('Cannot rate yourself.');
25	    if (!Number.isInteger(score) || score < 1 || score > 5) {
26	      throw new Error('Score must be between 1 and 5.');
27	    }
28	
29	    const rating = createRating({
30	      id: generateId(),
31	      fromUserId,
32	      toUserId,
33	      classId,
34	      score,
35	      tags: tags || [],
36	      comment: comment || '',
37	    });
38	
39	    await this._ratingRepo.add(rating);
40	    await this._auditService.log('rating', rating.id, 'created', `Rating ${score}/5 from ${fromUserId} to ${toUserId}`, fromUserId);
41	    return rating;
42	  }
43	
44	  /**
45	   * File an appeal on a rating.
46	   */
47	  async fileAppeal(ratingId, appealerId, reason) {
48	    if (!ratingId) throw new Error('ratingId is required.');
49	    if (!appealerId) throw new Error('appealerId is required.');
50	    if (!reason || String(reason).trim() === '') throw new Error('Appeal reason is required.');
51	
52	    const rating = await this._ratingRepo.getById(ratingId);
53	    if (!rating) throw new Error('Rating not found.');
54	
55	    const existingAppeals = await this._appealRepo.getByRatingId(ratingId);
56	    const pending = existingAppeals.find(a => a.status === APPEAL_STATUS.PENDING);
57	    if (pending) throw new Error('An appeal is already pending for this rating.');
58	
59	    const appeal = createAppeal({
60	      id: generateId(),
61	      ratingId,
62	      appealerId,
63	      reason,
64	    });
65	
66	    await this._appealRepo.add(appeal);
67	    await this._auditService.log('appeal', appeal.id, 'filed', `Appeal filed for rating ${ratingId}`, appealerId);
68	    return appeal;
69	  }
70	
71	  /**
72	   * Resolve an appeal (reviewer decision: uphold, adjust, void).
73	   */
74	  async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore = null) {
75	    if (!appealId) throw new Error('appealId is required.');
76	    if (!reviewerId) throw new Error('reviewerId is required.');
77	
78	    // RBAC: only reviewers and admins can resolve appeals (fail-closed)
79	    const actingUser = await this._userRepo.getById(reviewerId);
80	    if (!actingUser) {
81	      throw new Error('Acting user not found. Cannot resolve appeal.');
82	    }
83	    if (![USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role)) {
84	      throw new Error('Only administrators or staff reviewers can resolve appeals.');
85	    }
86	
87	    const appeal = await this._appealRepo.getById(appealId);
88	    if (!appeal) throw new Error('Appeal not found.');
89	
90	    if (appeal.status !== APPEAL_STATUS.PENDING) {
91	      throw new Error('Appeal has already been resolved.');
92	    }
93	
94	    if (!rationale || rationale.trim().length === 0) {
95	      throw new Error('Written rationale is required.');
96	    }
97	
98	    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
99	    if (!validDecisions.includes(decision)) {
100	      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
101	    }
102	
103	    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
104	      throw new Error('Adjusted score must be between 1 and 5.');
105	    }
106	
107	    appeal.status = decision;
108	    appeal.decision = decision;
109	    appeal.rationale = rationale;
110	    appeal.reviewerId = reviewerId;
111	    appeal.adjustedScore = adjustedScore;
112	    appeal.resolvedAt = now();
113	
114	    await this._appealRepo.put(appeal);
115	
116	    // If adjusted, update the original rating
117	    if (decision === APPEAL_STATUS.ADJUSTED) {
118	      const rating = await this._ratingRepo.getById(appeal.ratingId);
119	      if (rating) {
120	        rating.score = adjustedScore;
121	        await this._ratingRepo.put(rating);
122	      }
123	    }
124	
125	    // If voided, we could mark the rating as void — for now just log it
126	    await this._auditService.log('appeal', appealId, 'resolved', `Decision: ${decision}, rationale: ${rationale}`, reviewerId);
127	    return appeal;
128	  }
129	
130	  async getRatingById(ratingId) {
131	    return this._ratingRepo.getById(ratingId);
132	  }
133	
134	  async getRatingsForUser(toUserId) {
135	    return this._ratingRepo.getByToUserId(toUserId);
136	  }
137	
138	  async getRatingsByUser(fromUserId) {
139	    return this._ratingRepo.getByFromUserId(fromUserId);
140	  }
141	
142	  async getAllRatings() {
143	    return this._ratingRepo.getAll();
144	  }
145	
146	  async getPendingAppeals() {
147	    return this._appealRepo.getByStatus(APPEAL_STATUS.PENDING);
148	  }
149	
150	  async getAppealsByRatingId(ratingId) {
151	    return this._appealRepo.getByRatingId(ratingId);
152	  }
153	
154	  async getAllAppeals() {
155	    return this._appealRepo.getAll();
156	  }
157	}
158	
159	export default new RatingService();
