13	// Resolution deadline is loaded from config; this is only a fallback default
14	const DEFAULT_RESOLUTION_DEADLINE_DAYS = 7;
15	
16	const FALLBACK_WORDS = ['spam', 'scam', 'fake', 'fraud', 'abuse', 'harassment', 'threat', 'exploit', 'illegal', 'offensive'];
17	
18	let sensitiveWords = [];
19	
20	export class ModerationService {
21	  constructor(deps = {}) {
22	    this._reportRepo = deps.reportRepository || reportRepository;
23	    this._userRepo = deps.userRepository || userRepository;
24	    this._auditService = deps.auditService || defaultAuditService;
25	    if (deps.sensitiveWords) {
26	      sensitiveWords = deps.sensitiveWords;
27	    }
28	  }
29	
30	  async loadSensitiveWords() {
31	    try {
32	      const response = await fetch('../src/config/sensitiveWords.json');
33	      const data = await response.json();
34	      sensitiveWords = (data.words || []).map(w => w.toLowerCase());
35	    } catch (e) {
36	      console.warn('Could not load sensitive words config, using fallback list.');
37	      sensitiveWords = FALLBACK_WORDS;
38	    }
39	  }
40	
41	  checkContent(text) {
42	    if (!text) return { flagged: false, words: [] };
43	    const lower = text.toLowerCase();
44	    const found = sensitiveWords.filter(w => lower.includes(w));
45	    return { flagged: found.length > 0, words: found };
46	  }
47	
48	  async submitReport(reporterId, targetId, targetType, reason) {
49	    if (!reporterId) throw new Error('reporterId is required.');
50	    if (!targetId) throw new Error('targetId is required.');
51	    if (!targetType) throw new Error('targetType is required.');
52	    const report = createReport({ id: generateId(), reporterId, targetId, targetType, reason });
53	    await this._reportRepo.add(report);
54	    await this._auditService.log('report', report.id, 'created', `Abuse report filed against ${targetType}:${targetId}`, reporterId);
55	    return report;
56	  }
57	
58	  async resolveReport(reportId, outcome, resolvedBy) {
59	    if (!reportId) throw new Error('reportId is required.');
60	    if (!resolvedBy) throw new Error('resolvedBy is required.');
61	
62	    // RBAC: only reviewers and admins can resolve reports (fail-closed)
63	    const actingUser = await this._userRepo.getById(resolvedBy);
64	    if (!actingUser) {
65	      throw new Error('Acting user not found. Cannot resolve report.');
66	    }
67	    if (![USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role)) {
68	      throw new Error('Only administrators or staff reviewers can resolve reports.');
69	    }
70	
71	    const report = await this._reportRepo.getById(reportId);
72	    if (!report) throw new Error('Report not found.');
73	    if (report.status === REPORT_STATUS.RESOLVED) throw new Error('Report has already been resolved.');
74	    const validOutcomes = Object.values(REPORT_OUTCOMES);
75	    if (!validOutcomes.includes(outcome)) throw new Error(`Outcome must be one of: ${validOutcomes.join(', ')}`);
76	    report.status = REPORT_STATUS.RESOLVED;
77	    report.resolution = outcome;
78	    report.resolvedBy = resolvedBy;
79	    report.resolvedAt = now();
80	    await this._reportRepo.put(report);
81	    await this._auditService.log('report', report.id, 'resolved', `Report resolved: ${outcome}`, resolvedBy);
82	    return report;
83	  }
84	
85	  async getOpenReports() {
86	    const open = await this._reportRepo.getByStatus(REPORT_STATUS.OPEN);
87	    const underReview = await this._reportRepo.getByStatus(REPORT_STATUS.UNDER_REVIEW);
88	    return [...open, ...underReview];
89	  }
90	
91	  async getOverdueReports() {
92	    const open = await this.getOpenReports();
93	    const config = getConfig();
94	    const deadlineDays = (config.moderation && config.moderation.resolutionDeadlineDays) || DEFAULT_RESOLUTION_DEADLINE_DAYS;
95	    const cutoff = Date.now() - deadlineDays * 24 * 60 * 60 * 1000;
96	    return open.filter(r => new Date(r.createdAt).getTime() < cutoff);
97	  }
98	
99	  async getAllReports() { return this._reportRepo.getAll(); }
100	  async getReportById(reportId) { return this._reportRepo.getById(reportId); }
101	}
102	
103	export default new ModerationService();
