3	 */
4	
5	import moderationService from './ModerationService.js';
6	import notificationService from './NotificationService.js';
7	
8	export class SchedulerService {
9	  constructor() {
10	    this._intervals = [];
11	  }
12	
13	  /**
14	   * Start all scheduled tasks.
15	   */
16	  start() {
17	    // Check for overdue moderation reports every 30 minutes
18	    this._intervals.push(
19	      setInterval(() => this._checkOverdueReports(), 30 * 60 * 1000)
20	    );
21	
22	    // Run an initial check immediately
23	    this._checkOverdueReports();
24	  }
25	
26	  /**
27	   * Stop all scheduled tasks.
28	   */
29	  stop() {
30	    for (const id of this._intervals) {
31	      clearInterval(id);
32	    }
33	    this._intervals = [];
34	  }
35	
36	  /**
37	   * Check for overdue abuse reports and notify.
38	   */
39	  async _checkOverdueReports() {
40	    try {
41	      const overdue = await moderationService.getOverdueReports();
42	      for (const report of overdue) {
43	        // Only notify if not already notified (basic dedup via report status)
44	        if (report.status === 'open') {
45	          await notificationService.notify(
46	            'system',
47	            'Overdue Report',
48	            `Abuse report ${report.id} is overdue for resolution.`,
49	            'warning',
50	            '#/reviews'
51	          );
52	        }
53	      }
54	    } catch (err) {
55	      console.error('Scheduler: overdue report check failed', err);
56	    }
57	  }
58	}
