/**
 * ImportExportService — full dataset export/import with optional AES encryption.
 */

import { getDatabase, openDatabase, STORES } from '../store/Database.js';
import cryptoService from './CryptoService.js';
import { downloadBlob } from '../utils/helpers.js';

export class ImportExportService {
  /**
   * Export the entire dataset as JSON.
   * @param {string} [passphrase] — if provided, encrypt the export with AES-GCM
   */
  async exportAll(passphrase = null) {
    const db = getDatabase();
    if (!db) throw new Error('Database not initialized.');

    const data = {};
    for (const storeDef of STORES) {
      data[storeDef.name] = await this._readStore(db, storeDef.name);
    }

    // Also capture LocalStorage settings
    data._localStorage = {};
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      data._localStorage[key] = localStorage.getItem(key);
    }

    let jsonStr = JSON.stringify(data, null, 2);

    if (passphrase) {
      const encrypted = await cryptoService.encrypt(jsonStr, passphrase);
      jsonStr = JSON.stringify({ encrypted: true, ...encrypted });
    }

    const blob = new Blob([jsonStr], { type: 'application/json' });
    const filename = `trainingops-backup-${new Date().toISOString().slice(0, 10)}.json`;
    downloadBlob(blob, filename);

    return { success: true, filename };
  }

  /**
   * Import a dataset from a JSON file.
   * @param {File} file
   * @param {string} [passphrase] — for decryption
   * @returns {{ success: boolean, preview?: object, error?: string }}
   */
  async parseImportFile(file, passphrase = null) {
    const text = await file.text();
    let parsed;

    try {
      parsed = JSON.parse(text);
    } catch {
      return { success: false, error: 'Invalid JSON file.' };
    }

    // Decrypt if needed
    if (parsed.encrypted) {
      if (!passphrase) {
        return { success: false, error: 'File is encrypted. A passphrase is required.' };
      }
      try {
        const decrypted = await cryptoService.decrypt(parsed, passphrase);
        parsed = JSON.parse(decrypted);
      } catch {
        return { success: false, error: 'Decryption failed. Wrong passphrase.' };
      }
    }

    // Build preview: count of records per store
    const preview = {};
    for (const storeDef of STORES) {
      if (parsed[storeDef.name]) {
        preview[storeDef.name] = parsed[storeDef.name].length;
      }
    }

    return { success: true, preview, data: parsed };
  }

  /**
   * Apply imported data (overwrites existing). Must call parseImportFile first.
   */
  async applyImport(data) {
    if (!data || typeof data !== 'object') {
      throw new Error('Invalid import data format.');
    }

    const db = getDatabase();
    if (!db) throw new Error('Database not initialized.');

    for (const storeDef of STORES) {
      if (!data[storeDef.name]) continue;

      await new Promise((resolve, reject) => {
        const tx = db.transaction(storeDef.name, 'readwrite');
        const store = tx.objectStore(storeDef.name);
        store.clear();
        for (const record of data[storeDef.name]) {
          store.put(record);
        }
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
      });
    }

    // Restore LocalStorage entries
    if (data._localStorage) {
      for (const [key, value] of Object.entries(data._localStorage)) {
        localStorage.setItem(key, value);
      }
    }

    return { success: true };
  }

  _readStore(db, storeName) {
    return new Promise((resolve, reject) => {
      const tx = db.transaction(storeName, 'readonly');
      const store = tx.objectStore(storeName);
      const req = store.getAll();
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
  }
}

