1	/**
2	 * ImportExportService — full dataset export/import with optional AES encryption.
3	 */
4	
5	import { getDatabase, openDatabase, STORES } from '../store/Database.js';
6	import cryptoService from './CryptoService.js';
7	import { downloadBlob } from '../utils/helpers.js';
8	
9	export class ImportExportService {
10	  /**
11	   * Export the entire dataset as JSON.
12	   * @param {string} [passphrase] — if provided, encrypt the export with AES-GCM
13	   */
14	  async exportAll(passphrase = null) {
15	    const db = getDatabase();
16	    if (!db) throw new Error('Database not initialized.');
17	
18	    const data = {};
19	    for (const storeDef of STORES) {
20	      data[storeDef.name] = await this._readStore(db, storeDef.name);
21	    }
22	
23	    // Also capture LocalStorage settings
24	    data._localStorage = {};
25	    for (let i = 0; i < localStorage.length; i++) {
26	      const key = localStorage.key(i);
27	      data._localStorage[key] = localStorage.getItem(key);
28	    }
29	
30	    // Strip sensitive fields from export data
31	    if (data.users) {
32	      data.users = data.users.map(u => {
33	        const { passwordHash, lockoutUntil, ...safe } = u;
34	        return safe;
35	      });
36	    }
37	    if (data.sessions) {
38	      data.sessions = []; // Never export session data
39	    }
40	
41	    let jsonStr = JSON.stringify(data, null, 2);
42	
43	    if (passphrase) {
44	      const encrypted = await cryptoService.encrypt(jsonStr, passphrase);
45	      jsonStr = JSON.stringify({ encrypted: true, ...encrypted });
46	    }
47	
48	    const blob = new Blob([jsonStr], { type: 'application/json' });
49	    const filename = `trainingops-backup-${new Date().toISOString().slice(0, 10)}.json`;
50	    downloadBlob(blob, filename);
51	
52	    return { success: true, filename };
53	  }
54	
55	  /**
56	   * Import a dataset from a JSON file.
57	   * @param {File} file
58	   * @param {string} [passphrase] — for decryption
59	   * @returns {{ success: boolean, preview?: object, error?: string }}
60	   */
61	  async parseImportFile(file, passphrase = null) {
62	    const text = await file.text();
63	    let parsed;
64	
65	    try {
66	      parsed = JSON.parse(text);
67	    } catch {
68	      return { success: false, error: 'Invalid JSON file.' };
69	    }
70	
71	    // Decrypt if needed
72	    if (parsed.encrypted) {
73	      if (!passphrase) {
74	        return { success: false, error: 'File is encrypted. A passphrase is required.' };
75	      }
76	      try {
77	        const decrypted = await cryptoService.decrypt(parsed, passphrase);
78	        parsed = JSON.parse(decrypted);
79	      } catch {
80	        return { success: false, error: 'Decryption failed. Wrong passphrase.' };
81	      }
82	    }
83	
84	    // Build preview: count of records per store
85	    const preview = {};
86	    for (const storeDef of STORES) {
87	      if (parsed[storeDef.name]) {
88	        preview[storeDef.name] = parsed[storeDef.name].length;
89	      }
90	    }
91	
92	    return { success: true, preview, data: parsed };
93	  }
94	
95	  /**
96	   * Apply imported data (overwrites existing). Must call parseImportFile first.
97	   */
98	  async applyImport(data) {
99	    if (!data || typeof data !== 'object') {
100	      throw new Error('Invalid import data format.');
101	    }
102	
103	    const db = getDatabase();
104	    if (!db) throw new Error('Database not initialized.');
105	
106	    for (const storeDef of STORES) {
107	      if (!data[storeDef.name]) continue;
108	
109	      await new Promise((resolve, reject) => {
110	        const tx = db.transaction(storeDef.name, 'readwrite');
111	        const store = tx.objectStore(storeDef.name);
112	        store.clear();
113	        for (const record of data[storeDef.name]) {
114	          store.put(record);
115	        }
116	        tx.oncomplete = () => resolve();
117	        tx.onerror = () => reject(tx.error);
118	      });
119	    }
120	
121	    // Restore LocalStorage entries
122	    if (data._localStorage) {
123	      for (const [key, value] of Object.entries(data._localStorage)) {
124	        localStorage.setItem(key, value);
125	      }
126	    }
127	
128	    return { success: true };
129	  }
130	
131	  _readStore(db, storeName) {
132	    return new Promise((resolve, reject) => {
133	      const tx = db.transaction(storeName, 'readonly');
134	      const store = tx.objectStore(storeName);
135	      const req = store.getAll();
136	      req.onsuccess = () => resolve(req.result);
137	      req.onerror = () => reject(req.error);
138	    });
139	  }
140	}
141	
142	export default new ImportExportService();
