15	  { name: 'registrationEvents', keyPath: 'id', indexes: [{ name: 'registrationId', keyPath: 'registrationId' }, { name: 'timestamp', keyPath: 'timestamp' }] },
16	  { name: 'classes',            keyPath: 'id', indexes: [{ name: 'instructorId', keyPath: 'instructorId' }] },
17	  { name: 'questions',          keyPath: 'id', indexes: [{ name: 'type', keyPath: 'type' }, { name: 'difficulty', keyPath: 'difficulty' }] },
18	  { name: 'quizzes',            keyPath: 'id', indexes: [{ name: 'classId', keyPath: 'classId' }] },
19	  { name: 'quizResults',        keyPath: 'id', indexes: [{ name: 'quizId', keyPath: 'quizId' }, { name: 'userId', keyPath: 'userId' }] },
