{
  "name": "trainingops-enrollment-quality-console",
  "version": "1.0.0",
  "description": "Offline browser-based SPA for managing training enrollment, assessments, contracts, and trust workflows.",
  "type": "module",
  "scripts": {
    "start": "node server.js",
    "test": "node run_tests.js"
  },
  "private": true
}

1	/**
2	 * Minimal browser environment simulation for Node.js.
3	 * Provides window, document, localStorage, location, and basic DOM.
4	 * No external dependencies — pure JavaScript.
5	 */
6	
7	// ============================================================
8	// Minimal DOM Element
9	// ============================================================
10	
11	class MinimalElement {
12	  constructor(tagName) {
13	    this.tagName = tagName.toUpperCase();
14	    this.children = [];
15	    this.attributes = {};
16	    this.style = {};
17	    this.classList = new MinimalClassList();
18	    this.textContent = '';
19	    this._innerHTML = '';
20	    this._listeners = {};
21	    this.parentNode = null;
22	    this.disabled = false;
23	    this.value = '';
24	    this.type = '';
25	    this.dataset = {};
26	    this.id = '';
27	    this.className = '';
28	    this.checked = false;
29	    this.files = [];
30	  }
31	
32	  get innerHTML() { return this._innerHTML; }
33	  set innerHTML(val) {
34	    this._innerHTML = val;
35	    this.children = [];
36	    // Parse id attributes for querySelector
37	    this._parsedIds = {};
38	    const idRegex = /id="([^"]+)"/g;
39	    let m;
40	    while ((m = idRegex.exec(val)) !== null) {
41	      this._parsedIds[m[1]] = new MinimalElement('div');
42	      this._parsedIds[m[1]].id = m[1];
43	      this._parsedIds[m[1]]._innerHTML = '';
44	      this._parsedIds[m[1]]._parentRef = this;
45	    }
46	  }
47	
48	  setAttribute(name, value) { this.attributes[name] = value; }
49	  getAttribute(name) { return this.attributes[name] ?? null; }
50	
51	  addEventListener(event, handler) {
52	    if (!this._listeners[event]) this._listeners[event] = [];
53	    this._listeners[event].push(handler);
54	  }
55	
56	  removeEventListener(event, handler) {
57	    if (!this._listeners[event]) return;
58	    this._listeners[event] = this._listeners[event].filter(h => h !== handler);
59	  }
60	
61	  dispatchEvent(event) {
62	    const handlers = this._listeners[event.type || event] || [];
63	    for (const h of handlers) h(event);
64	  }
65	
66	  click() {
67	    this.dispatchEvent({ type: 'click', target: this, currentTarget: this, stopPropagation: () => {}, preventDefault: () => {} });
68	  }
69	
70	  querySelector(selector) {
71	    if (selector.startsWith('#')) {
72	      const id = selector.slice(1);
73	      if (this._parsedIds && this._parsedIds[id]) return this._parsedIds[id];
74	      for (const child of this.children) {
75	        const found = child.querySelector(selector);
76	        if (found) return found;
77	      }
78	    }
79	    if (selector.startsWith('.')) {
80	      const cls = selector.slice(1);
81	      if (this.classList.contains(cls)) return this;
82	      for (const child of this.children) {
83	        const found = child.querySelector(selector);
84	        if (found) return found;
85	      }
86	    }
87	    return null;
88	  }
89	
90	  querySelectorAll(selector) {
91	    const results = [];
92	    if (selector.startsWith('.')) {
93	      const cls = selector.slice(1);
94	      if (this.classList.contains(cls)) results.push(this);
95	    }
96	    for (const child of this.children) {
97	      results.push(...child.querySelectorAll(selector));
98	    }
99	    return results;
100	  }
101	
102	  appendChild(child) {
103	    child.parentNode = this;
104	    this.children.push(child);
105	    return child;
106	  }
107	
108	  removeChild(child) {
109	    this.children = this.children.filter(c => c !== child);
110	    child.parentNode = null;
111	    return child;
112	  }
113	
114	  getContext() {
115	    return {
116	      beginPath: () => {}, moveTo: () => {}, lineTo: () => {}, stroke: () => {},
117	      clearRect: () => {},
118	    };
119	  }
120	
121	  toDataURL() { return 'data:image/png;base64,mock'; }
122	}
123	
124	class MinimalClassList {
125	  constructor() { this._classes = new Set(); }
126	  add(cls) { this._classes.add(cls); }
127	  remove(cls) { this._classes.delete(cls); }
128	  toggle(cls, force) {
129	    if (force === undefined) {
130	      this._classes.has(cls) ? this._classes.delete(cls) : this._classes.add(cls);
131	    } else {
132	      force ? this._classes.add(cls) : this._classes.delete(cls);
133	    }
134	  }
135	  contains(cls) { return this._classes.has(cls); }
136	}
137	
138	// ============================================================
139	// Minimal Document
140	// ============================================================
141	
142	class MinimalDocument {
143	  constructor() {
144	    this.body = new MinimalElement('body');
145	    this._elements = {};
146	  }
147	
148	  createElement(tag) { return new MinimalElement(tag); }
149	
150	  getElementById(id) {
151	    return this._elements[id] || null;
152	  }
153	
154	  querySelector(selector) {
155	    if (selector.startsWith('#')) {
156	      return this.getElementById(selector.slice(1));
157	    }
158	    if (selector === '.app-shell') {
159	      return this._appShell || null;
160	    }
161	    return this.body.querySelector(selector);
162	  }
163	
164	  querySelectorAll(selector) {
165	    return this.body.querySelectorAll(selector);
166	  }
167	
168	  registerElement(id, el) {
169	    this._elements[id] = el;
170	    el.id = id;
171	  }
172	}
173	
174	// ============================================================
175	// Minimal localStorage
176	// ============================================================
177	
178	class MinimalStorage {
179	  constructor() { this._data = {}; }
180	  getItem(key) { return this._data[key] ?? null; }
181	  setItem(key, value) { this._data[key] = String(value); }
182	  removeItem(key) { delete this._data[key]; }
183	  clear() { this._data = {}; }
184	  get length() { return Object.keys(this._data).length; }
185	  key(index) { return Object.keys(this._data)[index] || null; }
186	}
187	
188	// ============================================================
189	// Minimal Window + Location
190	// ============================================================
191	
192	class MinimalLocation {
193	  constructor() { this._hash = ''; }
194	  get hash() { return this._hash; }
195	  set hash(val) {
196	    this._hash = val;
197	    // Trigger hashchange
198	    if (globalThis._hashChangeListeners) {
199	      for (const fn of globalThis._hashChangeListeners) {
200	        fn({ type: 'hashchange' });
201	      }
202	    }
203	  }
204	}
205	
206	// ============================================================
207	// Install globals
208	// ============================================================
209	
210	export function installBrowserEnv() {
211	  const doc = new MinimalDocument();
212	  const storage = new MinimalStorage();
213	  const location = new MinimalLocation();
214	
215	  globalThis._hashChangeListeners = [];
216	
217	  globalThis.document = doc;
218	  globalThis.localStorage = storage;
219	  globalThis.window = globalThis;
220	  globalThis.location = location;
221	
222	  // Stub URL methods
223	  globalThis.URL = globalThis.URL || class { static createObjectURL() { return 'blob:mock'; } static revokeObjectURL() {} };
224	  globalThis.Blob = globalThis.Blob || class { constructor(parts, opts) { this.parts = parts; this.type = opts?.type; } };
225	  globalThis.FileReader = globalThis.FileReader || class {
226	    readAsText(file) { setTimeout(() => { this.result = file._text || ''; if (this.onload) this.onload(); }, 0); }
227	    readAsArrayBuffer(file) { setTimeout(() => { this.result = file._buffer || new ArrayBuffer(0); if (this.onload) this.onload(); }, 0); }
228	    readAsDataURL(file) { setTimeout(() => { this.result = 'data:mock'; if (this.onload) this.onload(); }, 0); }
229	  };
230	
231	  // Stub addEventListener on window for hashchange
232	  const origAddEventListener = globalThis.addEventListener?.bind(globalThis);
233	  globalThis.addEventListener = (event, handler) => {
234	    if (event === 'hashchange') {
235	      globalThis._hashChangeListeners.push(handler);
236	    } else if (origAddEventListener) {
237	      origAddEventListener(event, handler);
238	    }
239	  };
240	
241	  // Create app root element
242	  const appEl = new MinimalElement('div');
243	  appEl.id = 'app';
244	  doc.registerElement('app', appEl);
245	
246	  return { document: doc, localStorage: storage, location, appEl };
247	}
248	
249	export function resetBrowserEnv() {
250	  if (globalThis.localStorage) globalThis.localStorage.clear();
251	  if (globalThis.location) globalThis.location._hash = '';
252	  if (globalThis._hashChangeListeners) globalThis._hashChangeListeners = [];
253	}
