1	/**
2	 * ImportExportService — full dataset export/import with optional AES encryption.
3	 * RBAC: Administrator-only for all operations.
4	 */
5	
6	import { getDatabase, openDatabase, STORES } from '../store/Database.js';
7	import cryptoService from './CryptoService.js';
8	import userRepository from '../repositories/UserRepository.js';
9	import { USER_ROLES } from '../models/User.js';
10	import { downloadBlob } from '../utils/helpers.js';
11	
12	export class ImportExportService {
13	  constructor(deps = {}) {
14	    this._userRepo = deps.userRepository || userRepository;
15	  }
16	
17	  /**
18	   * Verify the acting user is an Administrator (fail-closed).
19	   */
20	  async _requireAdmin(actingUserId) {
21	    if (!actingUserId) throw new Error('userId is required for import/export operations.');
22	    const user = await this._userRepo.getById(actingUserId);
23	    if (!user) throw new Error('Acting user not found. Cannot perform import/export.');
24	    if (user.role !== USER_ROLES.ADMINISTRATOR) {
25	      throw new Error('Only administrators can perform import/export operations.');
26	    }
27	  }
28	
29	  /**
30	   * Export the entire dataset as JSON.
31	   * @param {string} actingUserId — must be an Administrator
32	   * @param {string} [passphrase] — if provided, encrypt the export with AES-GCM
33	   */
34	  async exportAll(actingUserId, passphrase = null) {
35	    await this._requireAdmin(actingUserId);
36	
37	    const db = getDatabase();
38	    if (!db) throw new Error('Database not initialized.');
39	
40	    const data = {};
41	    for (const storeDef of STORES) {
42	      data[storeDef.name] = await this._readStore(db, storeDef.name);
43	    }
44	
45	    // Also capture LocalStorage settings
46	    data._localStorage = {};
47	    for (let i = 0; i < localStorage.length; i++) {
48	      const key = localStorage.key(i);
49	      data._localStorage[key] = localStorage.getItem(key);
50	    }
51	
52	    // Strip sensitive fields from export data
53	    if (data.users) {
54	      data.users = data.users.map(u => {
55	        const { passwordHash, lockoutUntil, ...safe } = u;
56	        return safe;
57	      });
58	    }
59	    if (data.sessions) {
60	      data.sessions = []; // Never export session data
61	    }
62	
63	    let jsonStr = JSON.stringify(data, null, 2);
64	
65	    if (passphrase) {
66	      const encrypted = await cryptoService.encrypt(jsonStr, passphrase);
67	      jsonStr = JSON.stringify({ encrypted: true, ...encrypted });
68	    }
69	
70	    const blob = new Blob([jsonStr], { type: 'application/json' });
71	    const filename = `trainingops-backup-${new Date().toISOString().slice(0, 10)}.json`;
72	    downloadBlob(blob, filename);
73	
74	    return { success: true, filename };
75	  }
76	
77	  /**
78	   * Import a dataset from a JSON file.
79	   * @param {string} actingUserId — must be an Administrator
80	   * @param {File} file
81	   * @param {string} [passphrase] — for decryption
82	   * @returns {{ success: boolean, preview?: object, error?: string }}
83	   */
84	  async parseImportFile(actingUserId, file, passphrase = null) {
85	    await this._requireAdmin(actingUserId);
86	
87	    const text = await file.text();
88	    let parsed;
89	
90	    try {
91	      parsed = JSON.parse(text);
92	    } catch {
93	      return { success: false, error: 'Invalid JSON file.' };
94	    }
95	
96	    // Decrypt if needed
97	    if (parsed.encrypted) {
98	      if (!passphrase) {
99	        return { success: false, error: 'File is encrypted. A passphrase is required.' };
100	      }
101	      try {
102	        const decrypted = await cryptoService.decrypt(parsed, passphrase);
103	        parsed = JSON.parse(decrypted);
104	      } catch {
105	        return { success: false, error: 'Decryption failed. Wrong passphrase.' };
106	      }
107	    }
108	
109	    // Build preview: count of records per store
110	    const preview = {};
111	    for (const storeDef of STORES) {
112	      if (parsed[storeDef.name]) {
113	        preview[storeDef.name] = parsed[storeDef.name].length;
114	      }
115	    }
116	
117	    return { success: true, preview, data: parsed };
118	  }
119	
120	  /**
121	   * Apply imported data (overwrites existing). Must call parseImportFile first.
122	   * @param {string} actingUserId — must be an Administrator
123	   * @param {object} data — parsed import data
124	   */
125	  async applyImport(actingUserId, data) {
126	    await this._requireAdmin(actingUserId);
127	
128	    if (!data || typeof data !== 'object') {
129	      throw new Error('Invalid import data format.');
130	    }
131	
132	    const db = getDatabase();
133	    if (!db) throw new Error('Database not initialized.');
134	
135	    for (const storeDef of STORES) {
136	      if (!data[storeDef.name]) continue;
137	
138	      await new Promise((resolve, reject) => {
139	        const tx = db.transaction(storeDef.name, 'readwrite');
140	        const store = tx.objectStore(storeDef.name);
141	        store.clear();
142	        for (const record of data[storeDef.name]) {
143	          store.put(record);
144	        }
145	        tx.oncomplete = () => resolve();
146	        tx.onerror = () => reject(tx.error);
147	      });
148	    }
149	
150	    // Restore LocalStorage entries
151	    if (data._localStorage) {
152	      for (const [key, value] of Object.entries(data._localStorage)) {
153	        localStorage.setItem(key, value);
154	      }
155	    }
156	
157	    return { success: true };
158	  }
159	
160	  _readStore(db, storeName) {
161	    return new Promise((resolve, reject) => {
162	      const tx = db.transaction(storeName, 'readonly');
163	      const store = tx.objectStore(storeName);
164	      const req = store.getAll();
165	      req.onsuccess = () => resolve(req.result);
166	      req.onerror = () => reject(req.error);
167	    });
168	  }
169	}
170	
171	export default new ImportExportService();
