    const ID_PATTERN = /^[a-zA-Z0-9_\-.:]+$/;

    for (const key of Object.keys(data)) {
      if (key === '_localStorage' || key === 'encrypted' || key === 'passphraseRequired') continue;
      if (!VALID_STORES.includes(key)) {
        // Skip unknown stores but don't fail — forward compat
        continue;
      }

      const records = data[key];
      if (!Array.isArray(records)) {
        errors.push(`Store "${key}" must be an array`);
        continue;
      }

      for (let i = 0; i < records.length; i++) {
        const record = records[i];
        if (typeof record !== 'object' || record === null) {
          errors.push(`Store "${key}" record ${i}: must be an object`);
          continue;
        }
        // Validate ID field if present — prevent script injection via IDs
        const id = record.id || record.key;
        if (id && typeof id === 'string' && !ID_PATTERN.test(id)) {
          errors.push(`Store "${key}" record ${i}: invalid ID format "${String(id).substring(0, 20)}..."`);
        }
      }
    }
    return errors;
  }

