1	/**
2	 * CryptoService — PBKDF2 password hashing, AES encryption, SHA-256 hashing, masking.
3	 */
4	
5	const PBKDF2_ITERATIONS = 100000;
6	const SALT_LENGTH = 16;
7	const AES_IV_LENGTH = 12;
8	
9	export class CryptoService {
10	  /**
11	   * Hash a password with PBKDF2.
12	   * @returns {{ hash: string, salt: string }}
13	   */
14	  async hashPassword(password) {
15	    const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
16	    const keyMaterial = await crypto.subtle.importKey(
17	      'raw',
18	      new TextEncoder().encode(password),
19	      'PBKDF2',
20	      false,
21	      ['deriveBits']
22	    );
23	    const bits = await crypto.subtle.deriveBits(
24	      { name: 'PBKDF2', salt, iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
25	      keyMaterial,
26	      256
27	    );
28	    return {
29	      hash: this._bufToHex(bits),
30	      salt: this._bufToHex(salt),
31	    };
32	  }
33	
34	  /**
35	   * Verify a password against a stored hash+salt.
36	   */
37	  async verifyPassword(password, storedHash, storedSalt) {
38	    const salt = this._hexToBuf(storedSalt);
39	    const keyMaterial = await crypto.subtle.importKey(
40	      'raw',
41	      new TextEncoder().encode(password),
42	      'PBKDF2',
43	      false,
44	      ['deriveBits']
45	    );
46	    const bits = await crypto.subtle.deriveBits(
47	      { name: 'PBKDF2', salt, iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
48	      keyMaterial,
49	      256
50	    );
51	    return this._bufToHex(bits) === storedHash;
52	  }
53	
54	  /**
55	   * SHA-256 hash of a string.
56	   */
57	  async sha256(content) {
58	    const data = new TextEncoder().encode(content);
59	    const hash = await crypto.subtle.digest('SHA-256', data);
60	    return this._bufToHex(hash);
61	  }
62	
63	  /**
64	   * AES-GCM encrypt with a passphrase.
65	   * @returns {{ iv: string, ciphertext: string, salt: string }}
66	   */
67	  async encrypt(plaintext, passphrase) {
68	    const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
69	    const key = await this._deriveAESKey(passphrase, salt);
70	    const iv = crypto.getRandomValues(new Uint8Array(AES_IV_LENGTH));
71	    const encoded = new TextEncoder().encode(plaintext);
72	    const ciphertext = await crypto.subtle.encrypt(
73	      { name: 'AES-GCM', iv },
74	      key,
75	      encoded
76	    );
77	    return {
78	      iv: this._bufToHex(iv),
79	      ciphertext: this._bufToHex(ciphertext),
80	      salt: this._bufToHex(salt),
81	    };
82	  }
83	
84	  /**
85	   * AES-GCM decrypt with a passphrase.
86	   */
87	  async decrypt(encryptedData, passphrase) {
88	    const salt = this._hexToBuf(encryptedData.salt);
89	    const iv = this._hexToBuf(encryptedData.iv);
90	    const ciphertext = this._hexToBuf(encryptedData.ciphertext);
91	    const key = await this._deriveAESKey(passphrase, salt);
92	    const decrypted = await crypto.subtle.decrypt(
93	      { name: 'AES-GCM', iv },
94	      key,
95	      ciphertext
96	    );
97	    return new TextDecoder().decode(decrypted);
98	  }
99	
100	  /**
101	   * Generate a tamper-evident hash for document signing.
102	   */
103	  async generateSignatureHash(documentContent, signerName, timestamp) {
104	    const payload = `${documentContent}|${signerName}|${timestamp}`;
105	    return this.sha256(payload);
106	  }
107	
108	  /**
109	   * Mask a string showing only last N chars.
110	   */
111	  mask(value, visibleCount = 4) {
112	    if (!value || value.length <= visibleCount) return value;
113	    return '*'.repeat(value.length - visibleCount) + value.slice(-visibleCount);
114	  }
115	
116	  // --- Internal helpers ---
117	
118	  async _deriveAESKey(passphrase, salt) {
119	    const keyMaterial = await crypto.subtle.importKey(
120	      'raw',
121	      new TextEncoder().encode(passphrase),
122	      'PBKDF2',
123	      false,
124	      ['deriveKey']
125	    );
126	    return crypto.subtle.deriveKey(
127	      { name: 'PBKDF2', salt, iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
128	      keyMaterial,
129	      { name: 'AES-GCM', length: 256 },
130	      false,
131	      ['encrypt', 'decrypt']
132	    );
133	  }
134	
135	  _bufToHex(buffer) {
136	    const bytes = new Uint8Array(buffer);
137	    return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
138	  }
139	
140	  _hexToBuf(hex) {
141	    const bytes = new Uint8Array(hex.length / 2);
142	    for (let i = 0; i < hex.length; i += 2) {
143	      bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
144	    }
145	    return bytes.buffer;
146	  }
147	}
148	
149	export default new CryptoService();
