1	/**
2	 * RatingService — two-way ratings with tag-based feedback and appeal flow.
3	 */
4	
5	import ratingRepository from '../repositories/RatingRepository.js';
6	import appealRepository from '../repositories/AppealRepository.js';
7	import userRepository from '../repositories/UserRepository.js';
8	import registrationRepository from '../repositories/RegistrationRepository.js';
9	import defaultAuditService from './AuditService.js';
10	import { createRating, createAppeal, APPEAL_STATUS } from '../models/Rating.js';
11	import { REGISTRATION_STATUS } from '../models/Registration.js';
12	import { USER_ROLES } from '../models/User.js';
13	import { generateId, now } from '../utils/helpers.js';
14	
15	export class RatingService {
16	  constructor(deps = {}) {
17	    this._ratingRepo = deps.ratingRepository || ratingRepository;
18	    this._appealRepo = deps.appealRepository || appealRepository;
19	    this._userRepo = deps.userRepository || userRepository;
20	    this._registrationRepo = deps.registrationRepository || registrationRepository;
21	    this._auditService = deps.auditService || defaultAuditService;
22	  }
23	
24	  async submitRating({ fromUserId, toUserId, classId, score, tags, comment }) {
25	    if (!fromUserId) throw new Error('fromUserId is required.');
26	    if (!toUserId) throw new Error('toUserId is required.');
27	    if (fromUserId === toUserId) throw new Error('Cannot rate yourself.');
28	    if (!Number.isInteger(score) || score < 1 || score > 5) {
29	      throw new Error('Score must be between 1 and 5.');
30	    }
31	
32	    // When classId is provided, verify completion before allowing rating.
33	    // Per prompt: "Two-way ratings are captured after completion."
34	    if (classId) {
35	      const regs = await this._registrationRepo.getByClassId(classId);
36	      // Only enforce if registrations exist for this class (data-driven check)
37	      if (regs.length > 0) {
38	        const fromUserApproved = regs.some(r => r.userId === fromUserId && r.status === REGISTRATION_STATUS.APPROVED);
39	        if (!fromUserApproved) {
40	          throw new Error('You can only rate after completing (approved registration in) the class.');
41	        }
42	      }
43	    }
44	
45	    const rating = createRating({
46	      id: generateId(),
47	      fromUserId,
48	      toUserId,
49	      classId,
50	      score,
51	      tags: tags || [],
52	      comment: comment || '',
53	    });
54	
55	    await this._ratingRepo.add(rating);
56	    await this._auditService.log('rating', rating.id, 'created', `Rating ${score}/5 from ${fromUserId} to ${toUserId}`, fromUserId);
57	    return rating;
58	  }
59	
60	  /**
61	   * File an appeal on a rating.
62	   */
63	  async fileAppeal(ratingId, appealerId, reason) {
64	    if (!ratingId) throw new Error('ratingId is required.');
65	    if (!appealerId) throw new Error('appealerId is required.');
66	    if (!reason || String(reason).trim() === '') throw new Error('Appeal reason is required.');
67	
68	    const rating = await this._ratingRepo.getById(ratingId);
69	    if (!rating) throw new Error('Rating not found.');
70	
71	    // Ownership: only the rated user (toUserId) can file an appeal on their rating
72	    if (rating.toUserId !== appealerId) {
73	      await this._auditService.log('appeal', ratingId, 'unauthorized_attempt', `User ${appealerId} tried to appeal rating belonging to ${rating.toUserId}`, appealerId);
74	      throw new Error('Only the rated user can file an appeal on this rating.');
75	    }
76	
77	    const existingAppeals = await this._appealRepo.getByRatingId(ratingId);
78	    const pending = existingAppeals.find(a => a.status === APPEAL_STATUS.PENDING);
79	    if (pending) throw new Error('An appeal is already pending for this rating.');
80	
81	    const appeal = createAppeal({
82	      id: generateId(),
83	      ratingId,
84	      appealerId,
85	      reason,
86	    });
87	
88	    await this._appealRepo.add(appeal);
89	    await this._auditService.log('appeal', appeal.id, 'filed', `Appeal filed for rating ${ratingId}`, appealerId);
90	    return appeal;
91	  }
92	
93	  /**
94	   * Resolve an appeal (reviewer decision: uphold, adjust, void).
95	   */
96	  async resolveAppeal(appealId, decision, rationale, reviewerId, adjustedScore = null) {
97	    if (!appealId) throw new Error('appealId is required.');
98	    if (!reviewerId) throw new Error('reviewerId is required.');
99	
100	    // RBAC: only reviewers and admins can resolve appeals (fail-closed)
101	    const actingUser = await this._userRepo.getById(reviewerId);
102	    if (!actingUser) {
103	      throw new Error('Acting user not found. Cannot resolve appeal.');
104	    }
105	    if (![USER_ROLES.ADMINISTRATOR, USER_ROLES.STAFF_REVIEWER].includes(actingUser.role)) {
106	      throw new Error('Only administrators or staff reviewers can resolve appeals.');
107	    }
108	
109	    const appeal = await this._appealRepo.getById(appealId);
110	    if (!appeal) throw new Error('Appeal not found.');
111	
112	    if (appeal.status !== APPEAL_STATUS.PENDING) {
113	      throw new Error('Appeal has already been resolved.');
114	    }
115	
116	    if (!rationale || rationale.trim().length === 0) {
117	      throw new Error('Written rationale is required.');
118	    }
119	
120	    const validDecisions = [APPEAL_STATUS.UPHELD, APPEAL_STATUS.ADJUSTED, APPEAL_STATUS.VOIDED];
121	    if (!validDecisions.includes(decision)) {
122	      throw new Error(`Decision must be one of: ${validDecisions.join(', ')}`);
123	    }
124	
125	    if (decision === APPEAL_STATUS.ADJUSTED && (adjustedScore === null || adjustedScore < 1 || adjustedScore > 5)) {
126	      throw new Error('Adjusted score must be between 1 and 5.');
127	    }
128	
129	    appeal.status = decision;
130	    appeal.decision = decision;
131	    appeal.rationale = rationale;
132	    appeal.reviewerId = reviewerId;
133	    appeal.adjustedScore = adjustedScore;
134	    appeal.resolvedAt = now();
135	
136	    await this._appealRepo.put(appeal);
137	
138	    // If adjusted, update the original rating
139	    if (decision === APPEAL_STATUS.ADJUSTED) {
140	      const rating = await this._ratingRepo.getById(appeal.ratingId);
141	      if (rating) {
142	        rating.score = adjustedScore;
143	        await this._ratingRepo.put(rating);
144	      }
145	    }
146	
147	    // If voided, we could mark the rating as void — for now just log it
148	    await this._auditService.log('appeal', appealId, 'resolved', `Decision: ${decision}, rationale: ${rationale}`, reviewerId);
149	    return appeal;
150	  }
151	
152	  async getRatingById(ratingId) {
153	    return this._ratingRepo.getById(ratingId);
154	  }
155	
156	  async getRatingsForUser(toUserId) {
157	    return this._ratingRepo.getByToUserId(toUserId);
158	  }
159	
160	  async getRatingsByUser(fromUserId) {
161	    return this._ratingRepo.getByFromUserId(fromUserId);
162	  }
163	
164	  async getAllRatings() {
165	    return this._ratingRepo.getAll();
166	  }
167	
168	  async getPendingAppeals() {
169	    return this._appealRepo.getByStatus(APPEAL_STATUS.PENDING);
170	  }
171	
172	  async getAppealsByRatingId(ratingId) {
173	    return this._appealRepo.getByRatingId(ratingId);
174	  }
