 * Report (abuse report) domain model.
 * States: open → under_review → resolved (terminal).
 * SLA: system auto-resolves after 7 days if not manually resolved.
 */

export const REPORT_STATUS = {
  OPEN: 'open',
  UNDER_REVIEW: 'under_review',
  RESOLVED: 'resolved',
};

export const REPORT_OUTCOMES = {
  DISMISSED: 'dismissed',
  REMOVED: 'removed',
  WARNED: 'warned',
};

export function createReport({ id, reporterId, targetId, targetType, reason = '', status, resolution = null, resolvedBy = null, resolvedAt = null, riskFlag = false, createdAt }) {
  return {
    id,
    reporterId,
    targetId,
    targetType,          // 'review', 'question_thread', 'answer'
    reason,
    status: status || REPORT_STATUS.OPEN,
    resolution,          // REPORT_OUTCOMES value
    resolvedBy,
    resolvedAt,
    riskFlag,            // true if content flagged by sensitive word filter
    createdAt: createdAt || new Date().toISOString(),
  };
}
"}

