 * SchedulerService — periodic enforcement of moderation SLA deadlines.
 */

import moderationService from './ModerationService.js';
import notificationService from './NotificationService.js';

export class SchedulerService {
  constructor() {
    this._intervals = [];
  }

  start() {
    this._intervals.push(
      setInterval(() => this._enforceModeration(), 30 * 60 * 1000)
    );
    this._enforceModeration();
  }

  stop() {
    for (const id of this._intervals) clearInterval(id);
    this._intervals = [];
  }

  async _enforceModeration() {
    try {
      const { escalated, autoResolved } = await moderationService.enforceDeadlines();
      for (const report of escalated) {
        await notificationService.notify(
          'system', 'Report Escalated',
          `Abuse report ${report.id} escalated — SLA deadline exceeded.`,
          'warning', '#/reviews'
        );
      }
      for (const report of autoResolved) {
        await notificationService.notify(
          'system', 'Report Auto-Resolved',
          `Abuse report ${report.id} auto-dismissed after extended SLA breach.`,
          'error', '#/reviews'
        );
      }
    } catch (err) {
      console.error('Scheduler: moderation enforcement failed', err);
    }
  }
}

export default new SchedulerService();
"}

