      // Build source data
      const src = buildTestServices();
      await src.repos.userRepository.add(makeUser({ id: 'admin', role: USER_ROLES.ADMINISTRATOR }));
      await src.repos.userRepository.add(makeUser({ id: 'inst', role: USER_ROLES.INSTRUCTOR }));
