399	    await it('should complete full cross-role workflow', async () => {
400	      const { registrationService, quizService, reviewService, moderationService,
401	              contractService, ratingService, reputationService, repos } = buildTestServices();
402	
403	      // Seed users
404	      await repos.userRepository.add(makeUser({ id: 'admin', role: USER_ROLES.ADMINISTRATOR }));
405	      await repos.userRepository.add(makeUser({ id: 'inst', role: USER_ROLES.INSTRUCTOR }));
406	      await repos.userRepository.add(makeUser({ id: 'rev', role: USER_ROLES.STAFF_REVIEWER }));
407	      await repos.userRepository.add(makeUser({ id: 'learner', role: USER_ROLES.LEARNER }));
408	      await repos.classRepository.add(makeClass({ id: 'c1', capacity: 20 }));
409	
410	      // 1. Admin creates contract template
411	      const tpl = await contractService.createTemplate({
412	        name: 'Enrollment', content: 'I {Name} agree.', createdBy: 'admin',
413	      });
414	      assert(tpl.id, 'Template created');
415	
416	      // 2. Learner creates registration
417	      const reg = await registrationService.create('learner', 'c1', 'Want to enroll');
418	      await registrationService.transition(reg.id, REGISTRATION_STATUS.SUBMITTED, '', 'learner');
419	
420	      // 3. Reviewer processes it
421	      await registrationService.transition(reg.id, REGISTRATION_STATUS.UNDER_REVIEW, '', 'rev');
422	      await registrationService.transition(reg.id, REGISTRATION_STATUS.APPROVED, '', 'rev');
423	
424	      // 4. Instructor creates quiz
425	      const q = await quizService.createQuestion({
426	        questionText: 'What is 1+1?', type: 'single', correctAnswer: 'B',
427	        difficulty: 1, tags: 'math', createdBy: 'inst',
428	      });
429	      const quiz = await quizService.generatePaper('Quiz 1', 'c1', { totalQuestions: 1, difficultyDistribution: { 1: 1.0 } }, 'inst');
430	
431	      // 5. Learner takes quiz
432	      const result = await quizService.submitAnswers(quiz.id, 'learner', [
433	        { questionId: q.id, answer: 'B' },
434	      ]);
435	      assertEqual(result.objectiveScore, 100);
436	
437	      // 6. Learner submits review
438	      const review = await reviewService.submitReview({
439	        userId: 'learner', rating: 5, text: 'Great class!',
440	      });
441	
442	      // 7. Someone reports the review, reviewer resolves
443	      const report = await moderationService.submitReport('inst', review.id, 'review', 'Checking');
444	      await moderationService.resolveReport(report.id, REPORT_OUTCOMES.DISMISSED, 'rev');
445	
446	      // 8. Rating + appeal
447	      await seedCompletedClassWithParticipants(repos, 'tc-1', ['inst']);
448	      const rating = await ratingService.submitRating({
449	        fromUserId: 'inst', toUserId: 'learner', classId: 'tc-1', score: 4,
450	      });
451	      const appeal = await ratingService.fileAppeal(rating.id, 'learner', 'Score too low');
452	      await ratingService.resolveAppeal(appeal.id, APPEAL_STATUS.ADJUSTED, 'Adjusting upward', 'rev', 5);
453	      const updated = await repos.ratingRepository.getById(rating.id);
454	      assertEqual(updated.score, 5);
455	
456	      // 9. Verify scoping — learner sees only own data
457	      const learnerRegs = await registrationService.getAllScoped('learner');
458	      assertEqual(learnerRegs.length, 1);
459	
460	      // 10. Verify admin sees everything
461	      const adminRegs = await registrationService.getAllScoped('admin');
462	      assertEqual(adminRegs.length, 1); // all registrations
463	
464	      // 11. Verify audit trail completeness
465	      const auditLogs = await repos.auditLogRepository.getAll();
466	      assert(auditLogs.length >= 10, `Expected comprehensive audit trail, got ${auditLogs.length}`);
467	    });
468	  });
469	
470	  // ============================================================
471	  // 11. CONFIG-DRIVEN BEHAVIOR STRICT CHECK
472	  // ============================================================
473

